import React from 'react';
import { Link } from 'react-router-dom';
import { TooltipMobile } from '../../../tooltip-mobile/TooltipMobile';
import { setMobileModalTrigger } from '../../../../store/reducers/mobile-modal-reducer';
import { mdSelectGiftIdAction } from '../../../../store/reducers/md-reducer';
import { MDGift } from '../../../../store/reducers/md-gift-interface';

export const useGiftHelpers = (
    dispatch: any, 
    i18n: any, 
    t: any, 
    gifts: MDGift[], 
    historyContext: React.ReactNode[]
) => {
    // Если gifts undefined или пустой, считаем что данные еще грузятся
    const isDataReady = gifts && gifts.length > 0;

    const giftLinkFunc = (giftId: string) => {
        if (!isDataReady) return <span key={giftId}>#{giftId}#</span>;

        const gift = gifts.find(g => g.id === giftId);
        if (!gift) return <span key={giftId}>#{giftId}#</span>;

        const name = i18n.language === "ru" ? gift.nameRU : gift.nameEN;
        
        return (
            <Link 
                className="MDFormattedText-link"
                to={`/limbus/${i18n.language}/mirror-dungeon/gifts`} 
                onClick={(e) => {
                    e.stopPropagation();
                    mdSelectGiftIdAction(dispatch, gift.id);
                }} 
                key={giftId + i18n.language}
            >
                <figure className="MDFormattedText-figure">
                    <img className='small-img' src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`} alt={name} />
                    <img className='big-img' src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`} alt={name} />
                    <figcaption className={`MDFormattedText--${(gift.id !== "gift_0") ? gift.sin : "none"}`}>
                        {name}
                    </figcaption>
                </figure>
            </Link>
        );
    };

    const simpleGiftFunc = (giftId: string, resultLength: number) => {
        if (!isDataReady) return <span key={giftId}>@{giftId}@</span>;

        const gift = gifts.find(g => g.id === giftId);
        if (!gift) return <span key={giftId + resultLength}>@{giftId}@</span>;

        const name = i18n.language === "ru" ? gift.nameRU : gift.nameEN;
        const descriptionGift = i18n.language === "ru" ? gift.grade1RU : gift.grade1EN;
        const imgPath = `${process.env.PUBLIC_URL}/images/md-gifts/${giftId}.webp`;

        const mobileModalHTML = (
            <TooltipMobile 
                image={<img className="status" src={imgPath} alt={giftId} />} 
                header={name} 
                text={descriptionGift} 
                history={historyContext}
                giftId={giftId} 
            />
        );

        return (
            <React.Fragment key={giftId + resultLength}>
                <img className="guide-status" src={imgPath} alt={giftId} style={{ width: "25px", height: "25px"}} />
                <span 
                    onClick={(e) => {
                        e.stopPropagation();
                        // Обязательно вызываем экшн для выбора подарка в сторе, 
                        // чтобы GiftsHeader сразу отобразил нужный ID при скролле
                        mdSelectGiftIdAction(dispatch, giftId); 
                        setMobileModalTrigger(dispatch, mobileModalHTML);
                    }} 
                    className={`status-name status-name--gift tooltip-container`}
                    style={{ cursor: 'pointer' }}
                >
                    {name}
                    <span className="entityFullInfo-tooltip">{t("SkillCoinDescription.clickToSeeDescription")}</span>
                </span>
            </React.Fragment>
        );
    };

    return { giftLinkFunc, simpleGiftFunc };
};
