import React from "react";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { SlotInterface, SINNER_ORDER } from "../../../store/reducers/tb-reducer";
import { IdentitySVG } from "../../svg/IdentitySVG";
import { EyeOpenedSVG } from "../../svg/EyeOpenedSVG";
import { TbList } from "../tb-list/TbList";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { handleIdentityImageError } from "../../../tools/identityImage";
import "./TbModal.css";

interface ModalProps {
    modalTrigger: SlotInterface | null;
    active: boolean;
    closer: Function;
}

const ModalSlot: React.FC<{ modalTrigger: SlotInterface | null, closer: Function }> = ({ modalTrigger, closer }) => {
    const { i18n, t } = useTranslation();
    if (!modalTrigger) return <></>;
    const { ego, identity } = modalTrigger;
    const egosMap = [
        { ego: ego.ZAYIN, glyph: "ז" },
        { ego: ego.TETH, glyph: "ט" },
        { ego: ego.HE, glyph: "ה" },
        { ego: ego.WAW, glyph: "ו" },
        { ego: ego.ALEPH, glyph: "ℵ" },
    ];

    return (
        <>
            {(!identity) ?
                <div className="modal-identity modal-empty"><IdentitySVG /></div> :
                <Link to={`/limbus/${i18n.language}/identities/${identity.imgUrl}`} className="modal-identity shadow" onClick={() => closer()}>
                    <img src={`${process.env.PUBLIC_URL}/images/identities/${identity.imgUrl}.1.webp`} onError={event => handleIdentityImageError(event, identity.imgUrl)} alt="id" />
                    <div className="modal-identity-shadow" /><div className={`modal-info`}>{t('GiftItem.info')}</div>
                </Link>
            }
            <div className="modal-ego-container">
                {egosMap.map(({ ego, glyph }, index) => (
                    <React.Fragment key={index}>
                        {ego ?
                            <Link to={`/limbus/${i18n.language}/ego/${ego.imgUrl}`} className="modal-ego shadow" onClick={() => closer()}>
                                <img src={`${process.env.PUBLIC_URL}/images/ego/${ego.imgUrl}.webp`} alt="ego" />
                                <div className="modal-ego-shadow" /><div className={`modal-info`}><EyeOpenedSVG /></div>
                                <div className={["modal-ego-frame", `${ego.egoSin}-sin-color`].join(" ")} />
                            </Link>
                            : <div className="modal-ego modal-empty"><span>{glyph}</span></div>
                        }
                    </React.Fragment>
                ))}
            </div>
        </>
    );
}

export const TbModal: React.FC<ModalProps> = ({ active, modalTrigger, closer }) => {
    const { slots } = useTypedSelector((state: any) => state.tbReducer);

    const lastSlotIndexRef = React.useRef<number>(-1);
    const lastSinnerRef = React.useRef<string | undefined>(undefined);
    const prevModalTriggerRef = React.useRef<SlotInterface | null>(null);

    if (modalTrigger && modalTrigger !== prevModalTriggerRef.current) {
        prevModalTriggerRef.current = modalTrigger;
        const idx = slots.findIndex((s: SlotInterface) => s === modalTrigger);
        if (idx !== -1) {
            lastSlotIndexRef.current = idx;
            lastSinnerRef.current = SINNER_ORDER[idx];
        }
    }

    // Всегда читаем актуальные данные слота из Redux по сохранённому индексу
    const effectiveSlot = lastSlotIndexRef.current !== -1
        ? slots[lastSlotIndexRef.current]
        : null;
    const effectiveSinner = lastSinnerRef.current;

    return (
        <div className={["modal", active ? "modal--active" : ""].join(" ")} onClick={() => { if (closer) closer() }}>
            <div className="modal__slot" onClick={(e) => e.stopPropagation()}>
                {/* effectiveSlot всегда свежий из Redux — отразит выбранную личность/эго */}
                <ModalSlot modalTrigger={effectiveSlot} closer={closer} />
            </div>
            <div className="modal__content" onClick={(e) => e.stopPropagation()}>
                <TbList
                    key={effectiveSinner}
                    isIdentityTeamBuilder={effectiveSinner}
                    currentSlot={effectiveSlot}
                />
            </div>
        </div>
    );
}
