import React from "react";
import { useTranslation } from "react-i18next";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { getStatusesEntityList } from "../../../tools/getStatusesEntityList";
import { parseEntityTraits } from "../../entity-full-info/traits";
import { TbTag } from "./tb-tag/TbTag";
import "./TbTags.css";

const STANDARD_TAGS = ["burn", "bleed", "tremor", "poise", "rupture", "charge", "sinking"];

export const TbTags:React.FC = () => {
    const {slots} = useTypedSelector(state=> state.tbReducer);
    const getListOfTags = () =>{
        let result:{count:number,tag:string}[] =[];
        let tagsMap:{[key:string]:number} = {};
        slots.forEach((slot,index)=>{
            if (slot.role === "support") return;
            const {ego,identity} = slot;
            let tags:string[] = [];
             if(identity){
                const {descriptionCoinEN4,descriptionPassive1EN,descriptionPassive2EN} =identity;
                tags = Object.keys(getStatusesEntityList([descriptionCoinEN4,descriptionPassive1EN,descriptionPassive2EN]));
            } 
            if (identity) {
                tags.push(...parseEntityTraits(identity.traits)
                    .filter(trait => !trait.negated)
                    .map(trait => `trait:${trait.name}`));
            }
            for(const key in ego){
                const currentEGO = ego[key];
                if(currentEGO){
                    const {CoinEN4,descriptionPassiveEN} = currentEGO;
                    tags.push(...Object.keys(getStatusesEntityList([CoinEN4,descriptionPassiveEN])))
                }
            }
            tags.forEach((tag)=>{
                if(tag in tagsMap)tagsMap[tag]+= 1;
                else tagsMap[tag] = 1;
            })
        })
        
        for(const key in tagsMap){
            result.push(
                {
                    count: tagsMap[key],
                    tag:key
                }
            )
        }

        result.sort((a, b) => b.count - a.count);

        return result;
    }
    const listOfTags = getListOfTags();
    const standardTags = STANDARD_TAGS
        .map(tag => listOfTags.find(item => item.tag === tag))
        .filter(Boolean) as {count:number,tag:string}[];
    const otherTags = listOfTags.filter(item => !STANDARD_TAGS.includes(item.tag));
    const {t} = useTranslation();
    return (
        <section className="tb-tags">
            <h2 className="tb-tags-header"> {t("TbTags.header")}</h2>
            <div className="tb-tags-layout">
                <div className="tb-tags-container tb-tags-container--standard">
                    {standardTags.map(({count,tag})=>{
                        return(
                            <TbTag key={tag} tag={tag} count={count}></TbTag>
                        )
                    })}
                </div>
                <div className="tb-tags-container tb-tags-container--other">
                    {otherTags.map(({count,tag})=>{
                        return(
                            <TbTag key={tag} tag={tag} count={count}></TbTag>
                        )
                    })}
                </div>
                {!listOfTags.length && <p>{t("TbTags.empty")} </p>}
            </div>
        </section>
    )
}
