import { QueryClient } from "react-query";
import { SlotInterface } from "../../../store/reducers/tb-reducer";
import { EGOInterface } from "../../../store/reducers/ego-reducer";
import { IdentityInterface } from "../../../store/reducers/ids-reducer";

const SINNER_COUNT = 12;
const IDENTITY_BASE = 10000;
const EGO_BASE = 20000;
const EGO_RARITIES = ["ZAYIN", "TETH", "HE", "WAW", "ALEPH"] as const;

type TeamCodeEntity = { gameId: number; imgUrl: string };

const getModifier = (
    entity: TeamCodeEntity | null | undefined,
    sinnerId: number,
    base: number,
    currentEntities: TeamCodeEntity[]
) => {
    if (!entity) return 0;

    const entityGameId = Number(entity.gameId);
    const currentEntity = Number.isInteger(entityGameId) && entityGameId > 0
        ? entity
        : currentEntities.find(item => item.imgUrl === entity.imgUrl);
    const gameId = Number(currentEntity?.gameId);
    const modifier = gameId % 100;
    const gameSinnerId = Math.floor((gameId - base) / 100);
    if (!Number.isInteger(gameId) || gameSinnerId !== sinnerId || modifier < 1 || modifier > 127) {
        throw new Error(`Некорректный gameId ${currentEntity?.gameId} у ${entity.imgUrl}`);
    }

    return modifier;
};

export const encodeFormationCode = async (slots: SlotInterface[], queryClient?: QueryClient): Promise<string> => {
    if (slots.length !== SINNER_COUNT) {
        throw new Error(`Для кода команды требуется ${SINNER_COUNT} слотов`);
    }

    const allIdsCache = queryClient?.getQueryData<IdentityInterface[]>("identities") || [];
    const allEgosCache = queryClient?.getQueryData<EGOInterface[]>("ego") || [];
    const occupiedSlotTypes = new Set<number>();
    const slotTypes = slots.map(slot => {
        const hasEntity = Boolean(slot.identity || Object.values(slot.ego || {}).some(Boolean));
        if (!hasEntity || slot.role === "support") return 0;

        const storedSlotType = Number(slot.teamCodeSlotType);
        if (Number.isInteger(storedSlotType) && storedSlotType > 0 && storedSlotType <= 15 && !occupiedSlotTypes.has(storedSlotType)) {
            occupiedSlotTypes.add(storedSlotType);
            return storedSlotType;
        }

        let slotType = 1;
        while (occupiedSlotTypes.has(slotType) && slotType <= 15) slotType++;
        occupiedSlotTypes.add(slotType);
        return slotType;
    });

    let bitString = "0";
    slots.forEach((slot, index) => {
        const sinnerId = index + 1;
        bitString += getModifier(slot.identity, sinnerId, IDENTITY_BASE, allIdsCache).toString(2).padStart(7, "0");
        bitString += slotTypes[index].toString(2).padStart(4, "0");
        EGO_RARITIES.forEach(rarity => {
            bitString += getModifier(slot.ego?.[rarity], sinnerId, EGO_BASE, allEgosCache).toString(2).padStart(7, "0");
        });
    });

    while (bitString.length % 8 !== 0) bitString += "0";
    const bytes = new Uint8Array(bitString.length / 8);
    for (let index = 0; index < bitString.length; index += 8) {
        bytes[index / 8] = parseInt(bitString.substring(index, index + 8), 2);
    }

    const innerB64 = btoa(String.fromCharCode(...Array.from(bytes)));
    const stream = new Blob([innerB64]).stream().pipeThrough(new (window as any).CompressionStream("gzip"));
    const compressedBytes = new Uint8Array(await new Response(stream).arrayBuffer());
    return btoa(String.fromCharCode(...Array.from(compressedBytes)));
};

export const decodeFormationCode = async (code: string, queryClient: QueryClient): Promise<SlotInterface[]> => {
    const compressedBinaryString = atob(code);
    const compressedBytes = new Uint8Array(compressedBinaryString.length);
    for (let i = 0; i < compressedBinaryString.length; i++) {
        compressedBytes[i] = compressedBinaryString.charCodeAt(i);
    }

    const stream = new Blob([compressedBytes]).stream().pipeThrough(new (window as any).DecompressionStream("gzip"));
    const decompressedBuffer = await new Response(stream).arrayBuffer();
    const innerB64 = new TextDecoder().decode(decompressedBuffer);
    const binaryString = atob(innerB64);
    let bitString = "";
    for (let i = 0; i < binaryString.length; i++) {
        bitString += binaryString.charCodeAt(i).toString(2).padStart(8, "0");
    }

    const requiredBits = 1 + SINNER_COUNT * (7 + 4 + EGO_RARITIES.length * 7);
    if (bitString.length < requiredBits) {
        throw new Error("Некорректный код команды");
    }

    const allIdsCache = queryClient.getQueryData<IdentityInterface[]>("identities") || [];
    const allEgosCache = queryClient.getQueryData<EGOInterface[]>("ego") || [];
    let offset = 1;
    const newSlots: SlotInterface[] = [];

    for (let index = 0; index < SINNER_COUNT; index++) {
        const sinnerId = index + 1;
        const identityModifier = parseInt(bitString.substring(offset, offset + 7), 2);
        offset += 7;
        const slotType = parseInt(bitString.substring(offset, offset + 4), 2);
        offset += 4;
        const identityGameId = IDENTITY_BASE + sinnerId * 100 + identityModifier;
        const identity = identityModifier > 0
            ? allIdsCache.find(item => item.gameId === identityGameId) || null
            : null;
        const ego: Record<string, EGOInterface | null> = {};

        for (const rarity of EGO_RARITIES) {
            const egoModifier = parseInt(bitString.substring(offset, offset + 7), 2);
            offset += 7;
            const egoGameId = EGO_BASE + sinnerId * 100 + egoModifier;
            ego[rarity] = egoModifier > 0
                ? allEgosCache.find(item => item.gameId === egoGameId) || null
                : null;
        }

        newSlots.push({
            identity,
            ego,
            role: slotType > 0 ? "combat" : "support",
            teamCodeSlotType: slotType
        });
    }

    return newSlots;
};
