import { StoredSiteSettings } from "./site-settings";

const PREFIX = "gll-settings-v1.";

export const encodeSiteSettings = (settings: StoredSiteSettings) => {
  const bytes = new TextEncoder().encode(JSON.stringify(settings));
  let binary = "";
  bytes.forEach(byte => { binary += String.fromCharCode(byte); });
  return PREFIX + btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
};

export const decodeSiteSettings = (code: string): StoredSiteSettings => {
  const normalized = code.trim();
  if (!normalized.startsWith(PREFIX)) throw new Error("Invalid settings code");
  const base64 = normalized.slice(PREFIX.length).replace(/-/g, "+").replace(/_/g, "/");
  const binary = atob(base64 + "=".repeat((4 - base64.length % 4) % 4));
  const bytes = Uint8Array.from(binary, char => char.charCodeAt(0));
  const data = JSON.parse(new TextDecoder().decode(bytes));
  if (!data?.global || !data?.pages) throw new Error("Invalid settings data");
  return data as StoredSiteSettings;
};
