import React, { useEffect, useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "react-query";
import { EventInterface } from "../../../store/reducers/events_list-reducer";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../../../tools/supabaseClient"; 
import "./EventsSection.css";

const MSK_OFFSET = 3;
const getMskFixedDate = (dateStr: any, targetMskHour: number): Date | null => {
  if (!dateStr) return null;
  if (typeof dateStr === 'string' && /^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
    const [day, month, year] = dateStr.split('.').map(Number);
    return new Date(Date.UTC(year, month - 1, day, targetMskHour - MSK_OFFSET));
  }
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return null;
  date.setUTCHours(targetMskHour - MSK_OFFSET, 0, 0, 0);
  return date;
};

export const EventSector: React.FC<{ event: EventInterface }> = ({ event }) => {
  const { t, i18n } = useTranslation();
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const { startDate, endDate } = useMemo(() => ({
    startDate: getMskFixedDate(event.startDate, 6),
    endDate: getMskFixedDate(event.endDate, 4),
  }), [event.startDate, event.endDate]);

  const formatDiff = (ms: number) => {
    const d = Math.floor(ms / 86400000);
    const h = Math.floor((ms % 86400000) / 3600000);
    return `${d}${t("EventsSection.d")} ${h}${t("EventsSection.h")}`;
  };

  const renderTimerLabel = () => {
    if (!startDate) return t("EventsSection.startDateUnknown");
    const diffStart = startDate.getTime() - now.getTime();
    if (diffStart > 0) return formatDiff(diffStart);
    if (!endDate) return t("EventsSection.endDateUnknown");
    const diffEnd = endDate.getTime() - now.getTime();
    return diffEnd <= 0 ? t("EventsSection.eventEnded") : formatDiff(diffEnd);
  };

  const eventLink = (event.link || "").split("|").map(link => link.trim()).filter(Boolean);
  const localizedLink = eventLink[i18n.language === "ru" ? 0 : 1] || eventLink[0] || "#";

  return (
    <article className="event-sector-new">
      <a href={localizedLink} target="_blank" rel="noopener noreferrer" className="event-card-link">
        <div className="event-image-wrapper">
          <img src={event.imgSrc} alt={event.nameEn} className="event-main-img" />
          <div className="event-overlay">
            <div className="event-timer-badge">
              <span className="timer-dot"></span>
              {renderTimerLabel()}
            </div>
            <div className="event-decor-dots">
              {[...Array(6)].map((_, i) => <span key={i} className="rarity-rhombus"></span>)}
            </div>
          </div>
        </div>
      </a>
    </article>
  );
};

export const EventsSection: React.FC = () => {
  const { data: events = [], isLoading } = useQuery("events", async () => {
    const url = `${SUPABASE_URL}/rest/v1/events?select=*`;
    const response = await fetch(url, {
      headers: {
        apikey: SUPABASE_ANON_KEY
      }
    });
    return response.json();
  }, { staleTime: 900000 });

  const { t } = useTranslation();

  if (isLoading) return <div className="loading-shimmer">{t("EventsSection.loading")}</div>;

  return (
    <section className="events-section">
      <h2 className="new-entity">{t("EventsSection.header")}</h2>
      {/* Добавлена обертка-контейнер для управления скроллом */}
      <div className="events-slider-wrapper">
        <div className="events-grid-layout">
          {events.map((event: any) => (
            <EventSector key={event.id} event={event} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default EventsSection;
