import { Dispatch } from "react";
import { damageTypes, guardTypes, rarityEGOTypes, rarityIdentityTypes, sinnerTypes, sinTypes, tagsIds, seasonTypes, eventTypes } from "../../constants/skillBasedTypes";
import { sinnerType, sinType ,dmgType,guardType,rarityEGOType,rarityIdentityType,seasonType,eventType} from "../../constants/types";

export type SinFilterInterface = { [key in sinType]: boolean; }
export type DmgTypeFilterInterface = { [key in dmgType]: boolean; }
export type GuardTypeFilterInterface = { [key in guardType]: boolean; }
export type TagsFilterInterface = { [key: string]: boolean; }
export type SinnerFilterInterface = { [key in sinnerType]: boolean; };
export type SinnerRarityFilterInterface = { [key in rarityIdentityType]: boolean; };
export type EGORarityFilterInterface = { [key in rarityEGOType]: boolean; };
export type SeasonFilterInterface = { [key in seasonType]: boolean; }
export type EventFilterInterface = { [key in eventType]: boolean; }

// Теперь у нас отображаются только этажи с 1 по 5
export const floorTypes = ["1F", "2F", "3F", "4F", "5F"];

// Новые текстовые теги из поля `tip` (включая автоматические диапазоны E и IM)
export const mdThemeTags = ["E", "IM", "C", "IN", "W", "RR", "AT", "SIN", "ST", "SP"];

export type FilterInterface = {
    types: {
        [key: string]: { [key: string]: boolean };
    } & {
        sin: SinFilterInterface,
        dmgType: DmgTypeFilterInterface,
        guardType: GuardTypeFilterInterface,
        tags: TagsFilterInterface,
        traits: Record<string, boolean>,
        sinner: SinnerFilterInterface,
        rarityIdentity: SinnerRarityFilterInterface,
        rarityEGO: EGORarityFilterInterface,
        md: Record<string, boolean>,
        season: SeasonFilterInterface,
        event: EventFilterInterface,
        // Фильтры для Зеркального Лабиринта (Темы)
        complexityFloor: Record<string, boolean>,
        complexityMode: { normal: boolean; hard: boolean },
        mdThemeTips: Record<string, boolean> // Новая секция для E, IM, C...
    }
}

export enum FilterActionTypes {
    CHANGE_TYPE_FILTER = "CHANGE_TYPE_FILTER",
    CLEAR_SECTION_FILTER = "CLEAR_SECTION_FILTER",
    RESET_ALL_FILTER = "RESET_ALL_FILTER"
}

export interface ChangeTypeFilterAction {
    type: FilterActionTypes.CHANGE_TYPE_FILTER;
    payload: string;
}
export interface ResetAllFilterAction {
    type: FilterActionTypes.RESET_ALL_FILTER;
}
export interface ClearSectionFilterAction {
    type: FilterActionTypes.CLEAR_SECTION_FILTER;
    payload: string;
}
export type FilterAction = ChangeTypeFilterAction | ClearSectionFilterAction | ResetAllFilterAction;

const initStateParam = <T extends string | number | symbol>(keys: T[]): { [key in T]: boolean } => { 
    let obj: { [key in T]: boolean } = {} as { [key in T]: boolean };
    keys.forEach(key => { obj[key] = false; })
    return obj;
}

const initialTypes = {
    dmgType: initStateParam(damageTypes),
    guardType: initStateParam(guardTypes),
    sin: initStateParam(sinTypes),
    tags: initStateParam(tagsIds),
    traits: {},
    sinner: initStateParam(sinnerTypes),
    rarityIdentity: initStateParam(rarityIdentityTypes),
    rarityEGO: initStateParam(rarityEGOTypes),
    md: { "none": false },
    season: initStateParam(seasonTypes),
    event: initStateParam(eventTypes),
    complexityFloor: initStateParam(floorTypes),
    complexityMode: { normal: false, hard: false },
    mdThemeTips: initStateParam(mdThemeTags) // Инициализируем новые кнопочки дефолтным false
}

const FILTER_STORAGE_KEY = "gll-selected-filters";
const getInitialState = (): FilterInterface => {
    try {
        const saved = JSON.parse(localStorage.getItem(FILTER_STORAGE_KEY) || "null");
        return saved?.types ? { types: { ...initialTypes, ...saved.types } } : { types: initialTypes };
    } catch {
        return { types: initialTypes };
    }
};

const initialState: FilterInterface = getInitialState();
const persistFilters = (state: FilterInterface) => localStorage.setItem(FILTER_STORAGE_KEY, JSON.stringify(state));

export const filterReducer = (state = initialState, action: FilterAction): FilterInterface => {
    const newState = JSON.parse(JSON.stringify(state)) as FilterInterface;

    switch (action.type) {
        case FilterActionTypes.RESET_ALL_FILTER: {
            const resetState = { ...resetAll(newState) };
            persistFilters(resetState);
            return resetState;
        }
        case FilterActionTypes.CHANGE_TYPE_FILTER: {
            const changedState = { ...applyFilter(action.payload, newState) };
            persistFilters(changedState);
            return changedState;
        }
        case FilterActionTypes.CLEAR_SECTION_FILTER: {
            const clearedState = { ...clearSection(action.payload, newState) };
            persistFilters(clearedState);
            return clearedState;
        }
        default: 
            return state
    }
}

const applyFilter = (payload: string, state: FilterInterface) => {
    const { types } = state;
    const { tags } = types;
    const separator = payload.indexOf(":");
    if (separator > 0) {
        const section = payload.slice(0, separator);
        const value = payload.slice(separator + 1);
        if (section in types && value) {
            types[section][value] = !types[section][value];
            return state;
        }
    }
    let keyExists = false;
    for (const key in types) {
        const current = types[key];
        if (payload in current) {
            const currentWithKey = current as { [key: string]: boolean };
            currentWithKey[payload] = !currentWithKey[payload];
            keyExists = true;
            return state;
        }
    }
    if (!keyExists) tags[payload] = true;
    return state;
};

export const filterChangeSectionValueAction = (
    dispatch: Dispatch<ChangeTypeFilterAction>,
    section: string,
    value: string
) => dispatch({ type: FilterActionTypes.CHANGE_TYPE_FILTER, payload: `${section}:${value}` });

const resetAll = (state: FilterInterface) => {
    const { types } = state;
    for (const key in types) clearSection(key, state);
    return state;
}

const clearSection = (payload: string, state: FilterInterface) => {
    const { types } = state;
    if (payload in types) {
        const type = types[payload]
        for (const key in type) type[key as keyof typeof type] = false;
    }
    return state;
}

export const filterResetAllAction = (dispatch: Dispatch<ResetAllFilterAction>) => {
    dispatch({ type: FilterActionTypes.RESET_ALL_FILTER })
}
export const filterChangeTypeAction = (dispatch: Dispatch<ChangeTypeFilterAction>, payload: string) => {
    dispatch({ type: FilterActionTypes.CHANGE_TYPE_FILTER, payload })
}
export const filterClearSectionAction = (dispatch: Dispatch<ClearSectionFilterAction>, payload: string) => {
    dispatch({ type: FilterActionTypes.CLEAR_SECTION_FILTER, payload })
}
