import { del } from "idb-keyval";
import { FETCH_CONFIG } from "./fetchConfig";

export const CACHE_TIME = 15 * 60 * 1000;
export const FETCH_KEYS = [...Object.keys(FETCH_CONFIG), "statuses"];
export const getCacheKey = (key: string) => `${key}_cache_game-id-v1`;

export const clearDataCache = async () => {
  const cacheKeys = FETCH_KEYS.map(getCacheKey);

  await Promise.all(cacheKeys.map((key) => del(key)));
  cacheKeys.forEach((key) => {
    localStorage.removeItem(key);
    sessionStorage.removeItem(key);
  });
};
