import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { mobileLayoutFrom } from "../../constants/mobileLayoutFrom";
import useHover from "../../hooks/useHover";
import { useIntersectionObserver } from "../../hooks/useIntersectionObserver";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { isIdentity } from "../../tools/isIdentity";
import { getIdentityImageUrl, handleIdentityImageError } from "../../tools/identityImage";
import { useSiteSettings } from "../../hooks/useSiteSettings";
import { ItemEGOInfo } from "../item-ego-info/ItemEGOInfo";
import { ItemIdentityInfo } from "../item-identity-info/ItemIdentityInfo";
import "./ItemEntity.css";

export interface IItemEntity {
    entity: IdentityInterface | EGOInterface;
    sinner?: string;
    animationDelay?: number;
    hideFooter?: boolean;
    isNewsContext?: boolean; 
}

export const ItemEntity: React.FC<IItemEntity> = ({ entity, sinner, animationDelay, hideFooter, isNewsContext }) => {
    const { rarity, imgUrl, isNew } = entity;
    const [animatedClass, setAnimatedClass] = useState("");
    const [, setTimer] = useState<NodeJS.Timeout | null>(null);

    const { t, i18n } = useTranslation();
    const { settings } = useSiteSettings();
    const nameKey = `name${i18n.language.toUpperCase()}` as keyof typeof entity;
    const rawName = entity[nameKey] as string;
    
    const formattedName = `[${rawName}]`;

    const isEgo = !isIdentity(entity);
    const rarityStyled = (isEgo) ? rarity : rarity.replaceAll("O", "Ø");

    const sinnerId = (sinner || (entity as any).sinner || "").toLowerCase().replace(/\s/g, "");

    const frameRarityClass = isEgo 
        ? `${entity.egoSin}-sin-color` 
        : `item-entity-sinner--${sinnerId}`;
    const imgFolder = (isEgo) ? "ego" : "identities";
    const fallbackImage = `${process.env.PUBLIC_URL}/images/${imgFolder}/${imgUrl}.webp`;
    
    const translatedSinner = t(`sinners.${sinnerId}`);

    const refItem = useRef<HTMLAnchorElement>(null);
    const { isVisible } = useIntersectionObserver(refItem, 0.1);
    const isHovering = useHover(refItem);
    const HoverComponent = (isEgo) ? <ItemEGOInfo entity={entity} /> : <ItemIdentityInfo entity={entity} />;
    
    const linkDestination = (isEgo) 
        ? `/limbus/${i18n.language}/ego/${imgUrl}` 
        : `/limbus/${i18n.language}/identities/${imgUrl}`;

    useEffect(() => {
        let tim: NodeJS.Timeout | null = null;
        if (isVisible) {
            const delay = animationDelay || 0;
            tim = setTimeout(() => setAnimatedClass("item-entity-container--animated"), delay);
            setTimer(tim);
        }
        return () => {
            if (tim) clearTimeout(tim);
        }
    }, [isVisible, animationDelay]);

    const isNewItem = !!(+isNew);
    const shouldShowFooter = isNewsContext ? isNewItem : !hideFooter;

    return (
        <Link to={linkDestination} ref={refItem} className={`item-entity-container ${animatedClass}`} >
            {isHovering && window.innerWidth > mobileLayoutFrom && HoverComponent}
            
            <div className="item-entity-content">
                <div className={"shadow"}>
                    {isEgo
                        ? <img className="item-entity-image" src={fallbackImage} alt={`${imgUrl}`} />
                        : <div className={`item-entity-image-stack${settings.identityHover ? "" : " item-entity-image-stack--static"}`}>
                            <img className="item-entity-image item-entity-image--base" src={getIdentityImageUrl(imgUrl, settings.identityImage)} onError={event => handleIdentityImageError(event, imgUrl)} alt={`${imgUrl}`} />
                            {settings.identityHover && <img className="item-entity-image item-entity-image--hover" src={getIdentityImageUrl(imgUrl, settings.identityImage === 1 ? 2 : 1)} onError={event => handleIdentityImageError(event, imgUrl, true)} alt="" aria-hidden="true" />}
                        </div>}
                    <div className="item-entity-overlay"></div>
                    <div className="item-entity-rarity" >{rarityStyled}</div>
                    <div className={"item-entity-name"}>{formattedName}</div>
                </div>
                
                {isNewItem && <span className="item-entity-new">{t("sinners.new")}</span>}
                
                {shouldShowFooter && (
                    <div className="item-entity-footer-wrapper">
                        <div className={["item-entity-footer-pill", frameRarityClass].join(" ")}>
                            <span className="item-sinner-display-name">{translatedSinner}</span>
                        </div>
                    </div>
                )}
            </div>
        </Link>
    );
};
