import React, { useEffect, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { FETCH_CONFIG } from "../../api/fetchConfig";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { EventInterface } from "../../store/reducers/events_list-reducer";
import { MDEvent } from "../../store/reducers/md-event-interface";
import { MDGift } from "../../store/reducers/md-gift-interface";
import { ChanLogInterface } from "../../store/reducers/chanlog-reducer";
import { EntityFullInfoIdentity } from "../entity-full-info/entity-full-info-identity/EntityFullInfoIdentity";
import { EntityFullInfoEGO } from "../entity-full-info/entity-full-info-ego/EntityFullInfoEGO";
import { IdentitySkills } from "../entity-full-info/identity-skills/IdentitySkills";
import { EgoSkills } from "../entity-full-info/ego-skills/EgoSkills";
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import { MDEventOption } from "../mirror-dungeon/events/option/MDEventOption";
import { createGiftList } from "../mirror-dungeon/formatted-text-gift/MDGiftFormattedText";
import { GiftsHeader } from "../mirror-dungeon/gifts/header/GiftsHeader";
import { ChangelogItem } from "../tier-list/tier-list-nav/TierListNav";
import { EventSector } from "../main-info/events-section/EventsSection";
import { CommunityTeamCard } from "../team-builder/community/CommunityTeamCard";
import { TeamPreset } from "../team-builder/community/team-types";
import "../../pages/TeamBuilderPage.css";
import "../mirror-dungeon/floor-themes/FloorThemes.css";
import "../guides/guides-full-info/GuidePageFull.css";
import "../main-info/MainInfo.css";

type Props = {
  tableName: string;
  draft: Record<string, any>;
  language?: "ru" | "en";
};

const validate = <T,>(key: string, row: Record<string, any>): T => {
  const validator = FETCH_CONFIG[key]?.validator;
  return (validator ? validator([row])[0] : row) as T;
};

const localized = (value: string, language: string) => {
  if (!value) return "";
  const parts = value.split("|");
  return parts.length === 2 ? parts[language === "ru" ? 0 : 1].trim() : value;
};

const GuidePreview: React.FC<{ guide: Record<string, any>; language: string }> = ({ guide, language }) => {
  const prefix = language === "ru" ? "descriptionRu" : "descriptionEn";
  const description = [1, 2, 3]
    .map(index => guide[`${prefix}${index}`] || "")
    .join("")
    .replace(/imagesguides/g, "/images/guides/")
    .replace(/(guide_\d+)([a-zA-Z])/g, "$1/$2")
    .replace(/\[img:([^/][^\]]+)\]/g, "[img:/$1]");
  return (
    <div className="guide-page admin-guide-preview">
      <h1 className="guide-page-title">{language === "ru" ? guide.nameRu : guide.nameEn}</h1>
      <div className="guide-header"><time className="guide-page-date">{guide.date}</time></div>
      <div className="guide-page-content"><SkillCoinDescription description={description} /></div>
    </div>
  );
};

const ThemePreview: React.FC<{ theme: Record<string, any>; language: string }> = ({ theme, language }) => {
  const { t } = useTranslation();
  const [normal, hard] = String(theme.complexity || "").split("|").map(value => value.trim());
  const bosses = Array.from(String(theme.possiblebosses || "").matchAll(/([^,[]+)\[([^|]+)\|([^\]]+)\](?:,|$)/g));
  return (
    <div className="MDThemes admin-theme-preview">
      <div className="MDThemes-container">
        <section className="MDThemes-section is-active">
          <div className="MDThemes-poster-wrapper">
            <div className="MDThemes-hook" />
            <img className="MDThemes-poster" src={`/images/md-themes/${theme.id}.webp`} alt={localized(theme.name, language)} />
          </div>
          <div className="MDThemes-info-content">
            <h3 className="MDThemes-info-title">{localized(theme.name, language)}</h3>
            <div className="MDThemes-complexity">
              {normal && <div><strong>{language === "ru" ? "Нормальный" : "Normal"}:</strong> {normal.replace(/\d+/g, value => `${value}F`)}</div>}
              {hard && <div><strong>{language === "ru" ? "Сложный" : "Hard"}:</strong> {hard.replace(/\d+/g, value => `${value}F`)}</div>}
            </div>
            {theme.description && <div className="MDThemes-description">{localized(theme.description, language).split("<br>").map((line, index) => <React.Fragment key={index}>{index > 0 && <br />}{line}</React.Fragment>)}</div>}
            {theme.uniquegifts && <div className="MDThemes-gifts-block"><h4>{t("MDEventOption.gifts_uniquegifts")}:</h4><div className="MDEvents-ego-gifts-section clickable-gifts">{createGiftList(String(theme.uniquegifts).split(",").map(value => value.trim()), t)}</div></div>}
            {!!bosses.length && <div className="MDThemes-bosses-block"><h4>{t("MDEventOption.bosses")}:</h4><div className="MDThemes-bosses-wrapper">{bosses.map((match, index) => {
              const imageId = match[1].trim();
              const name = match[language === "ru" ? 2 : 3].trim();
              return <div className="MDThemes-boss-card" key={`${imageId}-${index}`}><img className="MDThemes-mini-item" src={`/images/enemies/${imageId}.webp`} alt={name} /><span className="MDThemes-boss-name">{name}</span></div>;
            })}</div></div>}
            {theme.events && <div className="MDThemes-events-block"><h4>{t("MDEventOption.events")}:</h4><div className="MDThemes-events-icons">{String(theme.events).split(",").map((id: string) => <img key={id} className="MDThemes-mini-item clickable-item" src={`/images/md-events/${id.trim()}.webp`} alt={id.trim()} />)}</div></div>}
          </div>
        </section>
      </div>
    </div>
  );
};

const MDEventPreview: React.FC<{ event: MDEvent; language: string }> = ({ event, language }) => {
  const { t } = useTranslation();
  const option = language === "ru" ? event.choiceRU : event.choiceEN;
  const name = language === "ru" ? event.abnoRU : event.abnoEN;
  return (
    <div className="MDEvents admin-md-event-preview">
      <section className="MDEvents-section MDEvents-section--clickable MDEvents-section--false">
        <header><h3>{name}</h3><img src={`/images/md-events/${event.id}.webp`} alt={name} /><span className="MDEvents-ego-gifts-span">{t("MDEventOption.gifts_list_header")}</span><div className="MDEvents-ego-gifts-section">{createGiftList(option?.gift_id, t)}</div></header>
      </section>
      <div className="MDEvents-modal-body"><MDEventOption option={option} /></div>
    </div>
  );
};

export const AdminRecordPreview: React.FC<Props> = ({ tableName, draft, language: languageOverride }) => {
  const { i18n } = useTranslation();
  const queryClient = useQueryClient();
  const language = languageOverride || (i18n.language === "ru" ? "ru" : "en");
  const statusesReady = Boolean(queryClient.getQueryData("statuses"));
  const isStatus = tableName === "sinner_statuses" || tableName === "anomaly_statuses";

  useEffect(() => {
    if (languageOverride && i18n.language !== languageOverride) i18n.changeLanguage(languageOverride);
  }, [i18n, languageOverride]);

  const identity = useMemo(() => tableName === "ids" ? validate<IdentityInterface>("identities", draft) : null, [draft, tableName]);
  const ego = useMemo(() => tableName === "ego_new" ? validate<EGOInterface>("ego", draft) : null, [draft, tableName]);
  const mdEvent = useMemo(() => tableName === "md_events" ? validate<MDEvent>("md-events", draft) : null, [draft, tableName]);
  const gift = useMemo(() => tableName === "md_gifts" ? validate<MDGift>("md-gifts", draft) : null, [draft, tableName]);

  if ((identity || ego) && !statusesReady) return <div className="admin-preview-unavailable">Загрузка зависимостей предпросмотра…</div>;
  if (identity) return <div className="entityFullInfo entityFullInfo--identity admin-entity-preview"><EntityFullInfoIdentity identity={identity} maxLvlIdentity={60} statusUnik={identity.statusUnik} /><IdentitySkills identity={identity} maxLvlIdentity={60} /></div>;
  if (ego) return <div className="entityFullInfo admin-entity-preview"><EntityFullInfoEGO ego={ego} statusUnik={ego.statusUnik} uptieValue={4} /><EgoSkills ego={ego} /></div>;
  if (isStatus) {
    const name = draft[`name${language.toUpperCase()}`] || draft.nameEN || draft.id || "";
    const statusClass = draft.tip === "baf" ? "status-name2" : draft.tip === "pas" ? "status-name3" : "status-name";
    return <div className="TooltipMobile admin-status-preview">
      <div className="TooltipMobile-header">
        {draft.id && <img className="status" src={`/images/tags/${draft.id}.webp`} alt={draft.id} />}
        <span className={`${statusClass} status-name--${draft.id} tooltip-container`}>{name}</span>
      </div>
      <hr />
      <div className="TooltipMobile-info"><SkillCoinDescription description={draft[`description${language.toUpperCase()}`] || ""} /></div>
    </div>;
  }
  if (mdEvent) return <MDEventPreview event={mdEvent} language={language} />;
  if (tableName === "guides") return <GuidePreview guide={draft} language={language} />;
  if (tableName === "themes") return <ThemePreview theme={draft} language={language} />;
  if (gift) return <GiftsHeader previewGift={gift} />;
  if (tableName === "changelog") return <div className="changelog-content admin-changelog-preview"><ChangelogItem item={draft as ChanLogInterface} language={language} /></div>;
  if (tableName === "events") return <div className="changelog-content admin-event-preview"><EventSector event={draft as EventInterface} /></div>;
  if (tableName === "news_list") return <div className="vibe-banner-slot admin-news-preview"><div className="vibe-banner-content"><div className="vibe-banner-text"><h3 className="vibe-banner-title">{language === "ru" ? draft.title : draft.enTitle}</h3><p className="vibe-banner-desc">{language === "ru" ? draft.desc : draft.enDesc}</p></div><img src="/images/chibi/dante.png" alt="Chibi" className="vibe-banner-chibi" /></div><div className="vibe-banner-border-corner" /></div>;
  if (tableName === "md_gifts_obtain") return <div className="GiftsHeader-wrapper admin-obtain-preview"><div className="GiftsHeader-desc"><SkillCoinDescription description={language === "ru" ? draft.obtainRU : draft.obtainEN} /></div></div>;
  if (tableName === "team_presets") return <CommunityTeamCard team={draft as TeamPreset} showModeration />;
  return <div className="admin-preview-unavailable">Для этой таблицы нет отдельного публичного компонента.</div>;
};
