import React, { useEffect, useRef } from "react";
import { useDispatch } from "react-redux";
import useHover from "../../../../hooks/useHover";
import { useTypedSelector } from "../../../../hooks/useTypedSelector";
import { IdentityInterface } from "../../../../store/reducers/ids-reducer";
import { EnergyInterface, getSupportPassiveCostBySin, normalizeTbSin, tbResetHoverAction, tbSetHoverAction } from "../../../../store/reducers/tb-reducer";

const SINS_ORDER = ["wrath", "lust", "sloth", "glut", "gloom", "pride", "envy"];

interface TbSinInterface {
    sin: string;
    energy: EnergyInterface;

    className?: string;  // Добавьте это, если хотите передавать класс
    isSpent?: boolean; 
}

export const TbSin: React.FC<TbSinInterface> = ({ sin, energy }) => {
    
    const count = Number(energy.energyListPresent[sin as keyof typeof energy.energyListPresent]) || 0;
    const reqCount = Number(energy.energyListReq[sin as keyof typeof energy.energyListReq]) || 0;
    const { hover: tbHoverState, slots } = useTypedSelector(state => state.tbReducer);
    const supportPassiveCost = slots.reduce((total, slot) => {
        if (slot.role !== "support" || !slot.identity) return total;
        return total + getSupportPassiveCostBySin(slot.identity, sin);
    }, 0);

    const calcIndentity = (result: { visible: boolean; pres: number; req: number }, identity: IdentityInterface) => {
        const { skillsSin } = identity;
        if (normalizeTbSin(skillsSin[0]) === sin) {
            result.pres += 3;
            result.visible = true;
        }
        if (normalizeTbSin(skillsSin[1]) === sin) {
            result.pres += 2;
            result.visible = true;
        }
        if (normalizeTbSin(skillsSin[2]) === sin) {
            result.pres += 1;
            result.visible = true;
        }
        identity.guardSin?.forEach(guardSin => {
            if (normalizeTbSin(guardSin) !== sin) return;
            result.pres += 1;
            result.visible = true;
        });
        return result;
    }

    const calcEGO = (result: { visible: boolean; pres: number; req: number }, currEGO: any) => {
        let affinityReq = 0;

        // Если SinCost — это массив, ищем стоимость по индексу греха
        if (currEGO && Array.isArray(currEGO.SinCost)) {
            const sinIndex = SINS_ORDER.indexOf(sin);
            if (sinIndex !== -1) {
                affinityReq = Number(currEGO.SinCost[sinIndex]) || 0;
            }
        } else if (currEGO) {
            // Запасной вариант на случай старой структуры EGO (где грехи были ключами)
            affinityReq = Number(currEGO[sin as keyof typeof currEGO]) || 0;
        }

        result.req += affinityReq;
        if (affinityReq > 0) result.visible = true;
        return result;
    }

    const slotHoverMatch = () => {
        let result = { visible: false, pres: 0, req: 0 };
        if (!tbHoverState) return result;
        
        if (tbHoverState.type === "slot") {
            const { ego, identity, role } = tbHoverState.trigger;
            if (identity) {
                if (role === "support") {
                    const passiveCost = getSupportPassiveCostBySin(identity, sin);
                    result.req += passiveCost;
                    if (passiveCost > 0) result.visible = true;
                } else {
                    calcIndentity(result, identity);
                }
            }
            if (role === "support") return result;
            for (const key in ego) {
                const currEGO = ego[key];
                if (currEGO) calcEGO(result, currEGO);
            } 
        }
        else if (tbHoverState.type === "slot-identity") {
            if (tbHoverState.trigger) {
                const passiveCost = slots.some(slot => slot.identity === tbHoverState.trigger && slot.role === "support")
                    ? getSupportPassiveCostBySin(tbHoverState.trigger, sin)
                    : 0;
                if (passiveCost > 0) {
                    result.req += passiveCost;
                    result.visible = true;
                } else {
                    calcIndentity(result, tbHoverState.trigger);
                }
            }
        } else if (tbHoverState.type === "slot-ego") {
            if (tbHoverState.trigger) calcEGO(result, tbHoverState.trigger);
        }
        return result;
    }

    const refItem = useRef(null);
    const dispatch = useDispatch();
    const isHovering = useHover(refItem);
    const slotHoverInfo = slotHoverMatch();
   
    useEffect(() => {
        if (isHovering) tbSetHoverAction(dispatch, { type: "sin", trigger: sin });
        return () => {
            tbResetHoverAction(dispatch);
        } 
    }, [dispatch, isHovering, sin])

    return (
        <div ref={refItem} className={["tb-sins-sin", slotHoverInfo.visible ? "tb-sins-sin--active" : ""].join(" ")}>
            <img src={`${process.env.PUBLIC_URL}/images/sins/${sin}.webp`} className="tb-sins-img" alt={sin}/>
            {!!supportPassiveCost && <b className="tb-sins-support">S{supportPassiveCost}</b>}
            <span>
                {count}
                {!!slotHoverInfo.pres && <span className="tb-sins-pres">{`(${slotHoverInfo.pres})`}</span>}
                /
                <span style={{color: "red"}}>{reqCount}</span>
                {!!slotHoverInfo.req && <span className="tb-sins-req">{`(${slotHoverInfo.req})`}</span>}
            </span>
        </div>
    );
}
