export type SearchableEntity = Record<string, unknown>;

const transliteration: Record<string, string> = {
  а: "a", б: "b", в: "v", г: "g", д: "d", е: "e", ё: "yo", ж: "zh", з: "z", и: "i", й: "y",
  к: "k", л: "l", м: "m", н: "n", о: "o", п: "p", р: "r", с: "s", т: "t", у: "u", ф: "f",
  х: "h", ц: "ts", ч: "ch", ш: "sh", щ: "sch", ъ: "", ы: "y", ь: "", э: "e", ю: "yu", я: "ya",
};

export const normalizeSearchText = (value: unknown): string => String(value ?? "")
  .toLocaleLowerCase()
  .normalize("NFKD")
  .replace(/[\u0300-\u036f]/g, "")
  .replace(/ё/g, "е")
  .replace(/[^\p{L}\p{N}]+/gu, " ")
  .trim();

export const transliterate = (value: string): string => value
  .toLocaleLowerCase()
  .split("")
  .map(char => transliteration[char] ?? char)
  .join("");

export const getSearchVariants = (value: unknown): string[] => {
  const normalized = normalizeSearchText(value);
  if (!normalized) return [];
  return Array.from(new Set([normalized, normalizeSearchText(transliterate(normalized))]));
};

export const getEntitySearchText = (entity: SearchableEntity): string => {
  const keys = [
    "nameRU", "nameEN", "nameRu", "nameEn", "imgUrl", "gameId", "sinner", "rarity", "egoSin",
    "statusUnik", "traits", "tagsId", "descriptionPassiveEN", "descriptionPassiveRU", "guideEN", "guideRU",
    "descriptionEn1", "descriptionEn2", "descriptionEn3", "descriptionRu1", "descriptionRu2", "descriptionRu3",
  ];
  return keys.map(key => entity[key]).filter(Boolean).map(normalizeSearchText).join(" ");
};

export const getSearchScore = (entity: SearchableEntity, query: string): number => {
  const variants = getSearchVariants(query);
  if (!variants.length) return 1;

  const names = [entity.nameRU, entity.nameEN, entity.nameRu, entity.nameEn, entity.imgUrl, entity.gameId]
    .filter(Boolean).map(normalizeSearchText);
  const allText = getEntitySearchText(entity);
  let best = 0;

  for (const variant of variants) {
    for (const name of names) {
      if (name === variant) best = Math.max(best, 100);
      else if (name.startsWith(variant)) best = Math.max(best, 80);
      else if (name.includes(variant)) best = Math.max(best, 60);
    }
    if (allText.includes(variant)) best = Math.max(best, 20);
  }

  return best;
};

export const matchesSearch = (entity: SearchableEntity, query: string): boolean => getSearchScore(entity, query) > 0;

export const rankSearchResults = <T extends SearchableEntity>(entities: T[], query: string): T[] => entities
  .map((entity, index) => ({ entity, score: getSearchScore(entity, query), index }))
  .filter(item => item.score > 0)
  .sort((a, b) => b.score - a.score || a.index - b.index)
  .map(item => item.entity);
