import { StatusesInterface } from "../store/reducers/statuses-reducer";

export const isStatusFilterMatching = (
    searchValue:string, 
    status:StatusesInterface) =>{
    const {nameEN,nameRU} = status;
    const query = searchValue.toLocaleLowerCase();

    return String(nameRU || "").toLocaleLowerCase().includes(query)
        || String(nameEN || "").toLocaleLowerCase().includes(query);
};
