import React, { useState } from 'react';
import { TRAITS } from './traits';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useParams } from 'react-router-dom';
import { SEOHelmet } from '../../pages/SEOHelmet';
import { EGOInterface } from '../../store/reducers/ego-reducer';
import { LanguageDisclaimer } from '../language-disclaimer/LanguageDisclaimer';
import { EntityFullInfoEGO } from './entity-full-info-ego/EntityFullInfoEGO';
import { EgoSkills } from './ego-skills/EgoSkills';
import './EntityFullInfo.css';
import { useReviewerAccess } from '../../hooks/useReviewerAccess';
import { RelatedEntities } from './RelatedEntities';
import './RelatedEntities.css';

export const EntityFullInfoEGOMain = () => {
    const { egoId } = useParams();
    const { i18n, t } = useTranslation();

    const uptieValue = 4;
    const [showTraits, setShowTraits] = useState(false);

    const { isReviewer: canViewTraits } = useReviewerAccess();

    const entities = useQueryClient().getQueryData(
        'ego'
    ) as EGOInterface[];

    const entity = entities?.find(
        id => id.imgUrl === egoId
    );

    if (!entity) return null;

    const statusUnik = (entity as any).statusUnik || '';

    const traits = (entity as any).traits
        ? (entity as any).traits
              .split(',')
              .map((trait: string) => trait.trim())
              .filter(Boolean)
        : [];

    const nameKey =
        `name${i18n.language.toUpperCase()}` as keyof typeof entity;

    const rawName = entity[nameKey] as string;

    const sinnerId = (entity.sinner || '')
        .toLowerCase()
        .replace(/\s/g, '');

    const translatedSinner = t(`sinners.${sinnerId}`);

    const fullDisplayName = `[${rawName}] ${translatedSinner}`;
    const sourceDescription = (i18n.language === 'ru' ? entity.descriptionPassiveRU : entity.descriptionPassiveEN || '')
        .replace(/\s+/g, ' ').trim().slice(0, 300);

    return (
        <>
            <SEOHelmet
                title={`${fullDisplayName} | Great Limbus Library`}
                description={sourceDescription}
            />

            <h1 className="entity-info-header">
                {fullDisplayName}

                <LanguageDisclaimer />

                {canViewTraits && traits.length > 0 && (
                    <div
                        className="entity-traits-dropdown"
                        onClick={() =>
                            setShowTraits(prev => !prev)
                        }
                    >
                        <span className="entity-traits-title">
                            {i18n.language === 'ru'
                                ? `Черты ${showTraits ? '▲' : '▼'}`
                                : `Traits ${showTraits ? '▲' : '▼'}`}
                        </span>

                        {showTraits && (
                            <div className="entity-traits-list">
                                {traits.map((trait: string, index: number) => {
                                    const traitInfo = TRAITS[trait];

                                    return (
                                        <span
                                            key={`${trait}-${index}`}
                                            className="entity-trait-tag"
                                        >
                                            {traitInfo
                                                ? traitInfo[
                                                      i18n.language === 'ru'
                                                          ? 'ru'
                                                          : 'en'
                                                  ]
                                                : trait}
                                        </span>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}
            </h1>

            <div className="entityFullInfo">
                <EntityFullInfoEGO
                    ego={entity}
                    statusUnik={statusUnik}
                    uptieValue={uptieValue}
                />

                <EgoSkills
                    ego={entity}
                />
            </div>
            <RelatedEntities entity={entity} />
        </>
    );
};
