import { useQueries, useQuery, UseQueryResult } from "react-query";
import { CACHE_TIME } from "./cache";
import { universalFetcher } from "./universalFetcher";

const queryOptions = {
  staleTime: CACHE_TIME,
  cacheTime: Infinity,
  refetchOnWindowFocus: false,
  retry: 2
};

const useFetch = (key: string) => useQuery(
  key,
  () => universalFetcher(key),
  queryOptions
);

export const useFetchNewsList = () => useFetch("news_list");
export const useFetchMDGifts = () => useFetch("md-gifts");
export const useFetchChanLog = () => useFetch("chanlog");

export const useFetchByKeys = (keys: string[]): UseQueryResult<unknown[], unknown>[] =>
  useQueries(keys.map((key) => ({
    queryKey: key,
    queryFn: () => universalFetcher(key),
    ...queryOptions
  }))) as UseQueryResult<unknown[], unknown>[];
