import React from "react";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { normalizeTbSin } from "../../../store/reducers/tb-reducer";
import "./TbResonance.css";

const SINS = ["wrath", "lust", "sloth", "glut", "gloom", "pride", "envy"] as const;

const SIN_LABELS: Record<string, string> = {
    wrath: "Wrath",
    lust: "Lust",
    sloth: "Sloth",
    glut: "Gluttony",
    gloom: "Gloom",
    pride: "Pride",
    envy: "Envy",
};

export const TbResonance = () => {
    const { slots } = useTypedSelector(state => state.tbReducer);
    const resonanceCounts = slots.reduce<Record<string, number>>((result, slot) => {
        if (slot.role !== "combat" || !slot.identity) return result;

        const addSin = (sin: string | undefined, value: number) => {
            const key = normalizeTbSin(String(sin || ""));
            if (!SINS.includes(key as typeof SINS[number])) return;
            result[key] = (result[key] || 0) + value;
        };

        addSin(slot.identity.skillsSin[0], 3);
        addSin(slot.identity.skillsSin[1], 2);
        addSin(slot.identity.skillsSin[2], 1);
        slot.identity.guardSin?.forEach(sin => addSin(sin, 1));

        return result;
    }, {});

    return (
        <section className="tb-resonance">
            <h2 className="tb-resonance-header">Resonance</h2>
            <div className="tb-resonance-container">
                {SINS.map(sin => {
                    const count = Number(resonanceCounts[sin]) || 0;
                    const tier = count >= 6 ? 6 : count >= 3 ? 3 : 0;

                    return (
                        <div
                            className={[
                                "tb-resonance-pill",
                                `tb-resonance-pill--${sin}`,
                                tier ? "tb-resonance-pill--active" : "",
                                tier === 6 ? "tb-resonance-pill--max" : "",
                            ].join(" ")}
                            key={sin}
                            title={SIN_LABELS[sin]}
                        >
                            <img src={`${process.env.PUBLIC_URL}/images/sins/${sin}.webp`} alt="" />
                            <span>{SIN_LABELS[sin]}</span>
                            {!!tier && <b>{tier} ✓</b>}
                        </div>
                    );
                })}
            </div>
        </section>
    );
};
