import React, { useCallback, useEffect, useMemo, useState } from "react";
import { Session } from "@supabase/supabase-js";
import { del } from "idb-keyval";
import { useQueryClient } from "react-query";
import { FETCH_CONFIG } from "../../api/fetchConfig";
import { getCacheKey } from "../../api/cache";
import { supabase } from "../../tools/supabaseClient";
import { verifyDiscordAccess } from "../../tools/discordAccess";
import { AUTH_RETURN_PATH_KEY, beginAccountLink, getOAuthCallbackUrl } from "../../hooks/useAuthSession";
import { DiscordIconSVG } from "../svg/DiscordIcon";
import { useLocation, useNavigate } from "react-router-dom";
import { AdminRecordPreview } from "./AdminRecordPreview";
import "./AdminEditor.css";

type DatabaseRow = Record<string, any>;
type PaneSizes = { navigation: number; records: number; preview: number };

type TableConfig = {
  name: string;
  label: string;
  group: "Основное" | "Подземелье" | "Статусы" | "Сообщество" | "Import";
  primaryKey: string;
  queryKeys: string[];
  image?: (row: DatabaseRow) => string | null;
};

const TABLES: TableConfig[] = [
  { name: "game_import_rows", label: "Проверка импорта", group: "Import", primaryKey: "id", queryKeys: [] },
  { name: "team_presets", label: "Команды игроков", group: "Сообщество", primaryKey: "id", queryKeys: ["community-teams"] },
  { name: "ids", label: "Айди", group: "Основное", primaryKey: "imgUrl", queryKeys: ["identities"], image: row => row.imgUrl ? `/images/identities/${row.imgUrl}.1.webp` : null },
  { name: "ego_new", label: "E.G.O", group: "Основное", primaryKey: "imgUrl", queryKeys: ["ego"], image: row => row.imgUrl ? `/images/ego/${row.imgUrl}.webp` : null },
  { name: "guides", label: "Гайды", group: "Основное", primaryKey: "ids", queryKeys: ["guides"], image: row => row.ids ? `/images/guides/${row.ids}/${row.ids}.webp` : null },
  { name: "events", label: "События", group: "Основное", primaryKey: "id", queryKeys: ["events_list"], image: row => row.imgSrc || null },
  { name: "news_list", label: "Новости", group: "Основное", primaryKey: "title", queryKeys: ["news_list"] },
  { name: "changelog", label: "История изменений", group: "Основное", primaryKey: "ids", queryKeys: ["chanlog"] },
  { name: "md_events", label: "MD события", group: "Подземелье", primaryKey: "id", queryKeys: ["md-events"], image: row => row.id ? `/images/md-events/${row.id}.webp` : null },
  { name: "md_gifts", label: "MD гифты", group: "Подземелье", primaryKey: "id", queryKeys: ["md-gifts"], image: row => row.id ? `/images/md-gifts/${row.id}.webp` : null },
  { name: "md_gifts_obtain", label: "Получение гифтов", group: "Подземелье", primaryKey: "id", queryKeys: ["md-gifts"] },
  { name: "themes", label: "Темы этажей", group: "Подземелье", primaryKey: "id", queryKeys: ["themes"], image: row => row.id ? `/images/md-themes/${row.id}.webp` : null },
  { name: "sinner_statuses", label: "Статусы личностей", group: "Статусы", primaryKey: "id", queryKeys: ["statuses"], image: row => row.id ? `/images/tags/${row.id}.webp` : null },
  { name: "anomaly_statuses", label: "Статусы аномалий", group: "Статусы", primaryKey: "id", queryKeys: ["statuses"], image: row => row.id ? `/images/tags/${row.id}.webp` : null }
];

const NUMERIC_FIELDS = new Set([
  "ids.gameId",
  "ego_new.gameId",
  "events.id",
  "changelog.ids",
  "md_gifts.tier",
  "md_gifts_obtain.id"
]);

const LONG_FIELD_PATTERN = /(description|coin|review|guide|choice|obtain|possiblebosses|uniquegifts|events|tip|resists|sincost|skills|traits|statusunik|fuse)/i;
const TITLE_FIELDS = ["nameRU", "nameRu", "nameEN", "nameEn", "title", "enTitle", "name", "abnoRU", "abnoEN", "id", "ids", "imgUrl"];

type AdminAccessResult = { admin: boolean; error: string };
let adminAccessCache: { userId: string; result: AdminAccessResult; expiresAt: number } | null = null;
let pendingAdminAccess: { userId: string; promise: Promise<AdminAccessResult> } | null = null;

const verifyDiscordAdmin = async (session: Session): Promise<AdminAccessResult> => {
  const userId = session.user.id;
  if (adminAccessCache?.userId === userId && adminAccessCache.expiresAt > Date.now()) return adminAccessCache.result;
  if (pendingAdminAccess?.userId === userId) return pendingAdminAccess.promise;

  const promise = (async () => {
    const access = await verifyDiscordAccess(session);
    let message = access.error || "";
    if (!message && !access.admin) {
      message = "У Discord-аккаунта нет ни одной разрешённой роли администратора.";
    }
    const result = { admin: access.admin, error: message };
    adminAccessCache = { userId, result, expiresAt: Date.now() + (result.admin ? 60_000 : 5_000) };
    return result;
  })();
  pendingAdminAccess = { userId, promise };
  try {
    return await promise;
  } finally {
    if (pendingAdminAccess?.promise === promise) pendingAdminAccess = null;
  }
};

const stringifyValue = (value: any) => {
  if (value === null || value === undefined) return "";
  if (typeof value === "object") return JSON.stringify(value, null, 2);
  return String(value);
};

const recordTitle = (row: DatabaseRow) => {
  for (const key of TITLE_FIELDS) {
    if (row[key] !== null && row[key] !== undefined && String(row[key]).trim()) return String(row[key]);
  }
  return "Без названия";
};

const recordSubtitle = (row: DatabaseRow, primaryKey: string) => {
  const value = row[primaryKey];
  return value === null || value === undefined ? "Новая запись" : `${primaryKey}: ${value}`;
};

export const AdminEditor: React.FC = () => {
  const queryClient = useQueryClient();
  const location = useLocation();
  const navigate = useNavigate();
  const [user, setUser] = useState<any>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [authLoading, setAuthLoading] = useState(true);
  const [authError, setAuthError] = useState("");

  const [tableName, setTableName] = useState(TABLES[0].name);
  const [rows, setRows] = useState<DatabaseRow[]>([]);
  const [counts, setCounts] = useState<Record<string, number>>({});
  const [selectedRow, setSelectedRow] = useState<DatabaseRow | null>(null);
  const [draft, setDraft] = useState<DatabaseRow>({});
  const [nullFields, setNullFields] = useState<Set<string>>(new Set());
  const [search, setSearch] = useState("");
  const [moderationFilter, setModerationFilter] = useState<"all" | "pending" | "approved" | "rejected">("pending");
  const [loadingRows, setLoadingRows] = useState(false);
  const [saving, setSaving] = useState(false);
  const [isNew, setIsNew] = useState(false);
  const [showRawPreview, setShowRawPreview] = useState(false);
  const [previewLanguage, setPreviewLanguage] = useState<"ru" | "en">("ru");
  const [notice, setNotice] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [paneSizes, setPaneSizes] = useState<PaneSizes>({ navigation: 224, records: 320, preview: 460 });
  const [previewDependenciesReady, setPreviewDependenciesReady] = useState(false);

  const table = useMemo(() => TABLES.find(item => item.name === tableName) || TABLES[0], [tableName]);
  const isCommunityTable = table.name === "team_presets";
  const isImportQueue = table.name === "game_import_rows";
  const effectiveTableName = isImportQueue ? (selectedRow?.target_table || "ids") : table.name;
  const isDirty = useMemo(() => {
    if (isNew) return Object.values(draft).some(value => value !== "" && value !== null && value !== undefined);
    const source = isImportQueue ? selectedRow?.payload : selectedRow;
    return Boolean(source) && JSON.stringify(draft) !== JSON.stringify(source);
  }, [draft, isImportQueue, isNew, selectedRow]);

  const setAuthenticatedSession = useCallback(async (session: Session | null) => {
    const currentUser = session?.user || null;
    setUser(currentUser || null);
    if (!currentUser || !session) {
      setIsAdmin(false);
      return;
    }
    const result = await verifyDiscordAdmin(session);
    setIsAdmin(result.admin);
    setAuthError(result.error);
  }, []);

  useEffect(() => {
    let mounted = true;
    supabase.auth.getSession().then(async ({ data }) => {
      if (mounted) await setAuthenticatedSession(data.session);
      if (mounted) setAuthLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      window.setTimeout(() => setAuthenticatedSession(session), 0);
    });
    const refreshTimer = window.setInterval(() => {
      supabase.auth.getSession().then(({ data }) => setAuthenticatedSession(data.session));
    }, 5 * 60 * 1000);
    return () => {
      mounted = false;
      window.clearInterval(refreshTimer);
      subscription.unsubscribe();
    };
  }, [setAuthenticatedSession]);

  useEffect(() => {
    if (!user?.id) return;
    const saved = localStorage.getItem(`gll-admin-panes-${user.id}`);
    if (saved) {
      try { setPaneSizes({ ...paneSizes, ...JSON.parse(saved) }); } catch { /* ignore invalid saved layout */ }
    }
  // The layout is restored once when the authenticated account changes.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user?.id]);

  useEffect(() => {
    if (user?.id) localStorage.setItem(`gll-admin-panes-${user.id}`, JSON.stringify(paneSizes));
  }, [paneSizes, user?.id]);

  const startPaneResize = (pane: keyof PaneSizes, event: React.PointerEvent<HTMLDivElement>) => {
    event.preventDefault();
    const startX = event.clientX;
    const startValue = paneSizes[pane];
    document.body.classList.add("admin-is-resizing");
    const handleMove = (moveEvent: PointerEvent) => {
      const delta = moveEvent.clientX - startX;
      const limits: Record<keyof PaneSizes, [number, number]> = {
        navigation: [160, 360],
        records: [240, 560],
        preview: [320, Math.max(420, window.innerWidth * 0.72)]
      };
      const nextValue = startValue + (pane === "preview" ? -delta : delta);
      const [minimum, maximum] = limits[pane];
      setPaneSizes(previous => ({ ...previous, [pane]: Math.round(Math.min(maximum, Math.max(minimum, nextValue))) }));
    };
    const handleUp = () => {
      document.body.classList.remove("admin-is-resizing");
      window.removeEventListener("pointermove", handleMove);
      window.removeEventListener("pointerup", handleUp);
    };
    window.addEventListener("pointermove", handleMove);
    window.addEventListener("pointerup", handleUp);
  };

  const loadCounts = useCallback(async () => {
    const entries = await Promise.all(TABLES.map(async config => {
      const { count } = await supabase.from(config.name).select("*", { count: "exact", head: true });
      return [config.name, count || 0] as const;
    }));
    setCounts(Object.fromEntries(entries));
  }, []);

  const loadPreviewDependencies = useCallback(async () => {
    setPreviewDependenciesReady(false);
    const [sinnerResult, anomalyResult, giftsResult, eventsResult] = await Promise.all([
      supabase.from("sinner_statuses").select("*"),
      supabase.from("anomaly_statuses").select("*"),
      supabase.from("md_gifts").select("*"),
      supabase.from("md_events").select("*")
    ]);
    const normalizeStatuses = (items: any[] = []) => items.map(item => ({
      ...item,
      nameEN: item.nameEN || item.nameen || "",
      owners: typeof item.owners === "string" ? item.owners.split(",").map((owner: string) => owner.trim()) : (item.owners || [])
    }));
    queryClient.setQueryData("statuses", [...normalizeStatuses(sinnerResult.data || []), ...normalizeStatuses(anomalyResult.data || [])]);
    queryClient.setQueryData("md-gifts", FETCH_CONFIG["md-gifts"].validator?.(giftsResult.data || []) || giftsResult.data || []);
    queryClient.setQueryData("md-events", FETCH_CONFIG["md-events"].validator?.(eventsResult.data || []) || eventsResult.data || []);
    setPreviewDependenciesReady(true);
  }, [queryClient]);

  const selectRecord = useCallback((row: DatabaseRow | null, creating = false) => {
    if (isDirty && !window.confirm("Есть несохранённые изменения. Продолжить без сохранения?")) return false;
    setSelectedRow(row);
    const source = row && isImportQueue ? row.payload : row;
    setDraft(source ? { ...source } : {});
    setNullFields(new Set(source ? Object.keys(source).filter(key => source[key] === null) : []));
    setIsNew(creating);
    setNotice(null);
    return true;
  }, [isDirty, isImportQueue]);

  const loadRows = useCallback(async (config: TableConfig, preserveKey?: any) => {
    setLoadingRows(true);
    setNotice(null);
    const request = supabase.from(config.name).select("*").limit(5000);
    const { data, error } = config.name === "game_import_rows"
      ? await request.order("created_at", { ascending: false })
      : await request;
    setLoadingRows(false);
    if (error) {
      setRows([]);
      setNotice({ type: "error", text: error.message });
      return;
    }
    const loaded = (data || []) as DatabaseRow[];
    setRows(loaded);
    setCounts(previous => ({ ...previous, [config.name]: loaded.length }));
    const next = preserveKey !== undefined
      ? loaded.find(row => String(row[config.primaryKey]) === String(preserveKey))
      : loaded[0];
    setSelectedRow(next || null);
    const source = next && config.name === "game_import_rows" ? next.payload : next;
    setDraft(source ? { ...source } : {});
    setNullFields(new Set(source ? Object.keys(source).filter(key => source[key] === null) : []));
    setIsNew(false);
  }, []);

  useEffect(() => {
    if (!isAdmin) return;
    loadCounts();
    loadPreviewDependencies();
  }, [isAdmin, loadCounts, loadPreviewDependencies]);

  useEffect(() => {
    if (!isAdmin) return;
    loadRows(table);
  }, [isAdmin, loadRows, table]);

  useEffect(() => {
    const preventClose = (event: BeforeUnloadEvent) => {
      if (!isDirty) return;
      event.preventDefault();
      event.returnValue = "";
    };
    window.addEventListener("beforeunload", preventClose);
    return () => window.removeEventListener("beforeunload", preventClose);
  }, [isDirty]);

  const filteredRows = useMemo(() => {
    const query = search.trim().toLocaleLowerCase();
    return rows
      .filter(row => !isCommunityTable || moderationFilter === "all" || row.moderation_status === moderationFilter)
      .filter(row => !isImportQueue || moderationFilter === "all" || row.review_status === moderationFilter)
      .filter(row => !query || JSON.stringify(row).toLocaleLowerCase().includes(query));
  }, [rows, search, isCommunityTable, isImportQueue, moderationFilter]);

  const columns = useMemo(() => {
    const source = isImportQueue ? draft : (selectedRow || rows[0] || draft);
    const keys = Object.keys(source);
    const pkIndex = keys.indexOf(table.primaryKey);
    if (pkIndex > 0) keys.unshift(...keys.splice(pkIndex, 1));
    return keys;
  }, [draft, isImportQueue, rows, selectedRow, table.primaryKey]);

  const startCreate = () => {
    if (!selectRecord(null, true)) return;
    const template = rows[0] || {};
    const empty = Object.fromEntries(Object.keys(template).map(key => [key, typeof template[key] === "boolean" ? false : ""]));
    setDraft(empty);
  };

  const duplicateRecord = () => {
    if (!selectedRow || !selectRecord(null, true)) return;
    setDraft({ ...selectedRow, [table.primaryKey]: "" });
    setNullFields(new Set(Object.keys(selectedRow).filter(key => selectedRow[key] === null)));
  };

  const updateField = (key: string, value: any) => {
    setDraft(previous => ({ ...previous, [key]: value }));
    setNullFields(previous => {
      const next = new Set(previous);
      next.delete(key);
      return next;
    });
  };

  const toggleNull = (key: string) => {
    setNullFields(previous => {
      const next = new Set(previous);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  };

  const normalizePayload = () => Object.fromEntries(Object.entries(draft).map(([key, value]) => {
    if (nullFields.has(key)) return [key, null];
    if (NUMERIC_FIELDS.has(`${effectiveTableName}.${key}`) && value !== "") return [key, Number(value)];
    return [key, value];
  }));

  const clearFrontendCache = async () => {
    await Promise.all(table.queryKeys.map(async key => {
      queryClient.invalidateQueries(key);
      await del(getCacheKey(key));
    }));
  };

  const saveRecord = async () => {
    const payload = normalizePayload();
    if (isImportQueue) {
      if (!selectedRow) return;
      setSaving(true);
      const { data, error } = await supabase.from("game_import_rows").update({ payload }).eq("id", selectedRow.id).select().single();
      setSaving(false);
      if (error) {
        setNotice({ type: "error", text: error.message });
        return;
      }
      await loadRows(table, data.id);
      setNotice({ type: "success", text: "Черновик кандидата сохранён." });
      return;
    }
    if (payload[table.primaryKey] === "" || payload[table.primaryKey] === null || payload[table.primaryKey] === undefined) {
      setNotice({ type: "error", text: `Заполните обязательный ключ ${table.primaryKey}.` });
      return;
    }
    setSaving(true);
    const request = isNew
      ? supabase.from(table.name).insert(payload).select().single()
      : supabase.from(table.name).update(payload).eq(table.primaryKey, selectedRow?.[table.primaryKey]).select().single();
    const { data, error } = await request;
    setSaving(false);
    if (error) {
      setNotice({ type: "error", text: error.message });
      return;
    }
    await clearFrontendCache();
    await loadRows(table, data?.[table.primaryKey] ?? payload[table.primaryKey]);
    setNotice({ type: "success", text: isNew ? "Запись создана." : "Изменения сохранены." });
  };

  const deleteRecord = async () => {
    if (!selectedRow) return;
    const key = selectedRow[table.primaryKey];
    if (!window.confirm(`Удалить «${recordTitle(selectedRow)}»? Восстановление возможно только из бэкапа.`)) return;
    setSaving(true);
    const { error } = await supabase.from(table.name).delete().eq(table.primaryKey, key);
    setSaving(false);
    if (error) {
      setNotice({ type: "error", text: error.message });
      return;
    }
    await clearFrontendCache();
    await loadRows(table);
    setNotice({ type: "success", text: "Запись удалена." });
  };

  const moderateTeam = async (status: "approved" | "rejected") => {
    if (!selectedRow || !isCommunityTable) return;
    const note = status === "rejected" ? window.prompt("Причина отклонения (необязательно):", selectedRow.moderation_note || "") : null;
    if (status === "rejected" && note === null) return;
    setSaving(true);
    const { data, error } = await supabase
      .from("team_presets")
      .update({ moderation_status: status, moderation_note: status === "rejected" ? (note || null) : null })
      .eq("id", selectedRow.id)
      .select()
      .single();
    setSaving(false);
    if (error) {
      setNotice({ type: "error", text: error.message });
      return;
    }
    await loadRows(table, data.id);
    setNotice({ type: "success", text: status === "approved" ? "Команда опубликована." : "Команда отклонена." });
  };

  const reviewImport = async (status: "approved" | "rejected") => {
    if (!selectedRow || !isImportQueue) return;
    const note = status === "rejected" ? window.prompt("Причина отклонения:", selectedRow.review_note || "") : null;
    if (status === "rejected" && note === null) return;
    setSaving(true);
    const result = status === "approved"
      ? await supabase.rpc("apply_game_import_row", { target_row_id: selectedRow.id, edited_payload: normalizePayload() })
      : await supabase.rpc("reject_game_import_row", { target_row_id: selectedRow.id, note });
    setSaving(false);
    if (result.error) {
      setNotice({ type: "error", text: result.error.message });
      return;
    }
    const targetConfig = TABLES.find(item => item.name === selectedRow.target_table);
    if (targetConfig) {
      await Promise.all(targetConfig.queryKeys.map(async key => {
        queryClient.invalidateQueries(key);
        await del(getCacheKey(key));
      }));
    }
    await loadRows(table);
    setNotice({ type: "success", text: status === "approved" ? "Кандидат перенесён в рабочую таблицу." : "Кандидат отклонён." });
  };

  const handleLogin = async (event: React.FormEvent) => {
    event.preventDefault();
    setAuthLoading(true);
    setAuthError("");
    sessionStorage.setItem(AUTH_RETURN_PATH_KEY, window.location.pathname);
    const options = {
      redirectTo: getOAuthCallbackUrl(),
      scopes: "identify email guilds.members.read",
      queryParams: { prompt: "consent" }
    };
    const { data: { session } } = await supabase.auth.getSession();
    const discordLinked = user?.identities?.some((identity: any) => identity.provider === "discord");
    if (user && discordLinked) await supabase.auth.signOut({ scope: "local" });
    const { error } = user && session && !discordLinked
      ? await beginAccountLink(session, "discord", options.redirectTo)
      : await supabase.auth.signInWithOAuth({ provider: "discord", options });
    if (error) {
      sessionStorage.removeItem(AUTH_RETURN_PATH_KEY);
      setAuthError(error.message);
      setAuthLoading(false);
    }
  };

  if (authLoading) return <div className="admin-auth-state">Проверка доступа…</div>;

  if (!user || !isAdmin) {
    return (
      <div className="admin-auth-page">
        <form onSubmit={handleLogin} className="admin-auth-form">
          <span className="admin-auth-kicker">GLL DATABASE</span>
          <h1>Вход в админку</h1>
          <p>{user ? "У Discord-аккаунта нет нужной роли администратора." : "Доступ предоставляется по роли на Discord-сервере GLL."}</p>
          {authError && <div className="admin-notice admin-notice--error">{authError}</div>}
          <button type="submit" className="admin-discord-login" disabled={authLoading}><DiscordIconSVG />Войти через Discord</button>
          {user && <button type="button" className="admin-secondary-button" onClick={() => supabase.auth.signOut()}>Выйти из аккаунта</button>}
        </form>
      </div>
    );
  }

  return (
    <div className="admin-database-layout" style={{ "--admin-navigation-width": `${paneSizes.navigation}px`, "--admin-records-width": `${paneSizes.records}px` } as React.CSSProperties}>
      <nav className="admin-table-nav">
        <div className="admin-brand"><span>GLL</span><div><strong>Database</strong><small>единая админка</small></div></div>
        {(["Import", "Сообщество", "Основное", "Подземелье", "Статусы"] as const).map(group => (
          <section key={group} className="admin-table-group">
            <h2>{group}</h2>
            {TABLES.filter(item => item.group === group).map(item => (
              <button
                type="button"
                key={item.name}
                className={item.name === table.name ? "active" : ""}
                onClick={() => {
                  if (item.name === table.name || (isDirty && !window.confirm("Есть несохранённые изменения. Сменить таблицу?"))) return;
                  setSearch("");
                  setTableName(item.name);
                }}
              >
                <span>{item.label}</span><small>{counts[item.name] ?? "—"}</small>
              </button>
            ))}
          </section>
        ))}
        <div className="admin-account">
          <span>{user.email}</span>
          <button type="button" onClick={() => navigate(`/limbus/${location.pathname.match(/^\/limbus\/(ru|en)/)?.[1] || "en"}/`)}>На главную</button>
          <button type="button" onClick={() => supabase.auth.signOut()}>Выйти</button>
        </div>
      </nav>

      <div className="admin-pane-resizer admin-pane-resizer--main" onPointerDown={event => startPaneResize("navigation", event)} title="Изменить ширину меню" />

      <aside className="admin-records-panel">
        <header>
          <div><span>Таблица</span><h1>{table.label}</h1><code>{table.name}</code></div>
          {!isCommunityTable && !isImportQueue && <button type="button" className="admin-create-button" onClick={startCreate}>＋ Новая</button>}
        </header>
        <label className="admin-record-search">
          <span>⌕</span><input value={search} onChange={event => setSearch(event.target.value)} placeholder="Поиск по всем полям…" />
        </label>
        {isCommunityTable && <div className="admin-moderation-filters">{(["pending", "approved", "rejected", "all"] as const).map(status => <button type="button" className={moderationFilter === status ? "active" : ""} onClick={() => setModerationFilter(status)} key={status}>{status === "pending" ? "Не одобрены" : status === "approved" ? "Одобрены" : status === "rejected" ? "Отклонены" : "Все"}</button>)}</div>}
        {isImportQueue && <div className="admin-moderation-filters">{(["pending", "approved", "rejected", "all"] as const).map(status => <button type="button" className={moderationFilter === status ? "active" : ""} onClick={() => setModerationFilter(status)} key={status}>{status}</button>)}</div>}
        <div className="admin-record-count">Показано {filteredRows.length} из {rows.length}</div>
        <div className="admin-record-list">
          {loadingRows && <div className="admin-empty-state">Загрузка записей…</div>}
          {!loadingRows && filteredRows.map(row => {
            const active = !isNew && selectedRow?.[table.primaryKey] === row[table.primaryKey];
            const displayRow = isImportQueue ? row.payload : row;
            const displayTable = isImportQueue ? TABLES.find(item => item.name === row.target_table) : table;
            const thumb = displayTable?.image?.(displayRow);
            return (
              <button type="button" className={`admin-record-item ${active ? "active" : ""}`} key={String(row[table.primaryKey])} onClick={() => selectRecord(row)}>
                {thumb && <img src={thumb} alt="" onError={event => { event.currentTarget.style.display = "none"; }} />}
                <span><strong>{recordTitle(displayRow)}</strong><small>{isImportQueue ? `${row.target_table} · ${row.operation} · ${row.translation_status}` : recordSubtitle(row, table.primaryKey)}</small></span>
              </button>
            );
          })}
          {!loadingRows && !filteredRows.length && <div className="admin-empty-state">Ничего не найдено.</div>}
        </div>
      </aside>


      <div className="admin-pane-resizer admin-pane-resizer--main" onPointerDown={event => startPaneResize("records", event)} title="Изменить ширину списка" />

      <main className="admin-editor-panel">
        <header className="admin-editor-toolbar">
          <div>
            <span>{isNew ? "Новая запись" : "Редактирование"}</span>
            <h2>{isNew ? `Создание в ${table.label}` : selectedRow ? recordTitle(draft) : "Выберите запись"}</h2>
          </div>
          <div className="admin-editor-actions">
            {selectedRow && !isNew && isCommunityTable && draft.moderation_status !== "approved" && <button type="button" className="primary" onClick={() => moderateTeam("approved")} disabled={saving}>Одобрить</button>}
            {selectedRow && !isNew && isCommunityTable && draft.moderation_status !== "rejected" && <button type="button" onClick={() => moderateTeam("rejected")} disabled={saving}>Отклонить</button>}
            {selectedRow && isImportQueue && selectedRow.review_status === "pending" && <button type="button" className="primary" onClick={() => reviewImport("approved")} disabled={saving}>Одобрить и применить</button>}
            {selectedRow && isImportQueue && selectedRow.review_status === "pending" && <button type="button" className="danger" onClick={() => reviewImport("rejected")} disabled={saving}>Отклонить</button>}
            {selectedRow && !isNew && !isCommunityTable && !isImportQueue && <button type="button" onClick={duplicateRecord}>Дублировать</button>}
            {selectedRow && !isNew && !isImportQueue && <button type="button" className="danger" onClick={deleteRecord} disabled={saving}>Удалить</button>}
            <button type="button" className="primary" onClick={saveRecord} disabled={saving || (!selectedRow && !isNew) || (isImportQueue && selectedRow?.review_status !== "pending")}>{saving ? "Сохранение…" : isImportQueue ? "Сохранить черновик" : "Сохранить"}</button>
          </div>
        </header>

        {notice && <div className={`admin-notice admin-notice--${notice.type}`}>{notice.text}</div>}
        {isImportQueue && selectedRow && <div className="admin-import-meta">
          <strong>{selectedRow.target_table} · {selectedRow.operation} · {selectedRow.review_status}</strong>
          <span>Перевод: {selectedRow.translation_status}</span>
          {Array.isArray(selectedRow.warnings) && selectedRow.warnings.map((warning: string) => <em key={warning}>{warning}</em>)}
        </div>}

        {!selectedRow && !isNew ? <div className="admin-editor-empty"><h2>Выберите запись</h2><p>Или создайте новую кнопкой слева.</p></div> : (
          <div className="admin-editor-workspace" style={{ "--admin-preview-width": `${paneSizes.preview}px` } as React.CSSProperties}>
            <section className="admin-fields">
              {columns.map(key => {
                const sourceValue = draft[key];
                const isNull = nullFields.has(key);
                const isBoolean = typeof (isImportQueue ? draft : (selectedRow || rows[0] || {}))[key] === "boolean";
                const isNumeric = NUMERIC_FIELDS.has(`${effectiveTableName}.${key}`);
                const isLong = LONG_FIELD_PATTERN.test(key) || stringifyValue(sourceValue).length > 100;
                return (
                  <label key={key} className={`admin-field ${isLong ? "admin-field--wide" : ""}`}>
                    <span className="admin-field-label">
                      <strong>{key}</strong>
                      {key === table.primaryKey && <em>PRIMARY KEY</em>}
                      <button type="button" className={isNull ? "active" : ""} onClick={() => toggleNull(key)}>NULL</button>
                    </span>
                    {isBoolean ? (
                      <select value={isNull ? "null" : String(Boolean(sourceValue))} onChange={event => event.target.value === "null" ? toggleNull(key) : updateField(key, event.target.value === "true")}>
                        <option value="true">true</option><option value="false">false</option><option value="null">null</option>
                      </select>
                    ) : isLong ? (
                      <textarea rows={Math.min(16, Math.max(5, stringifyValue(sourceValue).split("\n").length + 2))} value={isNull ? "" : stringifyValue(sourceValue)} disabled={isNull} onChange={event => updateField(key, event.target.value)} />
                    ) : (
                      <input type={isNumeric ? "number" : "text"} value={isNull ? "" : stringifyValue(sourceValue)} disabled={isNull} onChange={event => updateField(key, event.target.value)} />
                    )}
                  </label>
                );
              })}
            </section>


            <div className="admin-pane-resizer admin-pane-resizer--workspace" onPointerDown={event => startPaneResize("preview", event)} title="Изменить ширину предпросмотра" />

            <aside className="admin-live-preview">
              <header><div><span>LIVE</span><h3>Предпросмотр</h3></div><div className="admin-preview-actions"><button type="button" className={previewLanguage === "ru" ? "active" : ""} onClick={() => setPreviewLanguage("ru")}>RU</button><button type="button" className={previewLanguage === "en" ? "active" : ""} onClick={() => setPreviewLanguage("en")}>EN</button><button type="button" onClick={() => setShowRawPreview(value => !value)}>{showRawPreview ? "Читаемый" : "JSON"}</button></div></header>
              {showRawPreview ? (
                <pre className="admin-json-preview">{JSON.stringify(normalizePayload(), null, 2)}</pre>
              ) : (
                <div className="admin-component-preview">{previewDependenciesReady ? <AdminRecordPreview tableName={effectiveTableName} draft={normalizePayload()} language={previewLanguage} /> : <div className="admin-preview-unavailable">Загрузка предпросмотра…</div>}</div>
              )}
            </aside>
          </div>
        )}
      </main>
    </div>
  );
};
