import { dmgType, guardType, guardTypeExtended, sinType, normalizeGuardType } from "../constants/types";
import { EGOInterface } from "../store/reducers/ego-reducer";
import { DmgTypeFilterInterface, FilterInterface, GuardTypeFilterInterface, SinFilterInterface, SinnerFilterInterface } from "../store/reducers/filter-reducer";
import { IdentityInterface } from "../store/reducers/ids-reducer";
import { TSearchState } from "../store/reducers/search-reducer";
import { StatusesInterface } from "../store/reducers/statuses-reducer";
import { getStatusesEntityList } from "./getStatusesEntityList";
import { isIdentity } from "./isIdentity";
import { parseEntityTraits } from "../componentslimbus/entity-full-info/traits";
import { matchesSearch } from "./search";

export const isFilterMatching = (filterState: FilterInterface, searchState: TSearchState, entity: IdentityInterface | EGOInterface, locale: string, statuses: StatusesInterface[]) => {
    const { types } = filterState;
    const searchValue = searchState.value;
    const { sinner, rarity } = entity;
    if (!matchesSearch(entity as unknown as Record<string, unknown>, searchValue)) return false;

    // --- ЛОГИКА STATUS UNIK ---
    const unik = (entity as any).statusUnik as string | undefined;
    const activeTags = Object.keys(types.tags).filter(key => types.tags[key] === true);
    
    let extraTags: string[] = [];
    if (unik) {
        const [addPart, removePart] = unik.split('|').map(s => s.trim().toLowerCase());
        
        // Если выбран тег, который у этой сущности в "черном списке" (| remove)
        if (removePart && activeTags.length > 0) {
            const statusesToRemove = removePart.split('#').filter(Boolean).map(s => s.trim());
            if (activeTags.some(tag => statusesToRemove.includes(tag.toLowerCase()))) {
                return false;
            }
        }
        // Собираем доп. теги из (add |)
        if (addPart) {
            extraTags = addPart.split('#').filter(Boolean).map(s => s.trim());
        }
    }

    // Фильтр Грешников
    const isSinnerFilterAny = Object.values(types.sinner).some((value) => value);
    if (isSinnerFilterAny && !types.sinner[sinner as keyof SinnerFilterInterface]) return false;

    // Редкость
    let isAnyRarityIdentity = Object.values(types.rarityIdentity).some((value) => value);
    let isAnyRarityEGO = Object.values(types.rarityEGO).some((value) => value);

    // Сезоны и Ивенты
    const isSeasonFilterAny = Object.values(types.season).some((value) => value);
    if (isSeasonFilterAny && !types.season[entity.season[0] as keyof typeof types.season]) return false;

    const isEventFilterAny = Object.values(types.event).some((value) => value);
    if (isEventFilterAny && !types.event[entity.season[1] as keyof typeof types.event]) return false;

    // Вспомогательная функция для Fuse статусов
    function getExtendedStatuses(baseStatusIds: string[]) {
        const extended = new Set(baseStatusIds);
        baseStatusIds.forEach(id => {
            const found = statuses.find(s => s.id === id);
            if (found && found.fuse_statuses) extended.add(found.fuse_statuses);
        });
        // Добавляем теги из statusUnik
        extraTags.forEach(t => extended.add(t));
        return Array.from(extended);
    }

    if (isIdentity(entity)) {
        const { guardType, guardSin, descriptionCoinEN4, descriptionPassive1EN, descriptionPassive2EN, skillsSin, skillsDmgType } = entity;
        const statusMap = getStatusesEntityList([descriptionCoinEN4, descriptionPassive1EN, descriptionPassive2EN]);
        const fuseStatuses = getExtendedStatuses(Object.keys(statusMap));

        const activeTraits = Object.keys(types.traits || {}).filter(key => types.traits[key]);
        if (activeTraits.length) {
            const identityTraits = parseEntityTraits(entity.traits);
            const positiveTraits = new Set(identityTraits.filter(trait => !trait.negated).map(trait => trait.name));
            if (!activeTraits.every(trait => positiveTraits.has(trait))) return false;
        }

        // ПРОВЕРКА ТЕГОВ (Status)
        for (const key in types.tags) {
            if (types.tags[key] === true && !fuseStatuses.includes(key)) return false;
        }

        if ((isAnyRarityEGO || isAnyRarityIdentity) && !types.rarityIdentity[rarity as keyof typeof types.rarityIdentity]) return false;

        // Грехи
        for (const key in types.sin) {
            if (types.sin[key as keyof SinFilterInterface] === true) {
                const allSins = [...skillsSin, ...(guardSin || [])];
                if (!allSins.includes(key as sinType)) return false;
            }
        }

        // Тип урона
        for (const key in types.dmgType) {
            if (types.dmgType[key as keyof DmgTypeFilterInterface] === true && !skillsDmgType.includes(key as dmgType)) return false;
        }

        // Тип защиты
        for (const key in types.guardType) {
            if (types.guardType[key as keyof GuardTypeFilterInterface] === true) {
                const normalizedKey = normalizeGuardType(key as guardTypeExtended);
                const normalizedGuardTypes = guardType.map(gt => normalizeGuardType(gt as guardTypeExtended));
                if (!normalizedGuardTypes.includes(normalizedKey as guardType)) return false;
            }
        }
    } else {
        const { dmgType, CoinEN4, descriptionPassiveEN } = entity;
        const statusMap = getStatusesEntityList([CoinEN4, descriptionPassiveEN]);
        const fuseStatuses = getExtendedStatuses(Object.keys(statusMap));

        // ПРОВЕРКА ТЕГОВ (Status)
        for (const key in types.tags) {
            if (types.tags[key] === true && !fuseStatuses.includes(key)) return false;
        }

        if ((isAnyRarityEGO || isAnyRarityIdentity) && !types.rarityEGO[rarity as keyof typeof types.rarityEGO]) return false;

        // Грехи EGO
        const activeSinFilters = Object.entries(types.sin).filter(([_, active]) => active);
        if (activeSinFilters.length > 0) {
            // Проверяем, совпадает ли врожденный egoSin хотя бы с одним из выбранных грехов в фильтре
            const isMatch = activeSinFilters.some(([sin]) => entity.egoSin === sin);
            if (!isMatch) return false;
        }

        // Тип урона EGO
        for (const key in types.dmgType) {
            if (types.dmgType[key as keyof DmgTypeFilterInterface] === true && !dmgType.includes(key as dmgType)) return false;
        }
    }

    return true;
}
