import React from 'react';
import "./EgoPassive.css";
import { EGOInterface } from '../../../../store/reducers/ego-reducer';
import { SkillCoinDescription } from "../../../guides/text-formatter/SkillCoinDescription";
import { useTranslation } from 'react-i18next';
import { useTypedSelector } from '../../../../hooks/useTypedSelector';

interface IEntityFullInfoProps {
    ego: EGOInterface;
}

export const EgoPassive: React.FC<IEntityFullInfoProps> = ({ ego }) => {
    const { i18n } = useTranslation();
    const { selectedUptie } = useTypedSelector(s => s.uptieReducer);
    const lang = i18n.language.toUpperCase();
    const namePassiveKey = `namePassive${lang}` as keyof typeof ego;
    const namePassive = ego[namePassiveKey] as string;
    const descriptionPassiveKey =
        `descriptionPassive${lang}` as keyof typeof ego;

    const rawDescription =
        ego[descriptionPassiveKey] as string;

    let descriptionPassive = rawDescription;


    const splitText = rawDescription.split("|");

    const hasUptie5 =
        splitText.length > 1 &&
        splitText[1]?.trim().length > 0;

    if (hasUptie5) {
        // Uptie V
        if (selectedUptie >= 5) {
            descriptionPassive = splitText[1].trim();
        } else {
            // Uptie I-IV
            descriptionPassive = splitText[0].trim();
        }
    }
    const showLock = selectedUptie === 1;
    return (
        <article className="entityFullInfo-passive" style={{ position: 'relative' }}>
            {showLock && (
                <div className="lock-overlay">
                    <div className="lock-center">
                        <img
                            src={`${process.env.PUBLIC_URL}/images/general/lock.png`}
                            alt="Locked"
                        />
                    </div>
                </div>
            )}
            <p className="passive-name">{namePassive}</p>
            <SkillCoinDescription description={descriptionPassive} />
        </article>
    );
};
