import React, { useMemo } from "react";
import { Link } from "react-router-dom";
import { useQueryClient } from "react-query";
import { useTranslation } from "react-i18next";
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { isIdentity } from "../../tools/isIdentity";

type Props = { entity: IdentityInterface | EGOInterface };

export const RelatedEntities: React.FC<Props> = ({ entity }) => {
  const queryClient = useQueryClient();
  const { i18n, t } = useTranslation();
  const related = useMemo(() => {
    const source: Array<IdentityInterface | EGOInterface> = isIdentity(entity)
      ? (queryClient.getQueryData("identities") as IdentityInterface[] || [])
      : (queryClient.getQueryData("ego") as EGOInterface[] || []);
    const matches = source.filter(item => item.imgUrl !== entity.imgUrl).map(item => {
      let score = 0;
      if (item.sinner === entity.sinner) score += 3;
      if (!isIdentity(entity) && !isIdentity(item) && item.egoSin === entity.egoSin) score += 2;
      if (isIdentity(entity) && isIdentity(item)) {
        score += item.skillsSin.some(sin => entity.skillsSin.includes(sin)) ? 1 : 0;
        score += item.skillsDmgType.some(type => entity.skillsDmgType.includes(type)) ? 1 : 0;
      }
      return { item, score };
    });
    return matches.filter(item => item.score > 0).sort((a, b) => b.score - a.score).slice(0, 6).map(item => item.item);
  }, [entity, queryClient]);

  if (!related.length) return null;
  const ego = !isIdentity(entity);

  return <section className="related-entities">
    <h2>{t("RelatedEntities.header", "Related")}</h2>
    <div className="related-entities-list">
      {related.map(item => {
        const name = i18n.language === "ru" ? item.nameRU : item.nameEN;
        const path = ego ? `/limbus/${i18n.language}/ego/${item.imgUrl}` : `/limbus/${i18n.language}/identities/${item.imgUrl}`;
        return <Link key={item.imgUrl} to={path} className="related-entity-link">{name || item.imgUrl}</Link>;
      })}
    </div>
  </section>;
};
