import React, { useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { useLocation } from "react-router-dom";
import { useQueryClient } from "react-query";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { IdentityInterface } from "../../../store/reducers/ids-reducer";
import { MDEvent } from "../../../store/reducers/md-event-interface";
import { MDGift } from "../../../store/reducers/md-gift-interface";
import { filterChangeSectionValueAction, filterClearSectionAction } from "../../../store/reducers/filter-reducer";
import { extractInlineTraits, parseEntityTraits, TRAITS } from "../../entity-full-info/traits";
import { EraserSVG } from "../../svg/EraserSvg";
import "./FiltersSectionTraits.css";

type Props = { isIdentityTeamBuilder?: string };

export const FiltersSectionTraits: React.FC<Props> = ({ isIdentityTeamBuilder }) => {
    const location = useLocation().pathname;
    const paramsType = new URLSearchParams(useLocation().search).get("type");
    const queryClient = useQueryClient();
    const identities = queryClient.getQueryData("identities") as IdentityInterface[] | undefined;
    const gifts = queryClient.getQueryData("md-gifts") as MDGift[] | undefined;
    const events = queryClient.getQueryData("md-events") as MDEvent[] | undefined;
    const selected = useTypedSelector(state => state.filterReducer.types.traits);
    const dispatch = useDispatch();
    const { i18n } = useTranslation();
    const [query, setQuery] = useState("");
    const [expanded, setExpanded] = useState(false);

    const isGiftsPage = location.includes("/mirror-dungeon/gifts");
    const isEventsPage = location.includes("/mirror-dungeon/events");
    const isFusionPage = location.includes("/mirror-dungeon/rest-stops");
    const visible = paramsType === "identities"
        || location.includes("/tierlist/identities")
        || location.includes("/identities")
        || (location.includes("/teambuilder") && !!isIdentityTeamBuilder)
        || isGiftsPage
        || isEventsPage
        || isFusionPage;

    const traits = useMemo(() => {
        const unique = new Set<string>();
        (identities || []).forEach(identity => {
            parseEntityTraits(identity.traits)
                .filter(trait => !trait.negated)
                .forEach(trait => unique.add(trait.name));
        });
        if (isGiftsPage) (gifts || []).forEach(gift => extractInlineTraits(gift).forEach(trait => unique.add(trait)));
        if (isEventsPage) (events || []).forEach(event => extractInlineTraits(event).forEach(trait => unique.add(trait)));
        if (isFusionPage) (gifts || []).forEach(gift => extractInlineTraits(gift).forEach(trait => unique.add(trait)));
        if (isGiftsPage || isEventsPage || isFusionPage) {
            Object.values(TRAITS).forEach(trait => unique.add(trait.en));
        }
        return Array.from(unique).sort((a, b) => a.localeCompare(b));
    }, [events, gifts, identities, isEventsPage, isFusionPage, isGiftsPage]);

    if (!visible || !traits.length) return null;

    const normalizedQuery = query.trim().toLocaleLowerCase();
    const matching = traits.filter(trait => trait.toLocaleLowerCase().includes(normalizedQuery));
    const selectedNames = traits.filter(trait => selected[trait]);
    const display = expanded || normalizedQuery
        ? matching
        : [...selectedNames, ...matching.filter(trait => !selected[trait]).slice(0, Math.max(0, 8 - selectedNames.length))];

    return (
        <section className={`filters-section filters-traits-section${expanded ? " filters-traits-section--expanded" : ""}`}>
            <header className="filters-traits-header">
                <span>{i18n.language === "ru" ? "Трейты" : "Traits"}<b>{traits.length}</b></span>
                {selectedNames.length > 0 && <button className="filters-clear-section" onClick={() => filterClearSectionAction(dispatch, "traits")}><EraserSVG /></button>}
            </header>
            <div className="filters-traits-controls">
                <input
                    value={query}
                    onChange={event => setQuery(event.target.value)}
                    placeholder={i18n.language === "ru" ? "Поиск трейта…" : "Search trait…"}
                />
                <button type="button" className="filters-traits-toggle" onClick={() => setExpanded(value => !value)} aria-expanded={expanded}>
                    {expanded
                        ? (i18n.language === "ru" ? "Свернуть" : "Collapse")
                        : `+${Math.max(0, traits.length - display.length)}`}
                </button>
            </div>
            <div className="filters-traits-list">
                {display.map(trait => (
                    <button
                        type="button"
                        className={`filters-trait-chip${selected[trait] ? " filters-trait-chip--active" : ""}`}
                        onClick={() => filterChangeSectionValueAction(dispatch, "traits", trait)}
                        key={trait}
                    >
                        {trait}
                    </button>
                ))}
            </div>
        </section>
    );
};
