import React, { useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { CommonPageLayout } from "./CommonPageLayout";
import { HeaderAuthButtons } from "../componentslimbus/main-info/HeaderAuthButtons";
import { getStoredSiteSettings, resetSiteSettings, SitePageKey, SiteSettings, updateSiteSettings } from "../store/site-settings";
import { decodeSiteSettings, encodeSiteSettings } from "../store/site-settings-code";
import "./SiteSettingsPage.css";

const pages: { key: SitePageKey; en: string; ru: string }[] = [
  { key: "global", en: "All pages", ru: "Все страницы" }, { key: "home", en: "Home", ru: "Главная" }, { key: "tierlist", en: "Tier list", ru: "Тирлист" },
  { key: "identities", en: "Identities list", ru: "Список Айдентичностей" }, { key: "ego", en: "E.G.O list", ru: "Список Эго" }, { key: "identity", en: "Identity details", ru: "Айди Эго" }, { key: "egoDetail", en: "E.G.O details", ru: "Детали Эго" }, { key: "guides", en: "Guides list", ru: "Список гайдов" }, { key: "guideDetail", en: "Guide details", ru: "Страница гайда" }, { key: "statuses", en: "Statuses", ru: "Статусы" }, { key: "mirrorDungeon", en: "Mirror Dungeon", ru: "Зеркальное подземелье" }, { key: "teambuilder", en: "Team builder", ru: "Тимбилдер" }
];

export const SiteSettingsPage: React.FC = () => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const [scope, setScope] = useState<SitePageKey>("global");
  const [stored, setStored] = useState(getStoredSiteSettings);
  const [code, setCode] = useState("");
  const [codeStatus, setCodeStatus] = useState("");
  const values = useMemo<SiteSettings>(() => scope === "global" ? stored.global : { ...stored.global, ...(stored.pages[scope] || {}) }, [scope, stored]);
  const save = (key: keyof SiteSettings, value: SiteSettings[keyof SiteSettings]) => { updateSiteSettings(scope, { [key]: value } as Partial<SiteSettings>); setStored(getStoredSiteSettings()); };
  const exportPreset = async () => { const nextCode = encodeSiteSettings(stored); setCode(nextCode); setCodeStatus(ru ? "Код создан" : "Code created"); try { await navigator.clipboard.writeText(nextCode); setCodeStatus(ru ? "Код скопирован" : "Code copied"); } catch { /* clipboard may be unavailable */ } };
  const importPreset = () => { try { const data = decodeSiteSettings(code); localStorage.setItem("gll-site-settings-v1", JSON.stringify(data)); window.dispatchEvent(new Event("gll-site-settings-updated")); setStored(getStoredSiteSettings()); setCodeStatus(ru ? "Настройки загружены" : "Settings imported"); } catch { setCodeStatus(ru ? "Некорректный код" : "Invalid settings code"); } };
  const reset = () => { resetSiteSettings(); setStored(getStoredSiteSettings()); setCode(""); setCodeStatus(""); };
  return <CommonPageLayout><section className="site-settings-page">
    <div className="site-settings-header"><div><span className="site-settings-kicker">GLL / SETTINGS</span><h1>{ru ? "Настройки сайта" : "Site settings"}</h1><p>{ru ? "Настройте внешний вид и поведение сайта для всех страниц или отдельно для каждой." : "Configure the appearance and behavior globally or per page."}</p></div><HeaderAuthButtons inline /></div>
    <div className="site-settings-toolbar"><label>{ru ? "Изменять:" : "Edit:"}<select value={scope} onChange={e => setScope(e.target.value as SitePageKey)}>{pages.map(page => <option key={page.key} value={page.key}>{ru ? page.ru : page.en}</option>)}</select></label><button onClick={exportPreset}>{ru ? "Создать код" : "Create code"}</button><button onClick={importPreset}>{ru ? "Загрузить код" : "Import code"}</button><button className="site-settings-reset" onClick={reset}>{ru ? "Сбросить" : "Reset"}</button></div>
    <div className="site-settings-code"><label>{ru ? "Код пресета настроек" : "Settings preset code"}<textarea value={code} onChange={e => { setCode(e.target.value); setCodeStatus(""); }} placeholder={ru ? "Вставьте сюда код настроек…" : "Paste settings code here…"} /><small>{codeStatus || (ru ? "Создайте код, чтобы скопировать его, или вставьте код для загрузки." : "Create a code to copy it, or paste a code to import it.")}</small></label></div>
    <div className="site-settings-grid">
      <article className="site-settings-card"><h2>{ru ? "Размер и ширина" : "Size and width"}</h2><SettingRange label={ru ? "Размер шрифта" : "Font size"} value={values.fontScale} min={0.85} max={1.2} step={0.05} suffix="×" onChange={v => save("fontScale", v)}/><SettingRange label={ru ? "Ширина основного контента" : "Main content width"} value={values.mainWidth} min={70} max={100} step={1} suffix="%" onChange={v => save("mainWidth", v)}/><SettingRange label={ru ? "Пустое место по краям" : "Side space"} value={values.sideSpace} min={0} max={12} step={1} suffix="%" onChange={v => save("sideSpace", v)}/></article>
      <article className="site-settings-card"><h2>{ru ? "Расположение и поведение" : "Layout and behavior"}</h2><SettingSelect label={ru ? "Фильтры" : "Filters"} value={values.filterLayout} options={[["sidebar",ru ? "Сбоку" : "Sidebar"],["content",ru ? "В контенте" : "Above content"]]} onChange={v => save("filterLayout", v as SiteSettings["filterLayout"])}/><SettingSelect label={ru ? "Картинка Айдентичностей" : "Identity image"} value={String(values.identityImage)} options={[["1","178.1"],["2","178.2"]]} onChange={v => save("identityImage", Number(v) as 1|2)}/><Toggle label={ru ? "Менять арт при наведении" : "Change art on hover"} value={values.identityHover} onChange={v => save("identityHover", v)}/><Toggle label={ru ? "Показывать анимации" : "Show animations"} value={!values.animationsDisabled} onChange={v => save("animationsDisabled", !v)}/><Toggle label={ru ? "Отключить Sweepers" : "Disable Sweepers"} value={!values.sweepersDisabled} onChange={v => save("sweepersDisabled", !v)}/><Toggle label={ru ? "Внутренний скролл навыков Айди Эго" : "Scrollable Identity skills panel"} value={values.identitySkillsScroll} onChange={v => save("identitySkillsScroll", v)}/></article>
    </div>
  </section></CommonPageLayout>;
};
const SettingRange: React.FC<{label:string;value:number;min:number;max:number;step:number;suffix:string;onChange:(v:number)=>void}> = p => <label className="site-setting-range"><span>{p.label}<b>{p.value}{p.suffix}</b></span><input type="range" min={p.min} max={p.max} step={p.step} value={p.value} onChange={e => p.onChange(Number(e.target.value))}/></label>;
const SettingSelect: React.FC<{label:string;value:string;options:string[][];onChange:(v:string)=>void}> = p => <label className="site-setting-row"><span>{p.label}</span><select value={p.value} onChange={e => p.onChange(e.target.value)}>{p.options.map(o => <option key={o[0]} value={o[0]}>{o[1]}</option>)}</select></label>;
const Toggle: React.FC<{label:string;value:boolean;onChange:(v:boolean)=>void}> = p => <label className="site-setting-row"><span>{p.label}</span><input className="site-setting-toggle" type="checkbox" checked={p.value} onChange={e => p.onChange(e.target.checked)}/></label>;
