import React, { useEffect, useState } from 'react';
import './App.css';
import { LimbusRouter } from './routers/LimbusRouter';
import { UmamusumeRouter } from './routers/UmamusumeRouter';
import { GameSelectionPage } from './pages/GameSelectionPage';
import { store } from './store/store';
import { Provider } from 'react-redux';
import { BrowserRouter, Routes, Route, Navigate, useLocation, useNavigate } from 'react-router-dom';
import {
  QueryClient,
  QueryClientProvider,
  useQueryClient
} from 'react-query';
import { HelmetProvider } from 'react-helmet-async';
import { clearDataCache } from './api/cache';
import { useReviewerAccess } from './hooks/useReviewerAccess';
import './i18n';
import { getEffectiveSiteSettings, SITE_SETTINGS_EVENT } from './store/site-settings';

const SiteSettingsRuntime = () => {
  const location = useLocation();
  const [settings, setSettings] = useState(() => getEffectiveSiteSettings(location.pathname));
  useEffect(() => { const refresh = () => setSettings(getEffectiveSiteSettings(location.pathname)); refresh(); window.addEventListener(SITE_SETTINGS_EVENT, refresh); return () => window.removeEventListener(SITE_SETTINGS_EVENT, refresh); }, [location.pathname]);
  useEffect(() => {
    const root = document.documentElement;
    root.classList.toggle('animations-disabled', settings.animationsDisabled);
    root.style.setProperty('--site-font-scale', String(settings.fontScale));
    root.style.setProperty('--content-inline-size', `${Math.max(50, settings.mainWidth - settings.sideSpace * 2)}%`);
    return () => root.classList.remove('animations-disabled');
  }, [settings]);
  return null;
};

const queryClient = new QueryClient();

const OldUrlRedirect = () => {
  const location = useLocation();
  const path = location.pathname;

  if (location.search.startsWith("?/")) {
    const legacyPath = location.search.slice(2).split("&")[0].replace(/^\/?/, "");
    const normalizedPath = legacyPath.startsWith("limbus/") ? `/${legacyPath}` : `/limbus/${legacyPath}`;
    return <Navigate to={normalizedPath} replace />;
  }

  if (path.startsWith('/limbus') || path.startsWith('/umamusume')) {
    return <Navigate to={`${path}${location.search}`} replace />;
  }

  return <Navigate to={`/limbus${path}${location.search}`} replace />;
};

const ClearCacheButton = () => {
  const queryClient = useQueryClient();
  const location = useLocation();
  const navigate = useNavigate();
  const { isAdmin } = useReviewerAccess();

  const clearCacheAndRefresh = async () => {
    try {
      queryClient.clear();

      await clearDataCache();
    } catch (error) {
      console.error('Cache clear error:', error);
    }

    window.location.reload();
  };

  if (/\/limbus\/[^/]+\/(admin|test\/)/.test(location.pathname)) return null;

  const language = location.pathname.match(/^\/limbus\/(ru|en)(?:\/|$)/)?.[1] || "en";

  return (
    <div className="site-utility-actions">
      {isAdmin && <button className="admin-panel-button" onClick={() => navigate(`/limbus/${language}/admin`)} title="Admin panel" aria-label="Admin panel">Admin panel</button>}
      <button className="clear-cache-button" onClick={clearCacheAndRefresh}>Clear cache</button>
    </div>
  );
};

function App() {

  useEffect(() => {
  const handleKeyDown = async (e: KeyboardEvent) => {
    if (e.ctrlKey && e.shiftKey && e.altKey) {
      e.preventDefault();

      try {
        await clearDataCache();
      } catch (error) {
        console.error(error);
      }

      window.location.reload();
    }
  };

  window.addEventListener('keydown', handleKeyDown);

  return () => {
    window.removeEventListener('keydown', handleKeyDown);
  };
}, []);

  return (
    <HelmetProvider>
      <QueryClientProvider client={queryClient}>
        <Provider store={store}>
          <BrowserRouter>
            <ClearCacheButton />

            <Routes>
              <Route
                path="/"
                element={<Navigate to="/limbus/en/" replace />}
              />

              <Route
                path="/select-game"
                element={<GameSelectionPage />}
              />

              <Route
                path="/limbus/*"
                element={<><SiteSettingsRuntime /><LimbusRouter /></>}
              />

              <Route
                path="/umamusume/*"
                element={<UmamusumeRouter />}
              />

              <Route
                path="*"
                element={<OldUrlRedirect />}
              />
            </Routes>
          </BrowserRouter>
        </Provider>
      </QueryClientProvider>
    </HelmetProvider>
  );
}

export default App;
