import { idsKeys } from "../constants/idsKeys";
import { egoKeys } from "../constants/egoKeys";
import { md_eventsKeys } from "../constants/md-eventsKeys";
import { md_giftsKeys } from "../constants/md-giftsKeys";


export interface DataConfig {
  endpoint: string;
  order?: string;
  validator?: (data: any[]) => any[];
}

type ValidationKey = {
  key: string;
  validation: (value: any) => { validatedVal: any };
};

const createValidator = (
  keys: ValidationKey[],
  fallback: (key: string) => unknown = () => ""
) => (data: any[]) => data.map((row) => {
  const item: Record<string, unknown> = {};

  keys.forEach(({ key, validation }) => {
    const value = row[key] ?? row[key.toLowerCase()] ?? fallback(key);
    item[key] = validation(value).validatedVal;
  });

  return item;
});

export const FETCH_CONFIG: Record<string, DataConfig> = {
  identities: {
    endpoint: 'ids',
    validator: createValidator(idsKeys)
  },
  ego: {
    endpoint: 'ego_new',
    order: 'nameEN.asc',
    validator: createValidator(egoKeys)
  },
  "md-events": {
    endpoint: 'md_events',
    order: 'order.asc',
    validator: createValidator(md_eventsKeys, (key) => key.includes('choice') ? "{}" : "")
  },
  "md-gifts": {
    endpoint: 'md_gifts',
    validator: createValidator(md_giftsKeys)
  },
  news_list: { endpoint: 'news_list' },
  events_list: { endpoint: 'events' },
  chanlog: { endpoint: 'changelog' },
  guides: { endpoint: 'guides', order: 'ids.asc' },
  bingo: { endpoint: 'bingo' },
  themes: { endpoint: "themes" },
};
