import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { FilterSVG } from "../svg/FilterSVG";
import { Filters, TFilterVisibility } from "./Filters";
import { useSiteSettings } from "../../hooks/useSiteSettings";

type Props = {
    children: React.ReactNode;
};

const getInitialVisibility = (): TFilterVisibility => (
    localStorage.getItem("filterVisibility") === "show" ? "show" : "hide"
);

export const FiltersSidebarLayout: React.FC<Props> = ({ children }) => {
    const { t } = useTranslation();
    const { settings } = useSiteSettings();
    const [visibility, setVisibility] = useState<TFilterVisibility>(getInitialVisibility);
    const collapsed = visibility === "hide";

    const updateVisibility = (next: TFilterVisibility) => {
        localStorage.setItem("filterVisibility", next);
        setVisibility(next);
    };

    return (
        <div className={`filters-sidebar-layout${collapsed ? " filters-sidebar-layout--collapsed" : ""}${settings.filterLayout === "content" ? " filters-sidebar-layout--content" : ""}`}>
            <div className="filters-sidebar-layout__content">
                {collapsed && (
                    <button
                        type="button"
                        className="filters-sidebar-restore"
                        onClick={() => updateVisibility("show")}
                    >
                        <FilterSVG />
                        <span>{t("Filters.showFilters")}</span>
                    </button>
                )}
                {children}
            </div>
            <aside className="filters-sidebar">
                <Filters visibility={visibility} onVisibilityChange={updateVisibility} />
            </aside>
        </div>
    );
};
