type SortableEntity = {
    rarity: string;
    releaseDate: number;
};

const rarityWeight: Record<string, number> = {
    ALEPH: 5,
    WAW: 4,
    OOO: 3,
    HE: 3,
    OO: 2,
    TETH: 2,
    O: 1,
    ZAYIN: 1,
};

export const compareEntitiesByRarityAndDate = <T extends SortableEntity>(a: T, b: T) => {
    const rarityDifference =
        (rarityWeight[b.rarity?.trim().toUpperCase()] || 0) -
        (rarityWeight[a.rarity?.trim().toUpperCase()] || 0);

    if (rarityDifference !== 0) return rarityDifference;

    const dateA = new Date(a.releaseDate).getTime() || 0;
    const dateB = new Date(b.releaseDate).getTime() || 0;
    return dateB - dateA;
};
