import React, { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { getIdentityImageUrl, handleIdentityImageError } from "../../../tools/identityImage";
import { supabase } from "../../../tools/supabaseClient";
import { TEAM_CONTENT_TYPES, TeamPreset, getLocalizedTeamText } from "../../team-builder/community/team-types";

type GuideTeam = Pick<TeamPreset, "id" | "author_name" | "title" | "title_ru" | "title_en" | "content_type" | "lineup">;

export const GuideTeamEmbed: React.FC<{ teamId: string }> = ({ teamId }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const [team, setTeam] = useState<GuideTeam | null>(null);
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    let active = true;
    setTeam(null);
    setFailed(false);
    supabase.from("team_presets")
      .select("id,author_name,title,title_ru,title_en,content_type,lineup")
      .eq("id", teamId)
      .eq("is_public", true)
      .eq("moderation_status", "approved")
      .maybeSingle()
      .then(({ data, error }) => {
        if (!active) return;
        if (error || !data) setFailed(true);
        else setTeam(data as GuideTeam);
      });
    return () => { active = false; };
  }, [teamId]);

  if (failed) return <span className="guide-team-error">{ru ? "Команда не найдена" : "Team not found"}: {teamId}</span>;
  if (!team) return <span className="guide-team-loading">{ru ? "Загрузка команды…" : "Loading team…"}</span>;

  const title = getLocalizedTeamText(team as TeamPreset, "title", ru);
  const contentType = TEAM_CONTENT_TYPES.find(item => item.value === team.content_type);
  const lineup = Array.isArray(team.lineup) ? team.lineup.filter(slot => slot?.identity?.imgUrl) : [];

  return (
    <span className="guide-team-embed">
      <span className="guide-team-heading team-section-heading">
        <span><strong>{title}</strong><small>{team.author_name}{contentType ? ` · ${ru ? contentType.ru : contentType.en}` : ""}</small></span>
        <button type="button" onClick={() => navigator.clipboard?.writeText(`[team:${team.id}]`)} title={team.id}>{ru ? "Копировать ID" : "Copy ID"}</button>
      </span>
      <span className="guide-team-lineup">
        {lineup.map((slot, index) => <img key={`${slot.sinner}-${index}`} src={getIdentityImageUrl(slot.identity!.imgUrl)} onError={event => handleIdentityImageError(event, slot.identity!.imgUrl)} alt={(ru ? slot.identity!.nameRU : slot.identity!.nameEN) || slot.sinner} title={(ru ? slot.identity!.nameRU : slot.identity!.nameEN) || slot.sinner} />)}
      </span>
    </span>
  );
};
