import React, { ReactNode } from "react";
import { useDispatch } from "react-redux";
import { DisclaimerBanner } from "../componentslimbus/disclaimer-banner/DisclaimerBanner";
import { LeftMenu } from "../componentslimbus/left-menu/LeftMenu";
import { MainLayoutContainer } from "../componentslimbus/main-layout-container/MainLayoutContainer";
import { MobileInfoModal } from "../componentslimbus/mobile-info-modal/MobileInfoModal";
import { ScrollUpButton } from "../componentslimbus/scroll-up-button/ScrollUpButton";
import { SiteFooter } from "../componentslimbus/site-footer/SiteFooter";
import { TbModal } from "../componentslimbus/team-builder/tb-modal/TbModal";
import { TopMenu } from "../componentslimbus/top-menu/TopMenu";
import { useTypedSelector } from "../hooks/useTypedSelector";
import { tbCloseModalAction } from "../store/reducers/tb-reducer";

interface ICommonPageLayout {
    children:ReactNode|ReactNode[],
    showFooter?: boolean,
}
export const CommonPageLayout:React.FC<ICommonPageLayout> = ({children, showFooter = true}) => {
    const {modalTrigger} = useTypedSelector(store => store.tbReducer);
    const dispatch = useDispatch();
    return  <>
        <TopMenu/>
        <LeftMenu/>
        <DisclaimerBanner/>
        <ScrollUpButton/>
        <MobileInfoModal/>
        <TbModal active={modalTrigger !== null} modalTrigger={modalTrigger} closer={() => tbCloseModalAction(dispatch)}/>
        <MainLayoutContainer hasFooter={showFooter}>
            
            {children}
            {showFooter && <SiteFooter/>}
        </MainLayoutContainer>
    </>
}
