export interface EntityTrait {
    name: string;
    negated: boolean;
}

const LEGACY_TRAIT_NAMES: Record<string, string> = {
    lcb: 'LCB',
    standard: 'Standard',
    walpurgis: 'Walpurgis Night',
    seasonal: 'Seasonal',
    event: 'Event',
    extraction: 'Extraction',
    limited: 'Limited',
    story: 'Story',
    limbus: 'Limbus Company',
    fixer: 'Fixer',
    oufi: 'Öufi Association',
    shi: 'Shi Association',
    seven: 'Seven Association',
    corpR: 'R Corp.',
    corpW: 'W Corp.',
    corpH: 'H Corp.',
    corpN: 'N Corp.',
    corpNFanatic: 'N Corp. Fanatic',
    multiCrack: 'MultiCrack Office',
    fullStop: 'Full-Stop Office',
    fingers: 'The Fingers',
    heishou: 'Heishou Pack',
    hpYou: 'Heishou Pack - You Branch',
    tLA: 'Technology Liberation Alliance',
    pequod: 'The Pequod',
    wutheringH: 'Wuthering Heights',
    wildH: 'The Wild Hunt',
    mechAmalgam: 'Mechanical Amalgam',
    egoGear: 'E.G.O Gear'
};

export const TRAITS: Record<string, { en: string; ru: string }> = Object.fromEntries(
    Object.entries(LEGACY_TRAIT_NAMES).map(([key, name]) => [
        key,
        { en: name, ru: name }
    ])
);

export const getTraitName = (value: string, language: 'en' | 'ru' = 'en'): string => {
    const key = value.trim().replace(/^!/, '');
    const canonicalKey = Object.keys(TRAITS).find(candidate => candidate.toLocaleLowerCase() === key.toLocaleLowerCase());
    return canonicalKey ? TRAITS[canonicalKey][language] : key.replace(/[_-]+/g, ' ');
};

export const extractInlineTraits = (value: unknown): string[] => {
    const traits = new Set<string>();
    const visit = (current: unknown) => {
        if (typeof current === 'string') {
            const regex = /#\/([^#{}\s]+)(?:\{[^}]*\})?#/g;
            let match: RegExpExecArray | null;
            while ((match = regex.exec(current)) !== null) traits.add(getTraitName(match[1]));
            return;
        }
        if (Array.isArray(current)) {
            current.forEach(visit);
            return;
        }
        if (current && typeof current === 'object') Object.values(current as Record<string, unknown>).forEach(visit);
    };
    visit(value);
    return Array.from(traits);
};

export const parseEntityTraits = (value?: string | null): EntityTrait[] => {
    if (!value) return [];

    let values: string[];
    try {
        const parsed = JSON.parse(value);
        values = Array.isArray(parsed) ? parsed.map(String) : [];
    } catch {
        values = value.split(',');
    }

    return values
        .map(rawValue => rawValue.trim())
        .filter(Boolean)
        .map(rawValue => {
            const negated = rawValue.startsWith('!');
            const key = negated ? rawValue.slice(1) : rawValue;
            return { name: getTraitName(key), negated };
        });
};
