import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { User } from "@supabase/supabase-js";
import { supabase } from "../../../tools/supabaseClient";
import { HeaderAuthButtons } from "../../main-info/HeaderAuthButtons";
import { CollapsibleSection } from "./CollapsibleSection";

type Props = { user?: User; loading: boolean; sessionError?: string };

export const TeamAccountPanel: React.FC<Props> = ({ user, loading, sessionError }) => {
  const { i18n } = useTranslation();
  const ru = i18n.language === "ru";
  const [error, setError] = useState("");
  const [working, setWorking] = useState(false);
  const [displayName, setDisplayName] = useState("");
  const [editingName, setEditingName] = useState(false);
  const [avatarProvider, setAvatarProvider] = useState("");
  const [avatarUrl, setAvatarUrl] = useState("");
  const [avatarMenuOpen, setAvatarMenuOpen] = useState(false);
  const avatarMenuRef = useRef<HTMLDivElement>(null);

  const avatarOptions = (user?.identities || []).flatMap(identity => {
    const url = identity.identity_data?.avatar_url || identity.identity_data?.picture;
    return url && (identity.provider === "google" || identity.provider === "discord")
      ? [{ provider: identity.provider, url }]
      : [];
  });

  useEffect(() => {
    if (!user) return;
    supabase.from("profiles").select("display_name,avatar_provider,avatar_url").eq("id", user.id).single().then(({ data }) => {
      setDisplayName(data?.display_name || user.user_metadata?.full_name || user.email?.split("@")[0] || "Player");
      setAvatarProvider(data?.avatar_provider || user.app_metadata?.provider || "");
      setAvatarUrl(data?.avatar_url || user.user_metadata?.avatar_url || user.user_metadata?.picture || "");
    });
  }, [user]);

  useEffect(() => {
    if (!avatarMenuOpen) return;
    const closeMenu = (event: PointerEvent) => {
      if (!avatarMenuRef.current?.contains(event.target as Node)) setAvatarMenuOpen(false);
    };
    document.addEventListener("pointerdown", closeMenu);
    return () => document.removeEventListener("pointerdown", closeMenu);
  }, [avatarMenuOpen]);

  const saveDisplayName = async () => {
    if (!user || displayName.trim().length < 2) return;
    setWorking(true);
    setError("");
    const { error: updateError } = await supabase.from("profiles").update({ display_name: displayName.trim() }).eq("id", user.id);
    setWorking(false);
    if (updateError) setError(updateError.message);
    else {
      setEditingName(false);
      window.dispatchEvent(new Event("gll-profile-updated"));
    }
  };

  const selectAvatar = async (provider: string) => {
    const option = avatarOptions.find(item => item.provider === provider);
    if (!option || provider === avatarProvider) return;
    setWorking(true);
    setError("");
    const { data, error: updateError } = await supabase.rpc("set_profile_avatar", { selected_provider: provider });
    setWorking(false);
    if (updateError) {
      setError(updateError.message);
      return;
    }
    setAvatarProvider(provider);
    setAvatarUrl(data || option.url);
    setAvatarMenuOpen(false);
    window.dispatchEvent(new Event("gll-profile-updated"));
  };

  return (
    <CollapsibleSection storageKey="account" kicker="GLL ACCOUNT" title={ru ? "Аккаунт и публикация" : "Account and publishing"} className="team-account-panel">
      <div className="team-account-content">
        <p>{ru ? "Войдите, чтобы сохранять составы и отправлять их на публикацию." : "Sign in to save comps and submit them for publication."}</p>
        {loading ? <span>{ru ? "Проверка входа…" : "Checking session…"}</span> : user ? (
          <div className="team-account-user">
            {avatarUrl && <div className="team-avatar-control" ref={avatarMenuRef}>
              <button
                type="button"
                className="team-avatar-trigger"
                onClick={() => avatarOptions.length > 1 && setAvatarMenuOpen(value => !value)}
                disabled={working || avatarOptions.length < 2}
                aria-expanded={avatarMenuOpen}
                aria-label={ru ? "Выбрать аватар" : "Choose avatar"}
              >
                <img className="team-account-avatar" src={avatarUrl} alt="" referrerPolicy="no-referrer" />
                {avatarOptions.length > 1 && <span className={`team-avatar-chevron${avatarMenuOpen ? " is-open" : ""}`}>⌄</span>}
              </button>
              {avatarMenuOpen && <div className="team-avatar-menu" role="menu">
                {avatarOptions.map(option => <button
                  type="button"
                  role="menuitemradio"
                  key={option.provider}
                  className={avatarProvider === option.provider ? "active" : ""}
                  onClick={() => selectAvatar(option.provider)}
                  aria-checked={avatarProvider === option.provider}
                >
                  <img src={option.url} alt="" referrerPolicy="no-referrer" />
                  <span>{option.provider === "discord" ? "Discord" : "Google"}</span>
                  {avatarProvider === option.provider && <b>✓</b>}
                </button>)}
              </div>}
            </div>}
            <span>{editingName ? <input className="team-account-name-input" value={displayName} onChange={event => setDisplayName(event.target.value)} minLength={2} maxLength={32} /> : <strong>{displayName || user.user_metadata?.full_name || user.email}</strong>}<small>{user.email}</small></span>
            {editingName ? <button type="button" onClick={saveDisplayName} disabled={working}>{ru ? "Сохранить" : "Save"}</button> : <button type="button" onClick={() => setEditingName(true)}>{ru ? "Сменить ник" : "Change nickname"}</button>}
            <HeaderAuthButtons inline />
          </div>
        ) : (
          <HeaderAuthButtons inline />
        )}
        {(error || sessionError) && <div className="community-error">{error || sessionError}</div>}
      </div>
    </CollapsibleSection>
  );
};
