import { useEffect, useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { Link, useLocation, useSearchParams } from "react-router-dom";
import { useQueryClient } from "react-query";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { searchChangeValueAction } from "../../store/reducers/search-reducer";
import { rankSearchResults } from "../../tools/search";
import { trackAnalyticsEvent } from "../Analytics";
import { SearchSVG } from "../svg/SearchSVG";
import { XMarkSVG } from "../svg/XMark";
import "./Search.css";

type SearchResult = Record<string, unknown> & { type: string; path: string; name?: unknown };

export const Search:React.FC = () =>{
    const dispatch = useDispatch();
    const {t} = useTranslation();
    const {targetRef, value} = useTypedSelector(store=>store.searchReducer);
    const queryClient = useQueryClient();
    const location = useLocation();
    const [searchParams, setSearchParams] = useSearchParams();
    const [timeoutId,setTimeoutId] = useState<null|NodeJS.Timeout>(null);
    const [focused, setFocused] = useState(false);
    const [draftValue, setDraftValue] = useState(value || searchParams.get("search") || "");
    const inputValue = draftValue;

    const results = useMemo<SearchResult[]>(() => {
        if (!inputValue.trim()) return [];
        const language = location.pathname.match(/^\/limbus\/(ru|en)/)?.[1] || "en";
        const identities = (queryClient.getQueryData("identities") as Array<Record<string, unknown>> || [])
            .map(entity => ({ ...entity, type: "identity", path: `/limbus/${language}/identities/${entity.imgUrl}`, name: language === "ru" ? entity.nameRU : entity.nameEN }));
        const egos = (queryClient.getQueryData("ego") as Array<Record<string, unknown>> || [])
            .map(entity => ({ ...entity, type: "ego", path: `/limbus/${language}/ego/${entity.imgUrl}`, name: language === "ru" ? entity.nameRU : entity.nameEN }));
        const guides = (queryClient.getQueryData("guides") as Array<Record<string, unknown>> || [])
            .map(entity => ({ ...entity, type: "guide", path: `/limbus/${language}/guides/${entity.ids}`, name: language === "ru" ? entity.nameRu : entity.nameEn }));
        const gifts = (queryClient.getQueryData("md-gifts") as Array<Record<string, unknown>> || [])
            .map(entity => ({ ...entity, type: "gift", path: `/limbus/${language}/mirror-dungeon/gifts`, name: language === "ru" ? entity.nameRU : entity.nameEN }));
        return rankSearchResults([...identities, ...egos, ...guides, ...gifts], inputValue).slice(0, 8) as SearchResult[];
    }, [inputValue, location.pathname, queryClient]);

    const handleInputCHange = (e:React.ChangeEvent<HTMLInputElement>) =>{
        const val = e.target.value || "";
        setDraftValue(val);
        handleSearchDelay(()=>{
            searchChangeValueAction(dispatch, val);
            trackAnalyticsEvent("site_search", {
                search_term: val.trim(),
                result_count: results.length,
                page_path: location.pathname,
            });
            const next = new URLSearchParams(searchParams);
            if (val.trim()) next.set("search", val.trim()); else next.delete("search");
            setSearchParams(next, { replace: true });
        });
    }
    const handleSubmit = (event:React.FormEvent<HTMLFormElement>,targetRef:React.RefObject<HTMLElement|null>|null) => {
        event.preventDefault();
        if (targetRef?.current) {
            targetRef.current.scrollIntoView({ behavior: 'smooth' });
        }
      };
    const handleSearchDelay = (searchAction:() => void) => {
        if (timeoutId){clearTimeout(timeoutId);}

        const newTimeoutId = setTimeout(() => {
            searchAction();
            setTimeoutId(null);
        }, 500);

        setTimeoutId(newTimeoutId);
    }

    useEffect(() => {
        return () => {
            if(timeoutId) clearTimeout(timeoutId)
        };
    }, [timeoutId]);
   

    useEffect(() => {
        const urlValue = searchParams.get("search") || "";
        if (urlValue !== value) searchChangeValueAction(dispatch, urlValue);
        setDraftValue(current => current === value || current === urlValue ? urlValue : current);
    }, [dispatch, searchParams, value]);

    return <form className="search" onSubmit={ (e) => {handleSubmit(e,targetRef) }} >
        <input value={inputValue} placeholder={t("Search.placeholder")} onChange={(e)=>{handleInputCHange(e)}} onFocus={() => setFocused(true)} onBlur={() => setTimeout(() => setFocused(false), 120)} aria-label={t("Search.placeholder")} />
        {inputValue && <button className="btn-clear" type="button" onMouseDown={event => event.preventDefault()} onClick={ () => {
            setDraftValue("");
            searchChangeValueAction(dispatch, "");
            const next = new URLSearchParams(searchParams);
            next.delete("search");
            setSearchParams(next, { replace: true });
        }}><XMarkSVG/></button>}
        <button aria-label="apply filter by name" className="btn-search" type="submit"><SearchSVG/></button>
        <div className={`search-loader ${!timeoutId && "search-loader--hidden"}`}>
            <div className="search-gray-line"></div>
            <div className="search-white-line"></div>
        </div>
        {focused && inputValue.trim() && <div className="search-results" role="listbox">
            {results.map(result => <Link key={`${result.type}-${String(result.imgUrl || result.ids || result.gameId)}`} to={result.path} className="search-result" onMouseDown={event => event.preventDefault()} onClick={() => trackAnalyticsEvent("search_result_select", { search_term: inputValue.trim(), result_type: result.type, result_path: result.path })}>
                <span className="search-result-type">{t(`Search.${result.type}`, result.type)}</span>
                <strong>{String(result.name || result.imgUrl || result.ids)}</strong>
            </Link>)}
            {!results.length && <span className="search-result-empty">{t("Search.empty", "No matching results")}</span>}
        </div>}
    </form>
}
