import React from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { Link, useLocation } from "react-router-dom";
import { locales } from "../../constants/locales";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { leftMenuChangeLayoutAction } from "../../store/reducers/left-menu-reducer";
import { LanguageSelect } from "../language-select/LanguageSelect";
import { ContactSVG } from "../svg/ContactSVG";
import { EGOSVG } from "../svg/EGOSVG";
import { GLLSVG } from "../svg/GLLSVG";
import { GratitudeSVG } from "../svg/GratitudeSVG";
import { GuidesSVG } from "../svg/GuidesSVG";
import { IdentitiesSVG } from "../svg/IdentitiesSVG";
import { MirrorDungeonSVG } from "../svg/MirrorDungeonSVG";
import { StatusesPageSVG } from "../svg/StatusesPageSVG";
import { TeamBuilderSVG } from "../svg/TeamBuilderSVG";
import { TierListSVG } from "../svg/TierListSVG";
import "./LeftMenu.css";

const CollapseIcon: React.FC<{ collapsed: boolean }> = ({ collapsed }) => (
    <svg viewBox="0 0 24 24" aria-hidden="true">
        <path d={collapsed ? "m9 5 7 7-7 7" : "m15 5-7 7 7 7"} />
    </svg>
);

const SettingsIcon = () => (
    <svg viewBox="0 0 24 24" aria-hidden="true">
        <path d="M12 8.4a3.6 3.6 0 1 0 0 7.2 3.6 3.6 0 0 0 0-7.2Zm0-5v2m0 13.2v2M3 12h2m14 0h2M5.64 5.64l1.42 1.42m9.88 9.88 1.42 1.42m0-12.72-1.42 1.42m-9.88 9.88-1.42 1.42" />
    </svg>
);

export const LeftMenu: React.FC = () => {
    const dispatch = useDispatch();
    const location = useLocation();
    const { t, i18n } = useTranslation();
    const isCollapsed = useTypedSelector(store => store.leftMenuReducer);

    const navLang = locales.some(locale => locale.locale === i18n.language)
        ? i18n.language
        : "en";
    const currentSection = location.pathname.split("/")[3] || "";
    const links = [
        { to: `/limbus/${navLang}/gratitude`, route: "gratitude", name: t("LeftMenu.gratitude"), SVG: GratitudeSVG },
        { to: `/limbus/${navLang}/tierlist/identities`, route: "tierlist", name: t("LeftMenu.tierlist"), SVG: TierListSVG },
        { to: `/limbus/${navLang}/teambuilder`, route: "teambuilder", name: t("LeftMenu.teambuilder"), SVG: TeamBuilderSVG },
        { to: `/limbus/${navLang}/identities`, route: "identities", name: t("LeftMenu.identities"), SVG: IdentitiesSVG },
        { to: `/limbus/${navLang}/ego`, route: "ego", name: t("LeftMenu.ego"), SVG: EGOSVG },
        { to: `/limbus/${navLang}/guides`, route: "guides", name: t("LeftMenu.guides"), SVG: GuidesSVG },
        { to: `/limbus/${navLang}/mirror-dungeon/themes`, route: "mirror-dungeon", name: t("LeftMenu.mirror_dungeon"), SVG: MirrorDungeonSVG },
        { to: `/limbus/${navLang}/statuses`, route: "statuses", name: t("LeftMenu.statuses"), SVG: StatusesPageSVG },
        { to: `/limbus/${navLang}/contact`, route: "contact", name: t("LeftMenu.contact"), SVG: ContactSVG }
    ];

    const toggleMenu = () => {
        leftMenuChangeLayoutAction(dispatch, !isCollapsed);
    };

    const closeMobileMenu = () => {
        if (window.matchMedia("(max-width: 1000px)").matches) {
            leftMenuChangeLayoutAction(dispatch, true, false);
        }
    };

    const collapseLabel = isCollapsed
        ? t("LeftMenu.expandMenu")
        : t("LeftMenu.collapseMenu");

    return (
        <aside className={`left-menu ${isCollapsed ? "left-menu--collapsed" : "left-menu--expanded"}`}>
            <header className="left-menu-header">
                <Link
                    className="left-menu-brand"
                    to={`/limbus/${navLang}/`}
                    onClick={closeMobileMenu}
                    aria-label="Great Limbus Library"
                >
                    <GLLSVG />
                    <span className="left-menu-brand-text">GREAT <b>LIMBUS</b> LIBRARY</span>
                </Link>
                <button
                    type="button"
                    className="left-menu-collapse-button"
                    onClick={toggleMenu}
                    aria-label={collapseLabel}
                    title={collapseLabel}
                >
                    <CollapseIcon collapsed={isCollapsed} />
                </button>
            </header>

            <nav className="left-menu-navigation" aria-label={t("LeftMenu.navigation")}>
                <ul>
                    {links.map(({ route, name, to, SVG }) => {
                        const isActive = currentSection === route;
                        return (
                            <li key={route}>
                                <Link
                                    className={`left-menu-link ${isActive ? "left-menu-link--active" : ""}`}
                                    to={to}
                                    onClick={closeMobileMenu}
                                    aria-current={isActive ? "page" : undefined}
                                    aria-label={name}
                                    title={isCollapsed ? name : undefined}
                                >
                                    <span className="left-menu-link-icon"><SVG active={isActive} /></span>
                                    <span className="left-menu-link-label">{name}</span>
                                </Link>
                            </li>
                        );
                    })}
                </ul>
            </nav>

            <footer className="left-menu-footer">
                <Link to={`/limbus/${navLang}/settings`} onClick={closeMobileMenu} className={`left-menu-setting ${currentSection === "settings" ? "left-menu-setting--active" : ""}`} aria-label={t("LeftMenu.settings")} title={isCollapsed ? t("LeftMenu.settings") : undefined}>
                    <span className="left-menu-setting-icon"><SettingsIcon /></span>
                    <span className="left-menu-setting-label">{t("LeftMenu.settings")}</span>
                </Link>
                <LanguageSelect compact={isCollapsed} />
            </footer>
        </aside>
    );
};
