import React, { useMemo } from "react";
import { useQueryClient } from "react-query";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { useDispatch } from "react-redux";
import { MDGift } from "../../../store/reducers/md-gift-interface";
import { IdentityInterface } from "../../../store/reducers/ids-reducer";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { parseEntityTraits } from "../../entity-full-info/traits";
import { CollapsibleSection } from "../community/CollapsibleSection";
import { mdSelectGiftIdAction } from "../../../store/reducers/md-reducer";
import "../../mirror-dungeon/gifts/list/GiftsList.css";
import "./TbGifts.css";

const normalize = (value: string) => value.toLocaleLowerCase().replace(/[^\p{L}\p{N}]+/gu, " ").replace(/\s+/g, " ").trim();
const STATUS_WORDS = ["burn", "bleed", "tremor", "rupture", "sinking", "poise", "charge", "tainted blood", "unique bleed"];

const identityReferences = (identity: IdentityInterface) => [
    identity.nameEN,
    identity.nameRU,
    identity.sinner,
    ...parseEntityTraits(identity.traits).filter(trait => !trait.negated).map(trait => trait.name),
].filter(Boolean).map(value => normalize(value as string)).filter(value => value.length >= 3);

const attackText = (identity: IdentityInterface) => normalize([
    identity.descriptionCoinEN1, identity.descriptionCoinEN2, identity.descriptionCoinEN3, identity.descriptionCoinEN4,
].filter(Boolean).join(" "));

const referenceMatches = (identity: IdentityInterface, target: string) => {
    const targetWords = normalize(target).split(" ").filter(word => !["the", "a", "an", "faction", "identity", "identities"].includes(word));
    if (!targetWords.length) return false;
    return identityReferences(identity).some(reference => targetWords.every(word => reference.includes(word)));
};

const canActivate = (gift: MDGift, identities: IdentityInterface[], statusWords: string[]) => {
    const description = normalize([gift.grade1EN, gift.grade2EN, gift.grade3EN].filter(Boolean).join(" "));
    const countMatch = description.match(/(\d+)\s+or\s+more\s+(.{0,100}?)(?:identities|identity|units|sinners)/i);
    if (countMatch) {
        const required = Number(countMatch[1]);
        const target = normalize(countMatch[2]);
        const status = statusWords.find(word => target.includes(word)) || statusWords.find(word => description.includes(word));
        const count = status
            ? identities.filter(identity => attackText(identity).includes(status)).length
            : identities.filter(identity => referenceMatches(identity, target)).length;
        if (count >= required) return true;
    }

    const directCondition = /(?:when|if|for each|for every|upon)\b[^.]{0,180}\b(?:identity|identities|sinner|trait|faction)/i.test(description);
    if (!directCondition) return false;
    return identities.some(identity => identityReferences(identity).some(reference => {
        if (description.includes(reference)) return true;
        const words = reference.split(" ");
        return words.length > 1 && Array.from({ length: words.length - 1 }, (_, index) => words.slice(index, index + 2).join(" "))
            .some(phrase => phrase.length >= 7 && description.includes(phrase));
    }));
};

export const TbGifts: React.FC<{ canToggle?: boolean }> = ({ canToggle = true }) => {
    const { slots } = useTypedSelector(state => state.tbReducer);
    const queryClient = useQueryClient();
    const gifts = useMemo(() => queryClient.getQueryData("md-gifts") as MDGift[] || [], [queryClient]);
    const statuses = useMemo(() => queryClient.getQueryData("statuses") as Array<{ id?: string; nameEN?: string; nameRU?: string }> || [], [queryClient]);
    const { i18n } = useTranslation();
    const dispatch = useDispatch();
    const identities = useMemo(() => slots.filter(slot => slot.identity && slot.role === "combat").map(slot => slot.identity as IdentityInterface), [slots]);
    const statusWords = useMemo(() => Array.from(new Set([
        ...STATUS_WORDS,
        ...statuses.flatMap(status => [status.id, status.nameEN, status.nameRU]).filter(Boolean).map(value => normalize(value as string)),
    ])), [statuses]);
    const activeGifts = useMemo(() => gifts.filter(gift => gift.id !== "gift_0" && canActivate(gift, identities, statusWords)), [gifts, identities, statusWords]);
    const isRussian = i18n.language === "ru";

    return <CollapsibleSection storageKey="gifts" title={isRussian ? "Activatable E.G.O Gifts" : "Activatable E.G.O Gifts"} badge={activeGifts.length} className="tb-gifts-section" collapsible={canToggle} hideHeading={!canToggle}>
        {activeGifts.length ? <div className="tb-gifts-list">{activeGifts.map(gift => {
            const name = isRussian ? gift.nameRU || gift.nameEN : gift.nameEN || gift.nameRU;
            return <figure className="tb-gift" key={gift.id} title={name}>
                <Link to={`/limbus/${i18n.language}/mirror-dungeon/gifts`} onClick={() => mdSelectGiftIdAction(dispatch, gift.id)} className="GiftsList-img-wrapper">
                    <img className="main-img" src={`${process.env.PUBLIC_URL}/images/md-gifts/${gift.id}.webp`} alt={name} />
                    {gift.keyword !== "none" && <img className="keyword-img" src={`${process.env.PUBLIC_URL}/${["blunt", "pierce", "slash"].includes(gift.keyword) ? "images/dmg-type" : "images/tags"}/${gift.keyword}.webp`} alt={gift.keyword} />}
                    <div className="GiftsList-shadow" />
                    <div className={`GiftsList-bar GiftsList-bar--${gift.sin}`} />
                </Link>
                <figcaption>{name.length > 9 ? `${name.slice(0, 9)}...` : name}</figcaption>
            </figure>;
        })}</div> : <p className="tb-gifts-empty">No gifts match this team yet</p>}
    </CollapsibleSection>;
};
