import { Session } from "@supabase/supabase-js";
import { supabase } from "./supabaseClient";

export type DiscordAccess = {
  admin: boolean;
  reviewer: boolean;
  verifiedAt?: string | null;
  reconnectRequired?: boolean;
  code?: string;
  error?: string;
};

export const verifyDiscordAccess = async (session: Session | null): Promise<DiscordAccess> => {
  if (!session) return { admin: false, reviewer: false };

  const providerToken = session.provider_token;
  const { data, error } = await supabase.functions.invoke("discord-access", {
    body: providerToken ? { providerToken } : {}
  });

  if (error) {
    let message = error.message;
    try {
      const payload = await (error as any).context?.json?.();
      if (payload?.error) message = payload.error;
    } catch { /* The response body is optional. */ }
    return { admin: false, reviewer: false, error: message };
  }

  return {
    admin: data?.admin === true,
    reviewer: data?.reviewer === true,
    verifiedAt: data?.verifiedAt || null,
    reconnectRequired: data?.reconnectRequired === true,
    code: data?.code,
    error: data?.error
  };
};
