import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { TEAM_CONTENT_TYPES, TEAM_STATUS_COLORS, TeamPreset, TeamVote, getLocalizedTeamText, getYoutubeVideoId } from "./team-types";
import { getTeamGiftIds, TeamGiftSelector } from "./TeamGiftSelector";
import { getIdentityImageUrl, handleIdentityImageError } from "../../../tools/identityImage";

type Props = {
  team: TeamPreset;
  onLoad?: (team: TeamPreset) => void;
  onDelete?: (team: TeamPreset) => void;
  onEdit?: (team: TeamPreset) => void;
  onVote?: (team: TeamPreset, vote: TeamVote) => void;
  userVote?: TeamVote | null;
  canVote?: boolean;
  showModeration?: boolean;
};

export const CommunityTeamCard: React.FC<Props> = ({ team, onLoad, onDelete, onEdit, onVote, userVote, canVote, showModeration }) => {
  const { i18n } = useTranslation();
  const queryClient = useQueryClient();
  const ru = i18n.language === "ru";
  const [showSupports, setShowSupports] = useState(false);
  const [descriptionExpanded, setDescriptionExpanded] = useState(false);
  const [statusPage, setStatusPage] = useState(0);
  const cardRef = useRef<HTMLElement>(null);
  const videoId = getYoutubeVideoId(team.youtube_url);
  const title = getLocalizedTeamText(team, "title", ru);
  const description = getLocalizedTeamText(team, "description", ru);
  const descriptionIsLong = description.length > 170 || description.split("\n").length > 3;
  const descriptionIsShort = description.length <= 80 && description.split("\n").length === 1;
  const contentType = TEAM_CONTENT_TYPES.find(option => option.value === team.content_type);
  const backgroundColor = team.background_status ? TEAM_STATUS_COLORS[team.background_status] : undefined;
  const recommendedGifts = getTeamGiftIds(team.recommended_gifts);

  useEffect(() => {
    const card = cardRef.current;
    const grid = card?.parentElement;
    if (!card || !grid) return;

    const updateSpan = () => {
      const styles = window.getComputedStyle(grid);
      const rowHeight = Number.parseFloat(styles.gridAutoRows) || 4;
      const rowGap = Number.parseFloat(styles.rowGap) || 0;
      const height = card.getBoundingClientRect().height;
      card.style.gridRowEnd = `span ${Math.ceil((height + rowGap) / (rowHeight + rowGap))}`;
    };

    updateSpan();
    if (typeof ResizeObserver === "undefined") return;
    const observer = new ResizeObserver(updateSpan);
    observer.observe(card);
    window.addEventListener("resize", updateSpan);
    return () => {
      observer.disconnect();
      window.removeEventListener("resize", updateSpan);
    };
  }, []);

  let rawLineup: unknown = team.lineup;
  if (typeof rawLineup === "string") {
    try { rawLineup = JSON.parse(rawLineup); } catch { rawLineup = []; }
  }
  const identities = (Array.isArray(rawLineup) ? rawLineup : []).filter(slot => (
    slot && typeof slot === "object" && slot.identity && typeof slot.identity.imgUrl === "string" && /^id_\d+$/.test(slot.identity.imgUrl)
  ));
  const combatIdentities = identities.filter(slot => slot.role !== "support");
  const supportIdentities = identities.filter(slot => slot.role === "support");
  const visibleIdentities = videoId ? combatIdentities : identities;

  let rawStatuses: unknown = team.statuses;
  if (typeof rawStatuses === "string") {
    try { rawStatuses = JSON.parse(rawStatuses); } catch { rawStatuses = []; }
  }
  const statusValues = Array.from(new Set([
    ...(team.main_status ? [team.main_status] : []),
    ...(Array.isArray(rawStatuses) ? rawStatuses.filter((value): value is string => typeof value === "string") : [])
  ]));
  const statusData = queryClient.getQueryData<any[]>("statuses") || [];
  const getStatus = (value: string) => statusData.find(item => item.id === value || item.nameEN === value || item.nameRU === value);
  const statusLabel = (value: string) => {
    const status = getStatus(value);
    return (ru ? status?.nameRU || status?.nameEN : status?.nameEN || status?.nameRU) || value;
  };
  const renderSlot = (slot: any, index: number) => (
    <div className={`community-lineup-slot community-lineup-slot--${slot.role}`} key={`${slot.sinner}-${index}`} title={`${slot.sinner} · ${slot.role === "support" ? (ru ? "В бекапе" : "In backup") : (ru ? "На поле битв" : "On the field")}`}>
      <img src={getIdentityImageUrl(slot.identity.imgUrl)} onError={event => handleIdentityImageError(event, slot.identity.imgUrl)} alt={(ru ? slot.identity.nameRU : slot.identity.nameEN) || slot.sinner} />
      <b
        className={`community-lineup-marker community-lineup-marker--${slot.role}`}
        aria-label={slot.role === "support" ? (ru ? "В бекапе" : "In backup") : (ru ? "На поле битв" : "On the field")}
      >
        {Number(slot.battle_order) > 0 ? slot.battle_order : null}
      </b>
    </div>
  );

  const voteTitle = !onVote
    ? (ru ? "Войдите, чтобы голосовать" : "Sign in to vote")
    : !canVote
      ? (ru ? "За свою команду голосовать нельзя" : "You cannot vote for your own team")
      : undefined;

  return (
    <article className={`community-team-card ${backgroundColor ? "has-status-background" : ""}`} ref={cardRef} style={backgroundColor ? { "--team-status-rgb": backgroundColor } as React.CSSProperties : undefined}>
      <header className="community-team-card-header">
        <div className="community-team-heading">
          <h3>{title}</h3>
          <button type="button" className="community-team-id" title={team.id} onClick={() => navigator.clipboard?.writeText(`[team:${team.id}]`)}>ID: {team.id.slice(0, 8)}</button>
          {!!statusValues.length && <div className="community-status-carousel">
            <div className="community-status-list">{statusValues.slice(statusPage * 3, statusPage * 3 + 3).map(status => {
              const isTrait = status.startsWith("trait:");
              const statusItem = getStatus(status);
              const label = isTrait ? status.slice(6) : statusLabel(status);
              return <span className={`community-status-tag ${isTrait ? "community-status-tag--trait" : ""} ${team.main_status === status ? "is-main" : ""}`} key={status} title={label} aria-label={label}>{statusItem?.id ? <img src={`/images/tags/${statusItem.id}.webp`} alt="" /> : <small>{isTrait ? label : label.slice(0, 2)}</small>}{team.main_status === status && <b>★</b>}</span>;
            })}</div>
            {statusValues.length > 3 && <div className="community-status-navigation"><button type="button" disabled={statusPage === 0} onClick={() => setStatusPage(page => Math.max(0, page - 1))}>‹</button><small>{statusPage + 1}/{Math.ceil(statusValues.length / 3)}</small><button type="button" disabled={(statusPage + 1) * 3 >= statusValues.length} onClick={() => setStatusPage(page => page + 1)}>›</button></div>}
          </div>}
          {contentType && <span className="community-content-type">{ru ? contentType.ru : contentType.en}</span>}
        </div>
        <div className="community-votes" title={voteTitle}>
          <button type="button" className={userVote === 1 ? "is-active" : ""} disabled={!onVote || !canVote} onClick={() => onVote?.(team, 1)} aria-label={ru ? "Лайк" : "Like"}>▲ <b>{team.likes_count || 0}</b></button>
          <button type="button" className={userVote === -1 ? "is-active is-dislike" : "is-dislike"} disabled={!onVote || !canVote} onClick={() => onVote?.(team, -1)} aria-label={ru ? "Дизлайк" : "Dislike"}>▼ <b>{team.dislikes_count || 0}</b></button>
        </div>
      </header>

      <div className="community-team-meta">
        <div className="community-team-author">
          {team.author_avatar_url ? <img src={team.author_avatar_url} alt="" referrerPolicy="no-referrer" /> : <span>{team.author_name?.slice(0, 1).toUpperCase() || "G"}</span>}
          <div><strong>{team.author_name}</strong><time>{new Date(team.created_at).toLocaleDateString(ru ? "ru-RU" : "en-US")}</time></div>
        </div>
        {showModeration && <span className={`team-moderation team-moderation--${team.moderation_status}`}>{team.moderation_status}</span>}
      </div>

      <div className={`community-team-pack ${videoId ? "has-video" : "is-full"}`}>
        {videoId && <a href={`https://www.youtube.com/watch?v=${videoId}`} target="_blank" rel="noreferrer" className="community-video-preview"><img src={`https://i.ytimg.com/vi/${videoId}/mqdefault.jpg`} alt="YouTube preview" /><span><b>▶</b> YouTube</span></a>}
        <div className="community-team-lineup">
          {visibleIdentities.map(renderSlot)}
          {!visibleIdentities.length && <span className="community-lineup-empty">{ru ? "Участники не выбраны" : "No members"}</span>}
        </div>
      </div>

      {!!videoId && !!supportIdentities.length && <button type="button" className="community-support-toggle" onClick={() => setShowSupports(value => !value)}>{showSupports ? (ru ? "Скрыть поддержку" : "Hide support") : `${ru ? "Показать поддержку" : "Show support"} (+${supportIdentities.length})`}</button>}
      {!!videoId && showSupports && <div className="community-team-lineup community-team-lineup--support">{supportIdentities.map(renderSlot)}</div>}
      {!!description && <div className={`community-description ${descriptionExpanded ? "is-expanded" : ""} ${descriptionIsShort ? "is-short" : ""}`}>
        <p>{description}</p>
        {descriptionIsLong && <button type="button" onClick={() => setDescriptionExpanded(value => !value)}>{descriptionExpanded ? (ru ? "Свернуть" : "Collapse") : (ru ? "Читать полностью" : "Read more")}</button>}
      </div>}
      {showModeration && team.moderation_note && <div className="community-moderation-note">{team.moderation_note}</div>}
      <footer>
        <span />
        {onEdit && <button type="button" className="community-edit-button" onClick={() => onEdit(team)}>{ru ? "Изменить" : "Edit"}</button>}
        {onDelete && <button type="button" className="community-delete-button" onClick={() => onDelete(team)}>{ru ? "Удалить" : "Delete"}</button>}
        {!!recommendedGifts.length && <TeamGiftSelector selected={recommendedGifts} ru={ru} viewOnly />}
        {onLoad && <button type="button" className="community-load-button" onClick={() => onLoad(team)}>{ru ? "Загрузить" : "Load team"}</button>}
      </footer>
    </article>
  );
};
