import React, { useEffect, useState, useLayoutEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { dmgType, guardTypeExtended, sinType, normalizeGuardType } from '../../../constants/types';
import { IdentityInterface } from '../../../store/reducers/ids-reducer';
import { IdentityPassive } from './identity-passive/IdentityPassive';
import { IdentitySanity } from './identity-sanity/IdentitySanity';
import { IdentityReview } from './identity-review/IdentityReview';
import { IdentitySkill } from './identity-skill/IdentitySkill';
import { UptieComponent } from '../uptie-module/uptie-component';
import "./IdentitySkills.css";
import { useReviewerAccess } from '../../../hooks/useReviewerAccess';

interface IEntityFullInfoProps {
    identity: IdentityInterface;
    maxLvlIdentity: number;
}

export interface ISkill {
    index: number;
    skillType: dmgType | guardTypeExtended;
    sin: sinType;
    type: "attack" | "guard";
    resourceCount: number;
}

export interface IPassive {
    index: number;
    sin: sinType;
    count: string;
    description: string;
    name: string;
    type: string;
    condition: string;
}

type TTabType = "skills" | "passives" | "sanity" | "review";

export const IdentitySkills: React.FC<IEntityFullInfoProps> = ({ identity, maxLvlIdentity }) => {
    const { t, i18n } = useTranslation();
    const { skillsDmgType, skillsSin } = identity;
    
    const [activeTab, setActiveTab] = useState<TTabType>("skills");
    const { isReviewer } = useReviewerAccess();
    const [uptieValue, setUptieValue] = useState(4);
    const scrollRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!isReviewer && activeTab === "review") setActiveTab("skills");
    }, [activeTab, isReviewer]);
    
    useLayoutEffect(() => {
        const scroll = scrollRef.current;
        const lastBlock = scroll?.lastElementChild as HTMLElement | null;
        if (!scroll || !lastBlock) return;

        const syncTailSpace = () => {
            scroll.style.removeProperty('--scroll-tail-space');
            const hasScroll = scroll.scrollHeight > scroll.clientHeight + 1;
            scroll.dataset.scrollable = String(hasScroll);
            if (!hasScroll) return;
            const tailSpace = Math.max(0, scroll.clientHeight - lastBlock.offsetHeight);
            if (tailSpace > 0) scroll.style.setProperty('--scroll-tail-space', `${tailSpace}px`);
        };
        const observer = new ResizeObserver(syncTailSpace);
        observer.observe(scroll);
        observer.observe(lastBlock);
        syncTailSpace();

        return () => {
            observer.disconnect();
            scroll.style.removeProperty('--scroll-tail-space');
            delete scroll.dataset.scrollable;
        };
    }, [activeTab, identity, uptieValue]);

    const tabs: TTabType[] = ["skills", "passives", 'sanity'];
    if (isReviewer) tabs.push('review');
    
    const resourceCounts = [3, 2, 1];
    const skills: ISkill[] = Array(Math.min(skillsDmgType.length, skillsSin.length)).fill(1).map((n, index) => ({
        index,
        skillType: skillsDmgType[index],
        sin: skillsSin[index],
        resourceCount: resourceCounts[index] || 0,
        type: "attack"
    }));
    
    if (identity.guardSin && identity.guardType) {
        identity.guardSin.forEach((sin, index) => {
            skills.push({
                index: skills.length,
                sin,
                skillType: identity.guardType[index],
                type: "guard",
                resourceCount: 0
            });
        });
    }
    
    const normalizedSkills = skills.map(skill => ({
        ...skill,
        displayType: skill.type === "guard" ? normalizeGuardType(skill.skillType as guardTypeExtended) : skill.skillType
    }));
    
    const passives: IPassive[] = [0, 1].map((n, index) => {
        let k1 = `sinPassive${n + 1}` as keyof typeof identity;
        let k2 = `countPassive${n + 1}` as keyof typeof identity;
        let k3 = `descriptionPassive${n + 1}${i18n.language.toUpperCase()}` as keyof typeof identity;
        let k4 = `passive${n + 1}Condition` as keyof typeof identity;
        let k5 = `namePassive${i18n.language.toUpperCase()}` as keyof typeof identity;
        let type = index === 0 ? t("EntityFullInfoSkills.battlePassive") : t("EntityFullInfoSkills.supportPassive");
        return {
            index: index,
            sin: identity[k1] as sinType,
            count: identity[k2] as string,
            description: identity[k3] as string,
            name: (identity[k5] as string[])[index],
            condition: identity[k4] as string,
            type: type,
        };
    });
    
    return (
        <section className={'entityFullInfo-skills'}>
            <ul className={`entityFullInfo-tabs`}>
                {tabs.map((tabType) => {
                    const isActive = activeTab === tabType;
                    return (
                        <li onClick={() => setActiveTab(tabType)} className={`entityFullInfo-tab ${isActive ? 'entityFullInfo-tab--active' : ""}`} key={tabType}>
                            {t(`EntityFullInfoSkills.tab.${tabType}`).toUpperCase()}
                            {isActive && <div className="entityFullInfo-tab-line" />}
                        </li>
                    )
                })}
            </ul>
            
            <UptieComponent value={uptieValue} setValue={setUptieValue} />
            
            <div ref={scrollRef} className="entityFullInfo-skills-scroll" data-tab={activeTab}>
            {
                (activeTab === "skills") && normalizedSkills.map(
                    (skill,index)=>{
                        return <IdentitySkill skill={skill} key={index} identity={identity} maxLvlIdentity={maxLvlIdentity}/>
                    }
                )
            }

            {
                (activeTab === "passives") && passives.map(
                    (passive,index)=>{
                        return <IdentityPassive passive={passive} key={index} identity={identity}/>
                    }
                )
            }

            {(activeTab === "sanity") && (
                <IdentitySanity identity={identity} />
            )}
            
            {(activeTab === "review") && (
                <IdentityReview identity={identity} />
            )}
            </div>

        </section>
    );
};
