import React from "react";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import "./TbDamage.css";

const parseDamageValues = (values: string[] | null | undefined) => {
    if (!values) return [];
    return values
        .flatMap(value => String(value || "").split(","))
        .map(value => value.trim())
        .filter(Boolean);
};

const getDamageLabels = (skillsOrder: string[] | string | null | undefined, count: number) => {
    const isStandard = !Array.isArray(skillsOrder)
        || String(skillsOrder).toLowerCase() === "standard"
        || String(skillsOrder).toLowerCase() === "standart";

    if (!isStandard) {
        return Array.from({ length: count }).map((_, index) => skillsOrder[index] || (index === count - 1 ? "D" : `C${index + 1}`));
    }

    return Array.from({ length: count }).map((_, index) => index === count - 1 ? "D" : `C${index + 1}`);
};

export const TbDamage = () => {
    const { slots, hover } = useTypedSelector(state => state.tbReducer);
    const combatIdentities = slots
        .filter(slot => slot.role !== "support" && slot.identity)
        .map(slot => slot.identity!);
    const hoveredIdentity = hover?.type === "slot-identity" ? hover.trigger : null;

    return (
        <section className="tb-damage">
            <h2 className="tb-damage-header">Damage</h2>
            <div className="tb-damage-list">
                {combatIdentities.map(identity => {
                    const minValues = parseDamageValues(identity.minPossibleDmg);
                    const maxValues = parseDamageValues(identity.maxPossibleDmg);
                    const count = Math.max(minValues.length, maxValues.length);
                    const labels = getDamageLabels(identity.skillsOrder as any, count);
                    const isActive = hoveredIdentity?.imgUrl === identity.imgUrl;

                    return (
                        <div className={`tb-damage-row ${isActive ? "tb-damage-row--active" : ""}`} key={identity.imgUrl}>
                            <span className="tb-damage-name">{identity.sinner}</span>
                            <div className="tb-damage-skills">
                                {Array.from({ length: count }).map((_, index) => {
                                    const label = labels[index];
                                    const isGuard = label.toLowerCase().includes("d");
                                    const min = minValues[index] || "?";
                                    const max = maxValues[index] || "?";

                                    return (
                                        <b className={isGuard ? "tb-damage-skill tb-damage-skill--guard" : "tb-damage-skill"} key={`${identity.imgUrl}-${index}`}>
                                            <span>{label}</span>
                                            {min}-{max}
                                        </b>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
                {!combatIdentities.length && <span className="tb-damage-empty">No active IDs</span>}
            </div>
        </section>
    );
};
