import { Dispatch } from "react";
import { set, get } from "idb-keyval"; 
import { isIdentity } from "../../tools/isIdentity";
import { EGOInterface } from "./ego-reducer";
import { IdentityInterface } from "./ids-reducer";

// --- КОНСТАНТЫ ---
const TB_STORAGE_KEY = "tb-stored-slots";

export const SINNER_ORDER = [
    "yi sang", "faust", "don quixote", "ryoshu", 
    "mersault", "hong lu", "heathcliff", "ishmael", 
    "rodion", "sinclair", "outis", "gregor"
];

const SINS_ORDER = ["wrath", "lust", "sloth", "glut", "gloom", "pride", "envy"];
export const normalizeTbSin = (sin: string) => {
    const normalized = String(sin || "").toLowerCase();
    return normalized === "greed" ? "pride" : normalized;
};

const toList = <T,>(value: T[] | T | null | undefined): T[] => {
    if (Array.isArray(value)) return value;
    if (value === null || value === undefined) return [];
    return [value];
};

export const getSupportPassiveCostBySin = (identity: IdentityInterface, sin: string) => {
    const targetSin = normalizeTbSin(sin);
    const sins = toList(identity.sinPassive2);
    const counts = toList(identity.countPassive2);

    return sins.reduce((total, passiveSin, index) => {
        if (normalizeTbSin(String(passiveSin)) !== targetSin) return total;
        return total + (Number(counts[index] ?? counts[0]) || 0);
    }, 0);
};

// --- ИНТЕРФЕЙСЫ ---
interface EnergyListReqInterface {
    "wrath": number, "lust": number, "sloth": number, "glut": number, "gloom": number, "pride": number, "envy": number,
}
interface EnergyListPresentInterface {
    "wrath": number, "lust": number, "sloth": number, "glut": number, "gloom": number, "pride": number, "envy": number,
}

export interface EnergyInterface {
    "energyListReq": EnergyListReqInterface,
    "energyListPresent": EnergyListPresentInterface,
}

export interface SlotInterface {
    "identity": IdentityInterface | null,
    "ego": {
        [key: string]: EGOInterface | null;
    };
    role?: "combat" | "support";
    teamCodeSlotType?: number;
}

export type SetHoverTbActionPayload = 
    { type: "slot", trigger: SlotInterface } |
    { type: "tag" | "sin", trigger: string } |
    { type: "slot-identity", trigger: IdentityInterface } |
    { type: "slot-ego", trigger: EGOInterface };

export interface TbInterface {
    slots: SlotInterface[],
    energy: EnergyInterface,
    modalTrigger: SlotInterface | null,
    hover: null | SetHoverTbActionPayload
}

// --- НАЧАЛЬНЫЕ СОСТОЯНИЯ ---
const energyInitial = { "wrath": 0, "lust": 0, "sloth": 0, "glut": 0, "gloom": 0, "pride": 0, "envy": 0 };

const SlotInterfaceInitial: SlotInterface = {
    "identity": null,
    "ego": { "ZAYIN": null, "TETH": null, "HE": null, "WAW": null, "ALEPH": null },
    role: "combat",
};

const initialState: TbInterface = {
    slots: SINNER_ORDER.map(() => ({
        ego: { ...SlotInterfaceInitial.ego },
        identity: null,
        role: "combat",
    })),
    energy: { energyListReq: { ...energyInitial }, energyListPresent: { ...energyInitial } },
    modalTrigger: null,
    hover: null
};

// --- ТИПЫ ЭКШЕНОВ ---
export enum TbActionTypes {
    ADD_ENTITY = "ADD_ENTITY",
    REMOVE_ENTITY = "REMOVE_ENTITY",
    RESET_ALL = "RESET_ALL",
    RESET_SLOT = "RESET_SLOT",
    TRIGGER_MODAL = "TRIGGER_MODAL",
    CLOSE_MODAL = "CLOSE_MODAL",
    SET_HOVER = "SET_HOVER",
    RESET_HOVER = "RESET_HOVER",
    SET_SLOTS = "SET_SLOTS",
    SET_SLOT_ROLE = "SET_SLOT_ROLE"
}

export type TbAction = any; 

// --- УТИЛИТА СОХРАНЕНИЯ ---
const persistData = (slots: SlotInterface[]) => {
    set(TB_STORAGE_KEY, slots).catch(err => console.error("IDB Save Error:", err));
};

const normalizeSlots = (slots: SlotInterface[]): SlotInterface[] => {
    return slots.map(slot => ({
        ...slot,
        ego: { ...SlotInterfaceInitial.ego, ...(slot.ego || {}) },
        role: (slot.role === "support" ? "support" : "combat") as "combat" | "support",
    }));
};

// --- РЕДЬЮСЕР ---
export const tbReducer = (state = initialState, action: TbAction): TbInterface => {
    switch (action.type) {
        case TbActionTypes.TRIGGER_MODAL:
            return { ...state, modalTrigger: action.payload.slot };
        case TbActionTypes.CLOSE_MODAL:
            return { ...state, modalTrigger: null };
            
        case TbActionTypes.ADD_ENTITY: {
            const result = addEntityLogic(action.payload.entity, state, action.payload.slot);
            persistData(result.slots);
            return { ...state, ...result };
        }
            
        case TbActionTypes.REMOVE_ENTITY: {
            const result = removeEntityLogic(action.payload.entity, state, action.payload.slot);
            persistData(result.slots);
            return { ...state, ...result };
        }
            
        case TbActionTypes.RESET_ALL: {
            const res = resetAllLogic();
            persistData(res.slots);
            return res;
        }
            
        case TbActionTypes.RESET_SLOT: {
            const res = resetSlotLogic(state.slots, action.payload.slotIndx);
            persistData(res.slots);
            return { ...state, ...res };
        }

        case TbActionTypes.SET_SLOTS: {
            const slots = normalizeSlots(action.payload.slots);
            persistData(slots);
            return { ...state, slots, energy: calculateAllEnergy(slots) };
        }

        case TbActionTypes.SET_SLOT_ROLE: {
            const slots = state.slots.map((slot, index) => (
                index === action.payload.slotIndx ? { ...slot, role: action.payload.role } : slot
            ));
            persistData(slots);
            return { ...state, slots, energy: calculateAllEnergy(slots) };
        }

        case TbActionTypes.SET_HOVER:
            return { ...state, hover: action.payload };
            
        case TbActionTypes.RESET_HOVER:
            return { ...state, hover: null };
            
        default:
            return state;
    }
};

// --- ЛОГИКА ---

const calculateAllEnergy = (slots: SlotInterface[]): EnergyInterface => {
    const energy: EnergyInterface = { 
        energyListPresent: { ...energyInitial }, 
        energyListReq: { ...energyInitial } 
    };
    const addPresentSin = (sin: string | undefined, value: number) => {
        const key = normalizeTbSin(String(sin || ""));
        if (!key || !(key in energy.energyListPresent)) return;
        energy.energyListPresent[key as keyof EnergyListPresentInterface] += value;
    };

    slots.forEach(slot => {
        if (slot.role === "support" && slot.identity) {
            SINS_ORDER.forEach(sin => {
                const value = getSupportPassiveCostBySin(slot.identity as IdentityInterface, sin);
                if (value) energy.energyListReq[sin as keyof EnergyListReqInterface] += value;
            });
            return;
        }

        if (slot.identity && slot.role !== "support") {
            const { skillsSin } = slot.identity;
            addPresentSin(skillsSin[0], 3);
            addPresentSin(skillsSin[1], 2);
            addPresentSin(skillsSin[2], 1);
            slot.identity.guardSin?.forEach(sin => addPresentSin(sin, 1));
        }
        if (slot.role === "support") return;
        Object.values(slot.ego).forEach((ego: any) => {
            if (!ego) return;
            const costArray = ego.SinCost || ego.SinСost;
            if (Array.isArray(costArray)) {
                SINS_ORDER.forEach((sin, i) => {
                    const value = Number(costArray[i]) || 0;
                    const key = sin === "greed" ? "pride" : sin;
                    energy.energyListReq[key as keyof EnergyListReqInterface] += value;
                });
            }
        });
    });
    return energy;
};

const addEntityLogic = (entity: any, state: TbInterface, slot: SlotInterface) => {
    const slots = [...state.slots];
    const index = slots.indexOf(slot);
    if (index === -1 || entity.sinner.toLowerCase() !== SINNER_ORDER[index]) return state;

    const newSlot = { ...slot, ego: { ...slot.ego } };
    if (isIdentity(entity)) {
        newSlot.identity = entity;
    } else {
        newSlot.ego[entity.rarity] = entity;
    }
    slots[index] = newSlot;

    return { slots, energy: calculateAllEnergy(slots) };
};

const removeEntityLogic = (entity: any, state: TbInterface, slot: SlotInterface) => {
    const slots = [...state.slots];
    const index = slots.indexOf(slot);
    if (index === -1) return state;

    const newSlot = { ...slot, ego: { ...slot.ego } };
    if (isIdentity(entity)) {
        newSlot.identity = null;
    } else {
        newSlot.ego[entity.rarity] = null;
    }
    slots[index] = newSlot;

    return { slots, energy: calculateAllEnergy(slots) };
};

const resetSlotLogic = (currentSlots: SlotInterface[], idx: number) => {
    const slots = [...currentSlots];
    slots[idx] = { identity: null, ego: { ...SlotInterfaceInitial.ego }, role: currentSlots[idx]?.role || "combat" };
    return { slots, energy: calculateAllEnergy(slots) };
};

const resetAllLogic = (): TbInterface => ({
    ...initialState,
    slots: SINNER_ORDER.map(() => ({ identity: null, ego: { ...SlotInterfaceInitial.ego }, role: "combat" }))
});

// --- ЭКШЕНЫ (ЭКСПОРТЫ ДЛЯ КОМПОНЕНТОВ) ---

export const tbLoadStoredDataAction = async (dispatch: Dispatch<any>) => {
    try {
        const saved = await get(TB_STORAGE_KEY);
        if (saved) {
            dispatch({ type: TbActionTypes.SET_SLOTS, payload: { slots: normalizeSlots(saved) } });
        }
    } catch (e) {
        console.error("IDB Load Error", e);
    }
};

export const tbSetSlotsAction = (dispatch: Dispatch<any>, payload: { slots: SlotInterface[] }) => {
    dispatch({ type: TbActionTypes.SET_SLOTS, payload });
};

export const tbSetHoverAction = (dispatch: Dispatch<any>, payload: SetHoverTbActionPayload) => {
    dispatch({ type: TbActionTypes.SET_HOVER, payload });
};

export const tbResetHoverAction = (dispatch: Dispatch<any>) => {
    dispatch({ type: TbActionTypes.RESET_HOVER });
};

export const tbAddEntityAction = (dispatch: Dispatch<any>, entity: any, slot: SlotInterface) => 
    dispatch({ type: TbActionTypes.ADD_ENTITY, payload: { entity, slot } });

export const tbRemoveEntityAction = (dispatch: Dispatch<any>, entity: any, slot: SlotInterface) => 
    dispatch({ type: TbActionTypes.REMOVE_ENTITY, payload: { entity, slot } });

export const tbResetAllAction = (dispatch: Dispatch<any>) => 
    dispatch({ type: TbActionTypes.RESET_ALL });

export const tbResetSlotAction = (dispatch: Dispatch<any>, slotIndx: number) => 
    dispatch({ type: TbActionTypes.RESET_SLOT, payload: { slotIndx } });

export const tbSetSlotRoleAction = (dispatch: Dispatch<any>, slotIndx: number, role: "combat" | "support") =>
    dispatch({ type: TbActionTypes.SET_SLOT_ROLE, payload: { slotIndx, role } });

export const tbTriggerModalAction = (dispatch: Dispatch<any>, slot: SlotInterface) => 
    dispatch({ type: TbActionTypes.TRIGGER_MODAL, payload: { slot } });

export const tbCloseModalAction = (dispatch: Dispatch<any>) => 
    dispatch({ type: TbActionTypes.CLOSE_MODAL });
