import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { useLocation, useSearchParams } from "react-router-dom";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { filterChangeSectionValueAction, filterResetAllAction } from "../../store/reducers/filter-reducer";
import { setMobileModalTrigger } from "../../store/reducers/mobile-modal-reducer";
import { Search } from "../search/Search";
import { ClearFilterSVG } from "../svg/ClearFilterSVG";
import { EyeClosedSVG } from "../svg/EyeClosedSVG";
import { EyeOpenedSVG } from "../svg/EyeOpenedSVG";
import { FilterSVG } from "../svg/FilterSVG";
import { FiltersList } from "./filters-list/FiltersList";
// ИМПОРТИРУЕМ ОБА КОМПОНЕНТА РАЗДЕЛЬНО:
import { FiltersSectionMd } from "./filters-section-md/FiltersSectionMd";
import { FiltersSectionMdThemes } from "./filters-section-md-themes/FiltersSectionMdThemes";
import { FiltersSection2 } from "./filters-section2/FiltersSection2";
import { FiltersSectionTraits } from "./filters-section-traits/FiltersSectionTraits";
import "./Filters.css";

export type TFilterVisibility = "hide" | "show";

type FiltersProps = {
    isIdentityTeamBuilder?: string;
    pageType?: "themes" | "gifts" | "events" | "fusion" | "general";
    visibility?: TFilterVisibility;
    onVisibilityChange?: (visibility: TFilterVisibility) => void;
};

export const Filters: React.FC<FiltersProps> = ({ isIdentityTeamBuilder, pageType, visibility, onVisibilityChange }) => {
    const routeLocation = useLocation();
    const location = routeLocation.pathname;
    const [searchParams, setSearchParams] = useSearchParams();
    const dispatch = useDispatch();
    const { t } = useTranslation();

    // 1. Страница ТЕМ (Floor Themes)
    const isThemesPage = pageType === "themes" || location.includes("/mirror-dungeon-themes") || location.includes("/md-themes");
    const isEventsPage = pageType === "events" || location.includes("/mirror-dungeon/events");
    const isFusionPage = pageType === "fusion" || location.includes("/mirror-dungeon/rest-stops");
    
    // 2. Страница ГИФТОВ (EGO Gifts)
    const isClassicMdPage = location.includes("/mirror-dungeon/gifts") || pageType === "gifts";
    const isMirrorDungeonPage = isThemesPage || isClassicMdPage || isEventsPage || isFusionPage;
    const usesMirrorDungeonContentLayout = isClassicMdPage || isEventsPage || isFusionPage;

    // Вычисляем точный pageType для передачи внутрь компонентов
    const computedPageType: "themes" | "gifts" | "general" = location.includes("/mirror-dungeon/gifts") || pageType === "gifts"
        ? "gifts"
        : (isThemesPage ? "themes" : "general");

    const getFilterVisibilityValue = () => {
        const filterVisibility = localStorage.getItem("filterVisibility");
        if (filterVisibility && ["hide", "show"].includes(filterVisibility)) {
            return filterVisibility as TFilterVisibility;
        }
        return "hide";
    };

    React.useEffect(() => {
        if (isIdentityTeamBuilder || isThemesPage || isEventsPage || isFusionPage) {
            filterResetAllAction(dispatch);
        }
    }, [isIdentityTeamBuilder, isThemesPage, isEventsPage, isFusionPage, dispatch]);

    const [internalVisibility, setInternalVisibility] = useState<TFilterVisibility>(getFilterVisibilityValue());
    const filterVisibility = visibility ?? internalVisibility;

    const updateFilterVisibility = (next: TFilterVisibility) => {
        setInternalVisibility(next);
        localStorage.setItem("filterVisibility", next);
        onVisibilityChange?.(next);
    };

    const handleFilterChange = () => {
        const newFilterVisibility: TFilterVisibility = filterVisibility === "hide" ? "show" : "hide";
        updateFilterVisibility(newFilterVisibility);
    };

    const filterState = useTypedSelector(state => state.filterReducer);
    const restoredPathRef = useRef<string | null>(null);

    useEffect(() => {
        if (restoredPathRef.current === routeLocation.pathname) return;
        restoredPathRef.current = routeLocation.pathname;
        const encoded = searchParams.get("filters");
        if (!encoded) return;

        filterResetAllAction(dispatch);
        encoded.split("|").forEach(entry => {
            const separator = entry.indexOf(":");
            if (separator <= 0) return;
            const section = entry.slice(0, separator);
            const values = entry.slice(separator + 1).split(",").filter(Boolean);
            values.forEach(value => filterChangeSectionValueAction(dispatch, section, value));
        });
    }, [dispatch, routeLocation.pathname, searchParams]);

    useEffect(() => {
        if (restoredPathRef.current !== routeLocation.pathname) return;
        const entries = Object.entries(filterState.types)
            .map(([section, values]) => {
                const active = Object.entries(values).filter(([, enabled]) => enabled).map(([value]) => value);
                return active.length ? `${section}:${active.join(",")}` : "";
            })
            .filter(Boolean);
        const next = new URLSearchParams(searchParams);
        const encoded = entries.join("|");
        if (encoded) next.set("filters", encoded); else next.delete("filters");
        if (next.toString() !== searchParams.toString()) setSearchParams(next, { replace: true });
    }, [filterState, routeLocation.pathname, searchParams, setSearchParams]);

    const calculateFiltersCount = () => {
        let count = 0;
        if (isThemesPage) {
            for (const key in filterState.types.complexityFloor) {
                count += Number(filterState.types.complexityFloor[key]);
            }
            count += Number(filterState.types.complexityMode.normal);
            count += Number(filterState.types.complexityMode.hard);
            return count;
        }

        for (const key in filterState.types) {
            for (const key2 in filterState.types[key]) {
                count += Number(filterState.types[key][key2]);
            }
        }
        return count;
    };

    return (
        <section className={`filters${isMirrorDungeonPage ? " filters--mirror-dungeon" : ""}${usesMirrorDungeonContentLayout ? " filters--mirror-dungeon-content" : ""}`}>
            <header className={`filters-main-header ${filterVisibility === "hide" ? "filters-main-header--collapse" : ""}`}>
                <span style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: "5px" }}>
                    {t("Filters.header") + ` (${calculateFiltersCount()})`}
                    <button
                        className="filters-show-btn"
                        onClick={handleFilterChange}
                        aria-label={filterVisibility === "show" ? t("Filters.hideFilters") : t("Filters.showFilters")}
                        title={filterVisibility === "show" ? t("Filters.hideFilters") : t("Filters.showFilters")}
                    >
                        {filterVisibility === "show" ? <EyeOpenedSVG /> : <EyeClosedSVG />}
                    </button>
                </span>
                <div className={"filters-header-btns"}>
                    <button onClick={() => {
                        setMobileModalTrigger(dispatch,
                            <div className={`filters-modal-wrapper${isMirrorDungeonPage ? " filters-modal-wrapper--mirror-dungeon" : ""}`}>
                                {/* Грехи показываем везде, кроме страниц тем */}
                                {!isThemesPage && !isEventsPage && !isFusionPage && <FiltersList isIdentityTeamBuilder={isIdentityTeamBuilder} />}
                                {/* Типы атак (FiltersSection2) показываем только вне MD */}
                                {!isThemesPage && !isClassicMdPage && !isEventsPage && !isFusionPage && <FiltersSection2 isIdentityTeamBuilder={isIdentityTeamBuilder} />}
                                
                                {/* ДЛЯ ТЕМ И ТОЛЬКО ТАМ: */}
                                {isThemesPage && <FiltersSectionMdThemes {...{ pageType: computedPageType } as any} />}
                                
                                {/* ДЛЯ ГИФТОВ: */}
                                {isClassicMdPage && <FiltersSectionMd {...{ pageType: computedPageType } as any} />}
                                {!isThemesPage && <FiltersSectionTraits isIdentityTeamBuilder={isIdentityTeamBuilder} />}
                            </div>);
                    }} className="filters-mobile-open btn-filters">
                        <FilterSVG />
                        {t("Filters.showFilters")}
                    </button>
                    <div className="filters-search-stack">
                        <button
                            onClick={() => filterResetAllAction(dispatch)}
                            className="clear-filters btn-filters"
                            aria-label={t("Filters.clearFilters")}
                            title={t("Filters.clearFilters")}
                        >
                            <ClearFilterSVG />
                        </button>
                        {!location.includes("/teambuilder") && <Search />}
                    </div>
                </div>
            </header>

            {filterVisibility === "show" && (
                <article className={"filters-main"}>
                    {/* Грехи показываем везде, кроме страниц тем */}
                    {!isThemesPage && !isEventsPage && !isFusionPage && <FiltersList isIdentityTeamBuilder={isIdentityTeamBuilder} />}
                    {/* Типы атак (FiltersSection2) показываем только вне MD */}
                    {!isThemesPage && !isClassicMdPage && !isEventsPage && !isFusionPage && <FiltersSection2 isIdentityTeamBuilder={isIdentityTeamBuilder} />}
                    
                    {/* ДЛЯ ТЕМ И ТОЛЬКО ТАМ: */}
                    {isThemesPage && <FiltersSectionMdThemes {...{ pageType: computedPageType } as any} />}
                    
                    {/* ДЛЯ ГИФТОВ: */}
                    {isClassicMdPage && <FiltersSectionMd {...{ pageType: computedPageType } as any} />}
                    {!isThemesPage && <FiltersSectionTraits isIdentityTeamBuilder={isIdentityTeamBuilder} />}
                </article>
            )}
        </section>
    );
};
