import { SkillCoinDescription } from "../../../guides/text-formatter/SkillCoinDescription";
import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useDispatch } from 'react-redux';
import { IdentityInterface } from '../../../../store/reducers/ids-reducer';
import { EGOInterface } from '../../../../store/reducers/ego-reducer';
import { setMobileModalTrigger } from '../../../../store/reducers/mobile-modal-reducer';
import { StatusesInterface } from '../../../../store/reducers/statuses-reducer';
import { TooltipMobile } from '../../../../componentslimbus/tooltip-mobile/TooltipMobile';
import { handleIdentityImageError } from '../../../../tools/identityImage';
import './IdentityReview.css';

interface ReviewSection {
  content: string;
  type: 'pros' | 'cons' | 'pros-cons';
}

interface IdentityReviewProps {
  identity: IdentityInterface;
  
  textSize?: 'small' | 'medium' | 'large';
}

export const IdentityReview: React.FC<IdentityReviewProps> = ({
  identity,
  textSize = 'medium'
}) => {
  const { t, i18n } = useTranslation();
  const queryClient = useQueryClient();
  const dispatch = useDispatch();
  const { reviewEN, reviewRU, guideEN, guideRU } = identity;
  const [isDisclaimerVisible, setIsDisclaimerVisible] = useState(false);
  const [isGuideVisible, setIsGuideVisible] = useState(false);
  
  const prosTitle = t("EntityFullInfoReview.Pros");
  const consTitle = t("EntityFullInfoReview.Cons");
  const prosConsTitle = t("EntityFullInfoReview.ProsCons");

  const reviewText = i18n.language === "ru" ? reviewRU : reviewEN;
  const guideText = i18n.language === "ru" ? guideRU : guideEN;

  const toggleDisclaimerVisibility = () => {
    setIsDisclaimerVisible(!isDisclaimerVisible);
  };

  const toggleGuideVisibility = () => {
    setIsGuideVisible(!isGuideVisible);
  };

  // Получаем данные из query cache
  const statuses = queryClient.getQueryData('statuses') as StatusesInterface[] || [];
  const ids = queryClient.getQueryData('identities') as IdentityInterface[] || [];
  const ego = queryClient.getQueryData('ego') as EGOInterface[] || [];

  // Функция для обработки статусов в тексте
  const processStatusTags = (text: string): React.ReactNode[] => {
    if (!text) return [];
    
    const result: React.ReactNode[] = [];
    let currentIndex = 0;
    
    // Регулярное выражение для поиска статусов (#rTG#)
    const statusRegex = /#(\w+)#/g;
    let match;
    
    while ((match = statusRegex.exec(text)) !== null) {
      // Добавляем текст до совпадения
      if (match.index > currentIndex) {
        result.push(text.substring(currentIndex, match.index));
      }
      
      const statusId = match[1];
      const status = statuses.find(s => s.id === statusId);
      
      if (status) {
        const descriptionKey = `description${i18n.language.toUpperCase()}` as keyof typeof status;
        const description = status[descriptionKey] as string || '';
        
        const nameKey = `name${i18n.language.toUpperCase()}` as keyof typeof status;
        const name = status[nameKey] as string || '';
        
        const imgHTML = <img className="status" src={`${process.env.PUBLIC_URL}/images/tags/${statusId}.webp`} alt={statusId} />;
        const mobileModalHTML = <TooltipMobile image={imgHTML} header={name} text={description} />;

        result.push(
          <span 
            key={`status-${statusId}-${result.length}`}
            className="review-status-tag"
            onClick={() => {
              setMobileModalTrigger(dispatch, mobileModalHTML);
            }}
          >
            {imgHTML}
            <span className="status-name">{name}</span>
            <span className="entityFullInfo-tooltip">
              {t("SkillCoinDescription.clickToSeeDescription")}
            </span>
          </span>
        );
      } else {
        // Если статус не найден, оставляем оригинальный текст
        result.push(match[0]);
      }
      
      currentIndex = match.index + match[0].length;
    }
    
    // Добавляем оставшийся текст
    if (currentIndex < text.length) {
      result.push(text.substring(currentIndex));
    }
    
    return result;
  };

  const processEntityLinks = (text: string): React.ReactNode[] => {
    if (!text) return [];
    
    const result: React.ReactNode[] = [];
    let currentIndex = 0;
    
    // Регулярное выражение для поиска ссылок на идентичности и ЭГО
    // Используем флаг 'g' для итерации через exec
    const entityRegex = /&(id|ego)[_-]?(\d+)&/g;
    let match;
    
    while ((match = entityRegex.exec(text)) !== null) {
      // 1. Добавляем чистый текст, который идет ДО найденной ссылки
      if (match.index > currentIndex) {
        result.push(text.substring(currentIndex, match.index));
      }
      
      const entityType = match[1]; // 'id' или 'ego'
      const entityId = match[2];   // числовой ID
      const fullMatch = match[0];  // весь найденный кусок, например &id_124&
      
      // Создаем стабильный ключ на основе типа, ID и позиции в строке
      const stableKey = `entity-link-${entityType}-${entityId}-${match.index}`;
      
      if (entityType === 'id') {
        const identityItem = ids.find(item => item.imgUrl === `id_${entityId}`);
        if (identityItem) {
          const name = i18n.language === 'ru' ? identityItem.nameRU : identityItem.nameEN;
          result.push(
            <a 
              key={stableKey}
              href={`https://gll-fun.com/limbus/${i18n.language}/identities/id_${entityId}`}
              className="entity-link"
              target="_blank"
              rel="noopener noreferrer"
            >
              <img 
                className="entity-icon" 
                src={`${process.env.PUBLIC_URL}/images/identities/id_${entityId}.1.webp`}
                onError={event => handleIdentityImageError(event, `id_${entityId}`)}
                alt={`id_${entityId}`} 
              />
              {name}
            </a>
          );
        } else {
          result.push(fullMatch); // Если ID не найден в базе, возвращаем текст как есть
        }
      } else if (entityType === 'ego') {
        const egoItem = ego.find(item => item.imgUrl === `ego_${entityId}`);
        if (egoItem) {
          const name = i18n.language === 'ru' ? egoItem.nameRU : egoItem.nameEN;
          result.push(
            <a 
              key={stableKey}
              href={`https://gll-fun.com/limbus/${i18n.language}/ego/ego_${entityId}`}
              className="entity-link"
              target="_blank"
              rel="noopener noreferrer"
            >
              <img 
                className="entity-icon" 
                src={`${process.env.PUBLIC_URL}/images/ego/ego_${entityId}.webp`} 
                alt={`ego_${entityId}`} 
              />
              {name}
            </a>
          );
        } else {
          result.push(fullMatch);
        }
      }
      
      // Обновляем индекс, чтобы продолжить с места ПОСЛЕ текущего совпадения
      currentIndex = match.index + fullMatch.length;
    }
    
    // 2. Добавляем оставшийся текст после последнего совпадения
    if (currentIndex < text.length) {
      result.push(text.substring(currentIndex));
    }
    
    return result;
  };

  // Функция для обработки тегов <br> (переносы строк)
  const processLineBreaks = (text: string): React.ReactNode[] => {
    if (!text) return [];
    
    const result: React.ReactNode[] = [];
    let currentIndex = 0;
    
    // Регулярное выражение для поиска тегов <br>
    const brRegex = /<br\s*\/?>/gi;
    let match;
    
    while ((match = brRegex.exec(text)) !== null) {
      // Добавляем текст до тега <br>
      if (match.index > currentIndex) {
        result.push(text.substring(currentIndex, match.index));
      }
      
      // Добавляем перенос строки
      result.push(<br key={`br-${result.length}`} />);
      
      currentIndex = match.index + match[0].length;
    }
    
    // Добавляем оставшийся текст
    if (currentIndex < text.length) {
      result.push(text.substring(currentIndex));
    }
    
    return result;
  };

  // Основная функция для обработки всех типов контента
  const processAllContent = (text: string): React.ReactNode[] => {
    if (!text) return [];
    
    // Сначала обрабатываем переносы строк <br>
    const withLineBreaks = processLineBreaks(text);
    
    // Затем обрабатываем статусы и entity links в текстовых узлах
    const withAllContent = withLineBreaks.flatMap(node => {
      if (typeof node === 'string') {
        // Сначала обрабатываем статусы (#rTG#)
        const withStatuses = processStatusTags(node);
        
        // Затем обрабатываем entity links (&id_123&, &ego_456&) в текстовых узлах
        const withEntities = withStatuses.flatMap(statusNode => {
          if (typeof statusNode === 'string') {
            return processEntityLinks(statusNode);
          }
          return [statusNode];
        });
        
        return withEntities;
      }
      return [node];
    });
    
    return withAllContent;
  };

  const processSpecialContent = (text: string): React.ReactNode[] => {
    if (!text) return [];
    
    let result: React.ReactNode[] = [];
    let currentIndex = 0;
    let inSpecialTag = false;
    let specialContent = '';
    
    for (let i = 0; i < text.length; i++) {
      if (text[i] === '<' && text[i + 1] === 'e' && text[i + 2] === '>') {
        // Начало специального тега <e>
        if (i > currentIndex) {
          // Добавляем обычный текст до тега с полной обработкой
          const regularText = text.substring(currentIndex, i);
          result.push(...processAllContent(regularText));
        }
        inSpecialTag = true;
        specialContent = '';
        i += 2; // Пропускаем '<e>'
        currentIndex = i + 1;
      } else if (inSpecialTag && text[i] === '<' && text[i + 1] === '/' && 
                 text[i + 2] === 'e' && text[i + 3] === '>') {
        // Конец специального тега </e>
        inSpecialTag = false;
        // Для SkillCoinDescription передаем оригинальный текст (без обработки React элементами)
        result.push(
          <SkillCoinDescription 
            key={`skillcoin-${result.length}`}
            description={specialContent} 
          />
        );
        i += 3; // Пропускаем '</e>'
        currentIndex = i + 1;
      } else if (inSpecialTag) {
        specialContent += text[i];
      }
    }
    
    // Добавляем оставшийся текст с полной обработкой
    if (currentIndex < text.length) {
      const remainingText = text.substring(currentIndex);
      result.push(...processAllContent(remainingText));
    }
    
    return result;
  };

  const parseLines = (text: string, type: ReviewSection['type']) => {
    if (!text) return null;
    
    // Разделяем по ; или |
    const lines = text.split(/[;|]/).map(line => line.trim()).filter(line => line);
    
    return lines.map((line, index) => {
      let symbolClass = '';
      let symbol = '';
      
      if (type === 'pros') {
        symbolClass = 'large-symbol--plus';
        symbol = '+';
      } else if (type === 'cons') {
        symbolClass = 'large-symbol--minus';
        symbol = '-';
      } else {
        symbolClass = 'large-symbol--mixed';
        symbol = '±';
      }

      return (
        <div key={index} className={`review-line text-size-${textSize}`}>
          <span className={`large-symbol ${symbolClass}`}>{symbol}</span>
          {processSpecialContent(line)}
        </div>
      );
    });
  };

  const parseReviewSections = (): ReviewSection[] => {
    if (!reviewText) return [];

    // First try to parse using titles if they exist
    if (reviewText.includes(prosTitle) && reviewText.includes(consTitle)) {
      const prosIndex = reviewText.indexOf(prosTitle);
      const consIndex = reviewText.indexOf(consTitle);
      
      if (prosIndex < consIndex) {
        return [
          {
            content: reviewText.substring(prosIndex + prosTitle.length, consIndex).trim(),
            type: 'pros'
          },
          {
            content: reviewText.substring(consIndex + consTitle.length).trim(),
            type: 'cons'
          }
        ];
      }
    }

    // Fallback to pipe (|) separation
    const sections = reviewText.split('|').map(s => s.trim());
    
    // When we have exactly 3 sections, put the mixed one in the middle
    if (sections.length === 3) {
      return [
        {
          content: sections[0],
          type: 'pros'
        },
        {
          content: sections[2],
          type: 'pros-cons'
        },
        {
          content: sections[1],
          type: 'cons'
        }
      ];
    }
    
    // Default handling for other cases
    const result: ReviewSection[] = [];
    
    if (sections.length > 0) {
      result.push({
        content: sections[0],
        type: 'pros'
      });
    }
    
    if (sections.length > 1) {
      result.push({
        content: sections[1],
        type: 'cons'
      });
    }
    
    return result;
  };

  const sections = parseReviewSections();

  const getTitle = (type: ReviewSection['type']) => {
    switch (type) {
      case 'pros': return prosTitle;
      case 'cons': return consTitle;
      case 'pros-cons': return prosConsTitle;
      default: return '';
    }
  };

  const getTitleClass = (type: ReviewSection['type']) => {
    switch (type) {
      case 'pros': return 'passive-name-plus';
      case 'cons': return 'passive-name-minus';
      case 'pros-cons': return 'passive-name-mixed';
      default: return '';
    }
  };

  return (
    <>

      {/* Guide section */}
      {guideText && (
        <div role="contentinfo" aria-label="Guide" className="entityFullInfo-guide">
          <div 
            className="entityFullInfo-guide-heading"
            onClick={toggleGuideVisibility}
            role="button"
            tabIndex={0}
            aria-expanded={isGuideVisible}
          >
            <span>{t("EntityFullInfoReview.GuideHeader")}</span>
            <span className="entityFullInfo-guide-toggle">
              {isGuideVisible ? '▲' : '▼'}
            </span>
          </div>
          {isGuideVisible && (
            <div className="entityFullInfo-guide-content">
              {processSpecialContent(guideText)}
            </div>
          )}
        </div>
      )}

      {/* Review content sections */}
      {sections.map((section, index) => {
        if (!section.content) return null;
        
        return (
          <article key={index} className={`entityFullInfo-review entityFullInfo-review-${index}`}>
            <span className={getTitleClass(section.type)}>
              {getTitle(section.type)}
            </span>
            <div className="review-content">
              {parseLines(section.content, section.type)}
            </div>
          </article>
        );
      })}
    </>
  );
};

export const getStatusesEntityList = (strsArr: string[] | undefined) => {
    const result: {
        [key: string]: number;
    } = {};
    
    if (!strsArr || !Array.isArray(strsArr)) {
        return result;
    }
    
    strsArr.forEach(l => {
        if (!l || typeof l !== 'string') {
            return;
        }
        
        const current = l.split("#");
        for (let i = 1; i < current.length; i += 2) {
            const currTag = current[i];
            if (!currTag) continue;
            if (!(currTag in result)) {
                result[currTag] = 1;
            } else {
                result[currTag] += 1;
            }
        }
    });
    
    return result;
};
