export type SitePageKey = "global" | "home" | "tierlist" | "identities" | "ego" | "identity" | "egoDetail" | "guides" | "guideDetail" | "statuses" | "mirrorDungeon" | "teambuilder" | "other";
export type FilterLayout = "sidebar" | "content";

export interface SiteSettings {
  fontScale: number;
  filterLayout: FilterLayout;
  mainWidth: number;
  sideSpace: number;
  animationsDisabled: boolean;
  identityImage: 1 | 2;
  identityHover: boolean;
  identitySkillsScroll: boolean;
  sweepersDisabled: boolean;
}

export type SiteSettingsOverrides = Partial<SiteSettings>;
export interface StoredSiteSettings { global: SiteSettings; pages: Partial<Record<Exclude<SitePageKey, "global">, SiteSettingsOverrides>>; }

export const SITE_SETTINGS_KEY = "gll-site-settings-v1";
export const SITE_SETTINGS_EVENT = "gll-site-settings-updated";
export const DEFAULT_SITE_SETTINGS: SiteSettings = {
  fontScale: 1,
  filterLayout: "sidebar",
  mainWidth: 92,
  sideSpace: 0,
  animationsDisabled: localStorage.getItem("animationsDisabled") === "true",
  identityImage: 1,
  identityHover: true,
  identitySkillsScroll: true,
  sweepersDisabled: false
};

const readStored = (): StoredSiteSettings => {
  try {
    const parsed = JSON.parse(localStorage.getItem(SITE_SETTINGS_KEY) || "null");
    return { global: { ...DEFAULT_SITE_SETTINGS, ...(parsed?.global || {}) }, pages: parsed?.pages || {} };
  } catch { return { global: DEFAULT_SITE_SETTINGS, pages: {} }; }
};

export const getStoredSiteSettings = () => readStored();
export const getPageKey = (pathname: string): SitePageKey => {
  const parts = pathname.split("/").filter(Boolean);
  const section = parts[2] || "";
  if (section === "tierlist") return "tierlist";
  if (section === "identities") return parts[3] ? "identity" : "identities";
  if (section === "ego") return parts[3] ? "egoDetail" : "ego";
  if (section === "guides") return parts[3] ? "guideDetail" : "guides";
  if (section === "statuses") return "statuses";
  if (section === "mirror-dungeon") return "mirrorDungeon";
  if (section === "teambuilder") return "teambuilder";
  if (!section) return "home";
  return "other";
};
export const getEffectiveSiteSettings = (pathname = window.location.pathname): SiteSettings => {
  const stored = readStored();
  const pageKey = getPageKey(pathname);
  return { ...stored.global, ...(pageKey === "global" ? {} : stored.pages[pageKey] || {}) };
};
export const saveSiteSettings = (next: StoredSiteSettings) => {
  localStorage.setItem(SITE_SETTINGS_KEY, JSON.stringify(next));
  window.dispatchEvent(new Event(SITE_SETTINGS_EVENT));
};
export const updateSiteSettings = (scope: SitePageKey, values: SiteSettingsOverrides) => {
  const stored = readStored();
  if (scope === "global") stored.global = { ...stored.global, ...values };
  else stored.pages[scope] = { ...(stored.pages[scope] || {}), ...values };
  saveSiteSettings(stored);
};
export const resetSiteSettings = () => saveSiteSettings({ global: DEFAULT_SITE_SETTINGS, pages: {} });
