import React from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { setMobileModalTrigger } from '../../store/reducers/mobile-modal-reducer';
import { mdSelectGiftIdAction } from '../../store/reducers/md-reducer';
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import "./TooltipMobile.css";

interface ITooltipMobileProps {
    image?: React.ReactNode;
    header?: string;
    text: string;
    // Массив предыдущих состояний тултипа для реализации кнопки "Назад"
    history?: React.ReactNode[]; 
    giftId?: string; // ID подарка для перехода
}

export const TooltipMobile: React.FC<ITooltipMobileProps> = ({ image, text, header, history = [], giftId }) => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const { i18n } = useTranslation();

    // Функция возврата на предыдущий уровень истории в модалке
    const goBack = (e: React.MouseEvent) => {
        e.stopPropagation();
        if (history.length === 0) return;

        const newHistory = [...history];
        const previousModal = newHistory.pop(); 
        
        if (previousModal) {
            setMobileModalTrigger(dispatch, previousModal);
        }
    };

    // Функция перехода к подарку на страницу Mirror Dungeon
    const navigateToGiftPage = (e: React.MouseEvent) => {
        e.preventDefault();
        e.stopPropagation();

        if (giftId) {
            // 1. Устанавливаем выбранный ID в Redux стор, чтобы GiftsHeader обновился
            mdSelectGiftIdAction(dispatch, giftId);

            // 2. Закрываем текущее модальное окно (чтобы увидеть страницу под ним)
            setMobileModalTrigger(dispatch, null);

            // 3. Формируем путь и переходим (если пользователь на другой странице)
            const path = `/limbus/${i18n.language}/mirror-dungeon/gifts`;
            navigate(path);

            // 4. Скроллим к нужному контейнеру после закрытия модалки
            setTimeout(() => {
                const element = document.querySelector('.GiftsHeader-container');
                if (element) {
                    element.scrollIntoView({ behavior: 'smooth', block: 'start' });
                }
            }, 100);
        }
    };

    // Создаем текущее состояние как элемент истории для будущих вложенных тултипов
    const currentAsHistoryItem = (
        <TooltipMobile image={image} header={header} text={text} history={history} giftId={giftId} />
    );
    const nextHistory = [...history, currentAsHistoryItem];

    return (
        <div className='TooltipMobile'>
            {/* Кнопка "Назад" - отображается только если мы зашли вглубь по ссылкам */}
            {history.length > 0 && (
                <button className="TooltipMobile-back" onClick={goBack}>
                    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5M12 19l-7-7 7-7"/>
                    </svg>
                </button>
            )}

            {/* Кнопка перехода к подарку (справа сверху) */}
            {giftId && (
                <div className="TooltipMobile-navigate" onClick={navigateToGiftPage}>
                    <figure className="MDFormattedText-figure" style={{ margin: 0 }}>
                        <img 
                            className='small-img' 
                            src={`${process.env.PUBLIC_URL}/images/md-gifts/${giftId}.webp`} 
                            alt={giftId} 
                        />
                    </figure>
                </div>
            )}

            {(!!header || !!image) && (
            <>
                    <div className='TooltipMobile-header'>
                        {header && (
                            <SkillCoinDescription
                                description={header}
                                historyContext={nextHistory}
                            />
                        )}

                        {image}
                    </div>

                    <hr />
                </>
            )}
                
            <div className='TooltipMobile-info'>
                <SkillCoinDescription description={text} historyContext={nextHistory} />
            </div>
        </div>
    );
};
