import React from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { filterChangeTypeAction, filterClearSectionAction, floorTypes, mdThemeTags } from "../../../store/reducers/filter-reducer";
import { EraserSVG } from "../../svg/EraserSvg";
import "../Filters.css"; 

type FiltersSectionMdProps = {
    pageType?: "themes" | "gifts" | "general";
};

export const FiltersSectionMdThemes: React.FC<FiltersSectionMdProps> = ({ pageType }) => {
    const filterState = useTypedSelector(state => state.filterReducer);
    const { i18n } = useTranslation();
    const dispatch = useDispatch();

    let countActive = 0;

    const handleFilterChange = (key: string) => {
        filterChangeTypeAction(dispatch, key);
    };

    const handleClearSection = () => {
        filterClearSectionAction(dispatch, "complexityFloor");
        filterClearSectionAction(dispatch, "complexityMode");
        filterClearSectionAction(dispatch, "mdThemeTips");
    };

    // Считаем активные элементы
    floorTypes.forEach(floor => { if (filterState.types.complexityFloor[floor]) countActive++; });
    mdThemeTags.forEach(tag => { if (filterState.types.mdThemeTips[tag]) countActive++; });
    if (filterState.types.complexityMode.normal) countActive++;
    if (filterState.types.complexityMode.hard) countActive++;

    const isRu = i18n.language === 'ru';

    // Вспомогательная функция описания для тултипов буквенных фильтров
    const getTagTooltip = (tag: string): string => {
        const descriptions: Record<string, {ru: string, en: string}> = {
            IM: { ru: "Бесконечное Зеркало", en: "Infinity Mirror" },
            E: { ru: "ЭКСТРИМ", en: "EXTREME" },
            C: { ru: "Песня", en: "Canto" },
            IN: { ru: "Антракт", en: "Intervallo" },
            W: { ru: "Вальпургиева ночь", en: "Walpurgisnacht" },
            RR: { ru: "Ж/д преломления", en: "Refraction Railway" },
            AT: { ru: "Типы атак", en: "Attack Type" },
            SIN: { ru: "Типы грехов", en: "Sin Type" },
            ST: { ru: "Типы статусов", en: "Status Type" },
            SP: { ru: "Особые", en: "Special" }
        };
        return isRu ? descriptions[tag]?.ru : descriptions[tag]?.en;
    };

    return (
        <section className="filters-section">
            <header>
                {isRu ? 'Настройки отображения тем' : 'Theme Filters'}
                {countActive >= 1 && (
                    <button className="filters-clear-section" onClick={handleClearSection}>
                        <EraserSVG />
                    </button>
                )}
            </header>

            <button
                className={`filters-filter ${filterState.types.complexityMode.normal ? "filters-filter--active" : ""}`}
                onClick={() => handleFilterChange("normal")}
            >
                <strong>N</strong>
                <span className="filters-filter-tooltip">{isRu ? "Обычное" : "Normal"}</span>
            </button>

            <button
                className={`filters-filter ${filterState.types.complexityMode.hard ? "filters-filter--active" : ""}`}
                onClick={() => handleFilterChange("hard")}
            >
                <strong>H</strong>
                <span className="filters-filter-tooltip">{isRu ? "Усложненное" : "Hard"}</span>
            </button>

            {floorTypes.map((floor) => (
                <button
                    key={floor}
                    className={`filters-filter ${filterState.types.complexityFloor[floor] ? "filters-filter--active" : ""}`}
                    onClick={() => handleFilterChange(floor)}
                    style={{ fontWeight: "600" }}
                >
                    {floor}
                    <span className="filters-filter-tooltip">
                        {isRu ? `${floor.replace("F", "")} Этаж` : `${floor.replace("F", "")} Floor`}
                    </span>
                </button>
            ))}

            {mdThemeTags.map((tag) => (
                <button
                    key={tag}
                    className={`filters-filter ${filterState.types.mdThemeTips[tag] ? "filters-filter--active" : ""}`}
                    onClick={() => handleFilterChange(tag)}
                    style={{ fontWeight: "600" }}
                >
                    {tag}
                    <span className="filters-filter-tooltip">
                        {getTagTooltip(tag)}
                    </span>
                </button>
            ))}
        </section>
    );
};
