import { useEffect, useState } from "react";
import { getEffectiveSiteSettings, getPageKey, getStoredSiteSettings, SITE_SETTINGS_EVENT, SitePageKey, SiteSettings, updateSiteSettings } from "../store/site-settings";
import { useLocation } from "react-router-dom";

export const useSiteSettings = () => {
  const location = useLocation();
  const [settings, setSettings] = useState<SiteSettings>(() => getEffectiveSiteSettings(location.pathname));
  useEffect(() => {
    const refresh = () => setSettings(getEffectiveSiteSettings(location.pathname));
    refresh();
    window.addEventListener(SITE_SETTINGS_EVENT, refresh);
    return () => window.removeEventListener(SITE_SETTINGS_EVENT, refresh);
  }, [location.pathname]);
  return { settings, pageKey: getPageKey(location.pathname), stored: getStoredSiteSettings(), update: (scope: SitePageKey, values: Partial<SiteSettings>) => updateSiteSettings(scope, values) };
};
